var __index = {"config":{"lang":["en"],"separator":"[\\s\\-,:!=\\[\\]()\"`/]+|\\.(?!\\d)|&[lg]t;|(?!\\b)(?=[A-Z][a-z])","pipeline":["stopWordFilter"]},"docs":[{"location":"index.html","title":"HiMatCal","text":"<p>Welcome to the documentation for the <code>himatcal</code> code!</p> <p>[!WARNING] \ud83d\udea7 This repository is still under construction. \ud83d\udea7</p>"},{"location":"install/codes.html","title":"Extra Codes","text":""},{"location":"install/codes.html#xtb-and-xtb_ase","title":"xtb and xtb_ase","text":"<pre><code>micromamba install -c conda-forge xtb\nuv pip install git+https://github.com/Quantum-Accelerators/xtb_ase.git\n</code></pre>"},{"location":"install/codes.html#pysisyphus","title":"pysisyphus","text":"<pre><code>uv pip install git+https://github.com/CCSun21/pysisyphus.git@dev\n</code></pre>"},{"location":"install/install.html","title":"Installation","text":""},{"location":"install/install.html#using-micromamba","title":"using micromamba","text":"<p>Note</p> <p>Installing with micromamba and uv is the recommended way to install himatcal.</p> <pre><code>micromamba env create -n himatcal python==3.10\nmicromamba activate himatcal\n\npip install uv\nuv pip install himatcal\nuv pip install git+https://gitlab.com/ase/ase.git\n</code></pre>"},{"location":"reference/SUMMARY.html","title":"SUMMARY","text":"<ul> <li>himatcal<ul> <li>atoms<ul> <li>core</li> <li>parser</li> </ul> </li> <li>calculator<ul> <li>aimnet<ul> <li>aimnet2ase</li> <li>aimnet2pysis</li> <li>core</li> <li>ensemble</li> <li>models</li> <li>nblist</li> </ul> </li> <li>gaussian_mcd</li> <li>mlp</li> <li>orca_mcd</li> <li>pyscf_calculator</li> </ul> </li> <li>recipes<ul> <li>crest<ul> <li>_base</li> <li>core</li> </ul> </li> <li>electrolyte<ul> <li>core</li> <li>reaction</li> <li>redox</li> <li>sol_stru<ul> <li>_base</li> <li>build_box</li> <li>core</li> <li>genFF</li> <li>md</li> </ul> </li> </ul> </li> <li>gaussian<ul> <li>_base</li> <li>core</li> <li>flow</li> </ul> </li> <li>gsm<ul> <li>DE_GSM</li> <li>SE_GSM</li> <li>core</li> </ul> </li> <li>materials<ul> <li>core</li> <li>diffubarrier</li> </ul> </li> <li>mcd<ul> <li>core</li> </ul> </li> <li>mol<ul> <li>core</li> </ul> </li> <li>quacc<ul> <li>core</li> </ul> </li> </ul> </li> <li>settings</li> <li>tools<ul> <li>db</li> <li>mpdownload</li> </ul> </li> <li>utils<ul> <li>ase</li> <li>ct</li> <li>mcd<ul> <li>chem</li> <li>ic</li> <li>mcd</li> <li>process</li> <li>run</li> </ul> </li> <li>os</li> <li>rdkit<ul> <li>core</li> </ul> </li> <li>visualization</li> </ul> </li> </ul> </li> </ul>"},{"location":"reference/himatcal/settings.html","title":"settings","text":"<p>Settings for himatcal</p>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings","title":"HimatcalSettings","text":"<p>               Bases: <code>BaseSettings</code></p> <p>Settings for himatcal</p>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.AIMNET2_MODEL_PATH","title":"AIMNET2_MODEL_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>AIMNET2_MODEL_PATH: Path = Field(Path(), description='Path to the aimnet2 model')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.CHEMSPIDER_API_KEY","title":"CHEMSPIDER_API_KEY  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>CHEMSPIDER_API_KEY: str = Field('', description='API key for ChemSpider')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.CONFIG_FILE","title":"CONFIG_FILE  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>CONFIG_FILE: Path = Field(_DEFAULT_CONFIG_FILE_PATH, description='Path to the YAML config file')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.CREST_EXE_PATH","title":"CREST_EXE_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>CREST_EXE_PATH: Path = Field(Path(), description='Path to the crest executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.CREST_EXE_PATH_V3","title":"CREST_EXE_PATH_V3  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>CREST_EXE_PATH_V3: Path = Field(Path(), description='Path to the crest executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.DEBUG","title":"DEBUG  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>DEBUG: bool = Field(False, description='Whether to enable debug logging')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.FORMCHK_PATH","title":"FORMCHK_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>FORMCHK_PATH: Path = Field(Path(), description='Path to the formchk executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.GROMACS_PATH","title":"GROMACS_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>GROMACS_PATH: Path = Field(Path(), description='Path to the gromacs executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.ISOSTAT_EXE_PATH","title":"ISOSTAT_EXE_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>ISOSTAT_EXE_PATH: Path = Field(Path(), description='Path to the isostat executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.MABASIS_PATH","title":"MABASIS_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>MABASIS_PATH: Path = Field(Path(), description='Path to the mabasis')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.MAPI_KEY","title":"MAPI_KEY  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>MAPI_KEY: str = Field('', description='API key for the Materials Project')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.MONGODB_URI","title":"MONGODB_URI  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>MONGODB_URI: str = Field('', description='MongoDB URI for the database connection')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.MULTIWFN_PATH","title":"MULTIWFN_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>MULTIWFN_PATH: Path = Field(Path(), description='Path to the Multiwfn executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.OBABEL_PATH","title":"OBABEL_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>OBABEL_PATH: Path = Field(Path(), description='Path to the obabel executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.ORCA_PATH","title":"ORCA_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>ORCA_PATH: Path = Field(Path(), description='Path to the ORCA executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.SGHPC1_KEY_PATH","title":"SGHPC1_KEY_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>SGHPC1_KEY_PATH: Path = Field('', description='Path to the ssh key file of sghpc1')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.SOBTOP_PATH","title":"SOBTOP_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>SOBTOP_PATH: Path = Field(Path(), description='Path to the sobtop executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.XMU_KEY_PATH","title":"XMU_KEY_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>XMU_KEY_PATH: Path = Field('', description='Path to the ssh key file of XMU')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.XTB_EXE_PATH","title":"XTB_EXE_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>XTB_EXE_PATH: Path = Field(Path(), description='Path to the xtb executable')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.YEESUAN_KEY_PATH","title":"YEESUAN_KEY_PATH  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>YEESUAN_KEY_PATH: Path = Field('', description='Path to the ssh key file of yeesuan')\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.model_config","title":"model_config  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>model_config = SettingsConfigDict(env_prefix='himatcal_', env_nested_delimiter='__', env_parse_none_str='None', extra='forbid', validate_assignment=True)\n</code></pre>"},{"location":"reference/himatcal/settings.html#himatcal.settings.HimatcalSettings.load_user_setting","title":"load_user_setting  <code>classmethod</code>","text":"<pre><code>load_user_setting(settings: dict[str, Any]) -&gt; dict[str, Any]\n</code></pre> <p>Load user settings</p> Source code in <code>himatcal/settings.py</code> <pre><code>@model_validator(mode=\"before\")\n@classmethod\ndef load_user_setting(cls, settings: dict[str, Any]) -&gt; dict[str, Any]:\n    \"\"\"Load user settings\"\"\"\n    return _type_handler(_use_custom_config_settings(settings))\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html","title":"core","text":""},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.Li","title":"Li  <code>module-attribute</code>","text":"<pre><code>Li = Atoms(symbols='Li', positions=[[0, 0, 0]])\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.Na","title":"Na  <code>module-attribute</code>","text":"<pre><code>Na = Atoms(symbols='Na', positions=[[0, 0, 0]])\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.PF6","title":"PF6  <code>module-attribute</code>","text":"<pre><code>PF6 = Atoms(symbols='PF6', positions=[[6.747, 7.453, 7.469], [7.944, 6.319, 7.953], [6.127, 6.381, 6.461], [5.794, 8.645, 7.001], [5.815, 7.032, 8.699], [7.617, 8.534, 8.484], [7.91, 7.908, 6.284]])\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.elements","title":"elements  <code>module-attribute</code>","text":"<pre><code>elements = ['', 'H', 'He', 'Li', 'Be', 'B', 'C', 'N', 'O', 'F', 'Ne', 'Na', 'Mg', 'Al', 'Si', 'P', 'S', 'Cl', 'Ar', 'K', 'Ca', 'Sc', 'Ti', 'V', 'Cr', 'Mn', 'Fe', 'Co', 'Ni', 'Cu', 'Zn', 'Ga', 'Ge', 'As', 'Se', 'Br', 'Kr', 'Rb', 'Sr', 'Y', 'Zr', 'Nb', 'Mo', 'Tc', 'Ru', 'Rh', 'Pd', 'Ag', 'Cd', 'In', 'Sn', 'Sb', 'Te', 'I', 'Xe', 'Cs', 'Ba', 'La', 'Ce', 'Pr', 'Nd', 'Pm', 'Sm', 'Eu', 'Gd', 'Tb', 'Dy', 'Ho', 'Er', 'Tm', 'Yb', 'Lu', 'Hf', 'Ta', 'W', 'Re', 'Os', 'Ir', 'Pt', 'Au', 'Hg', 'Tl', 'Pb', 'Bi', 'Po', 'At', 'Rn', 'Fr', 'Ra', 'Ac', 'Th', 'Pa', 'U', 'Np', 'Pu', 'Am', 'Cm', 'Bk', 'Cf', 'Es', 'Fm', 'Md', 'No', 'Lr', 'Rf', 'Db', 'Sg', 'Bh', 'Hs', 'Mt', 'Ds', 'Rg', 'Uub', 'Uut', 'Uuq', 'Uup', 'Uuh', 'Uus', 'Uuo']\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.add_cell","title":"add_cell","text":"<pre><code>add_cell(atoms, cell_parameters)\n</code></pre> <p>Add cell parameters to the atoms object.</p> <p>Args:</p> <pre><code>atoms (ase.Atoms): The atoms object.\ncell_parameters (list): The cell parameters.\n</code></pre> <p>Returns:</p> <pre><code>atoms (ase.Atoms): The atoms object with cell parameters.\n</code></pre> Source code in <code>himatcal/atoms/core.py</code> <pre><code>def add_cell(atoms, cell_parameters):\n    \"\"\"\n    Add cell parameters to the atoms object.\n\n    Args:\n\n        atoms (ase.Atoms): The atoms object.\n        cell_parameters (list): The cell parameters.\n\n    Returns:\n\n        atoms (ase.Atoms): The atoms object with cell parameters.\n    \"\"\"\n\n    atoms.set_cell(cell_parameters)\n    return atoms\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.dock_atoms","title":"dock_atoms","text":"<pre><code>dock_atoms(ship: Atoms, dock: Atoms | str = 'PF6', chg: int = 0, mult: int = 1, offset: float = 1.5, crest_sampling: bool = True, topo_change: bool = False)\n</code></pre> <p>Dock the ship\ud83d\udea2 atoms to the dock\u2693 atoms (default is PF6).</p> Parameters: <p>ship_atoms (ase.Atoms): The ship atoms.</p> Source code in <code>himatcal/atoms/core.py</code> <pre><code>def dock_atoms(\n    ship: Atoms,\n    dock: Atoms | str = \"PF6\",\n    chg: int = 0,\n    mult: int = 1,\n    offset: float = 1.5,\n    crest_sampling: bool = True,\n    topo_change: bool = False,\n):\n    \"\"\"\n    Dock the ship\ud83d\udea2 atoms to the dock\u2693 atoms (default is PF6).\n\n    Parameters:\n    -----------\n    ship_atoms (ase.Atoms): The ship atoms.\n    \"\"\"\n    dock_atoms_dict = {\"PF6\": PF6.copy(), \"Li\": Li.copy(), \"Na\": Na.copy()}\n\n    if isinstance(dock, str):\n        dock = dock_atoms_dict.get(dock, dock)\n\n    docked_atoms = ship.copy()\n    ship_atoms_center = docked_atoms.get_center_of_mass()\n    ship_atoms_center[0] = max(docked_atoms.positions.T[0])\n    dock_atoms_center = dock.get_center_of_mass()\n    dock_atoms_center[0] = min(dock.positions.T[0])\n    vector = ship_atoms_center - dock_atoms_center + [offset, 0, 0]\n    dock.positions += vector\n    docked_atoms.extend(dock)\n    if not crest_sampling:\n        return docked_atoms\n\n    processed_atoms = None\n    for _ in range(3):\n        logging.info(f\"Trying sampling the docked atoms using iMTD-GC the {_} time\")\n        with contextlib.suppress(Exception):\n            processed_atoms = iMTD_GC(\n                docked_atoms, chg=chg, mult=mult, topo_change=topo_change\n            )\n            break\n    if processed_atoms is None:\n        logging.info(\"Sampling failed, trying the docked atoms with topology change\")\n        for _ in range(3):\n            with contextlib.suppress(Exception):\n                processed_atoms = iMTD_GC(\n                    docked_atoms, chg=chg, mult=mult, topo_change=True\n                )\n                break\n        logging.info(\"Crest iMTD-GC Sampling failed!\")\n    return processed_atoms\n</code></pre>"},{"location":"reference/himatcal/atoms/core.html#himatcal.atoms.core.tmp_atoms","title":"tmp_atoms","text":"<pre><code>tmp_atoms(atoms, filename='tmp.xyz', create_tmp_folder=True)\n</code></pre> <p>Write the atoms to a temporary file in the tmp folder and return the path.</p> <p>Args:</p> <pre><code>create_tmp_folder:\natoms (ase.Atoms): The atoms object.\nfilename (str): The filename of the temporary file.\n</code></pre> <p>Returns:</p> <pre><code>filepath (str): The path of the temporary file\n</code></pre> Source code in <code>himatcal/atoms/core.py</code> <pre><code>def tmp_atoms(atoms, filename=\"tmp.xyz\", create_tmp_folder=True):\n    \"\"\"\n    Write the atoms to a temporary file in the tmp folder and return the path.\n\n    Args:\n\n        create_tmp_folder:\n        atoms (ase.Atoms): The atoms object.\n        filename (str): The filename of the temporary file.\n\n    Returns:\n\n        filepath (str): The path of the temporary file\n    \"\"\"\n\n    _CWD = Path.cwd()\n    if create_tmp_folder:\n        from monty.os import makedirs_p\n\n        tmp_path = _CWD / \"tmp\"\n        makedirs_p(tmp_path)\n        filepath = _CWD / \"tmp\" / filename\n    else:\n        filepath = _CWD / filename\n    write(filepath, atoms, format=\"xyz\")\n    return filepath\n</code></pre>"},{"location":"reference/himatcal/atoms/parser.html","title":"parser","text":""},{"location":"reference/himatcal/atoms/parser.html#himatcal.atoms.parser.mol2xyz","title":"mol2xyz","text":"<pre><code>mol2xyz(mol, comment=None)\n</code></pre> <p>Convert rdkit mol to xyz file. from https://github.com/yanfeiguan/QM_descriptors_calculation/blob/master/lib/file_parser.py</p> Source code in <code>himatcal/atoms/parser.py</code> <pre><code>def mol2xyz(mol, comment=None):\n    \"\"\"\n    Convert rdkit mol to xyz file.\n    from https://github.com/yanfeiguan/QM_descriptors_calculation/blob/master/lib/file_parser.py\n    \"\"\"\n    c = mol.GetConformers()[0]\n    coords = c.GetPositions()\n    atoms = [a.GetSymbol() for a in mol.GetAtoms()]\n\n    xyz = f\"{len(atoms)}\\n{comment}\\n\"\n    for a, c in zip(atoms, coords):\n        xyz += \"{}     {:14.9f}    {:14.9f}    {:14.9f}\\n\".format(a, *c)\n\n    return xyz\n</code></pre>"},{"location":"reference/himatcal/atoms/parser.html#himatcal.atoms.parser.xyz2mol","title":"xyz2mol","text":"<pre><code>xyz2mol(xyz, smiles)\n</code></pre> <p>Convert xyz files to rdkit mol. from https://github.com/yanfeiguan/QM_descriptors_calculation/blob/master/lib/file_parser.py</p> Source code in <code>himatcal/atoms/parser.py</code> <pre><code>def xyz2mol(xyz, smiles):\n    \"\"\"\n    Convert xyz files to rdkit mol.\n    from https://github.com/yanfeiguan/QM_descriptors_calculation/blob/master/lib/file_parser.py\n    \"\"\"\n    lines = xyz.splitlines()\n    N_atoms = int(lines[0])\n    comments = lines[1]\n\n    if N_atoms != len(lines[2:]):\n        raise ValueError(\"Number of atoms does not match\")\n\n    mol = Chem.MolFromSmiles(smiles)\n    AllChem.EmbedMolecule(mol, AllChem.ETKDG())\n    mol = Chem.AddHs(mol, addCoords=True)\n    try:\n        conf = mol.GetConformers()[0]\n    except Exception:\n        AllChem.EmbedMultipleConfs(\n            mol,\n            numConfs=1,\n            pruneRmsThresh=0.5,\n            randomSeed=1,\n            useExpTorsionAnglePrefs=True,\n            useBasicKnowledge=True,\n        )\n        try:\n            conf = mol.GetConformers()[0]\n        except Exception:\n            return None, None\n\n    atoms = [a.GetSymbol() for a in mol.GetAtoms()]\n    for i, coord in enumerate(lines[2:]):\n        split_coord = coord.split()\n\n        if atoms[i] != split_coord[0]:\n            raise ValueError(\"Atom does not match\")\n\n        conf.SetAtomPosition(i, np.array(split_coord[1:]).astype(\"float\"))\n\n    mol.SetProp(\"comments\", comments)\n    return mol, comments\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html","title":"gaussian_mcd","text":""},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian","title":"FastGaussian","text":"<pre><code>FastGaussian(command='g09', working_directory=None)\n</code></pre> <p>               Bases: <code>Gaussian</code></p> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def __init__(self, command=\"g09\", working_directory=None):\n    super().__init__(command, working_directory)\n    self.old_chk_name = \"old\"\n    self.new_chk_name = \"new\"\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.new_chk_name","title":"new_chk_name  <code>instance-attribute</code>","text":"<pre><code>new_chk_name = 'new'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.old_chk_name","title":"old_chk_name  <code>instance-attribute</code>","text":"<pre><code>old_chk_name = 'old'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.change_chk_file","title":"change_chk_file","text":"<pre><code>change_chk_file()\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def change_chk_file(self):\n    old_chk_directory = os.path.join(\n        self.working_directory, self.old_chk_name + \".chk\"\n    )\n    new_chk_directory = os.path.join(\n        self.working_directory, self.new_chk_name + \".chk\"\n    )\n    os.system(f\"mv {new_chk_directory} {old_chk_directory}\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.get_content","title":"get_content","text":"<pre><code>get_content()\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_content(self):\n    # Check whether old one exists\n    content = self.content\n    if os.path.exists(f\"{self.old_chk_name}.chk\"):\n        # print ('check point exists!!!')\n        content = f\"%oldchk={self.old_chk_name}.chk\\n\" + content\n        content = content + \" guess=read \"\n    content = f\"%chk={self.new_chk_name}.chk\\n\" + content\n    return content\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.get_energy","title":"get_energy","text":"<pre><code>get_energy(molecule, chg=None, multiplicity=None, file_name='test', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_energy(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    extra=\"\",\n    save_directory=None,\n):\n    energy = super().get_energy(\n        molecule, chg, multiplicity, file_name, extra, save_directory\n    )\n    self.change_chk_file()\n    return energy\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.get_force","title":"get_force","text":"<pre><code>get_force(molecule, chg=None, multiplicity=None, file_name='test', extra=' Symmetry = None', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_force(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    extra=\" Symmetry = None\",\n    save_directory=None,\n):\n    force = super().get_force(\n        molecule, chg, multiplicity, file_name, extra, save_directory\n    )\n    self.change_chk_file()\n    return force\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.FastGaussian.optimize_geometry","title":"optimize_geometry","text":"<pre><code>optimize_geometry(molecule, constraints={}, chg=None, multiplicity=None, file_name='test', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def optimize_geometry(\n    self,\n    molecule,\n    constraints={},\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    extra=\"\",\n    save_directory=None,\n):\n    trajectory = super().optimize_geometry(\n        molecule, constraints, chg, multiplicity, file_name, extra, save_directory\n    )\n    self.change_chk_file()\n    return trajectory\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian","title":"Gaussian","text":"<pre><code>Gaussian(command='g16', working_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def __init__(self, command=\"g16\", working_directory=None):\n    # Check command\n    self.name = \"gaussian\"\n    check = distutils.spawn.find_executable(command)\n    if check is not None:\n        self.command = command\n    else:\n        # Check default command\n        commands = [\"g09\", \"g16\"]\n        found = False\n        for old_command in commands:\n            check = distutils.spawn.find_executable(old_command)\n            if check is not None:\n                self.command = old_command\n                print(\n                    f\"command {self.command} is used for running Gaussian, instead of {command}!\"\n                )\n                found = True\n                break\n        if not found:\n            print(\"Gaussian not found!\")\n            exit()\n\n    if working_directory is not None and not os.path.exists(working_directory):\n        os.system(f\"mkdir {working_directory}\")\n        if not os.path.exists(working_directory):\n            print(\"Defined working directory does not exist!!!\")\n            working_directory = None\n\n    if working_directory is None:\n        working_directory = os.getcwd()\n        print(\"working directory is set to current diretory:\", working_directory)\n\n    self.working_directory = working_directory\n    # Check save directory\n    self.content = \"#p pm6 scf(xqc) \"\n    self.energy_unit = \"Hartree\"\n    self.distance_unit = \"Bohr\"\n    self.radian_unit = \"Radian\"\n    self.basis = \"\"\n    self.error_directory = None\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.basis","title":"basis  <code>instance-attribute</code>","text":"<pre><code>basis = ''\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.command","title":"command  <code>instance-attribute</code>","text":"<pre><code>command = command\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.content","title":"content  <code>instance-attribute</code>","text":"<pre><code>content = '#p pm6 scf(xqc) '\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.distance_unit","title":"distance_unit  <code>instance-attribute</code>","text":"<pre><code>distance_unit = 'Bohr'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.energy_unit","title":"energy_unit  <code>instance-attribute</code>","text":"<pre><code>energy_unit = 'Hartree'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.error_directory","title":"error_directory  <code>instance-attribute</code>","text":"<pre><code>error_directory = None\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.name","title":"name  <code>instance-attribute</code>","text":"<pre><code>name = 'gaussian'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.radian_unit","title":"radian_unit  <code>instance-attribute</code>","text":"<pre><code>radian_unit = 'Radian'\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.working_directory","title":"working_directory  <code>instance-attribute</code>","text":"<pre><code>working_directory = working_directory\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.__str__","title":"__str__","text":"<pre><code>__str__()\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def __str__(self):\n    content = \"\"\n    content += f\"working_directory: {self.working_directory}\\n\"\n    content += f\"command: {self.command}\\n\"\n    content += f\"Energy: {self.energy_unit}\\n\\n\"\n    content += f\"###### qc_input ######\\n{self.content}\\n\"\n    return content\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.change_working_directory","title":"change_working_directory","text":"<pre><code>change_working_directory(working_directory)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def change_working_directory(self, working_directory):\n    # Get current reaction coordinate\n    if not os.path.exists(working_directory):\n        print(\"Working directory does not exist! Creating new directory ...\")\n        os.system(f\"mkdir {working_directory}\")\n        if not os.path.exists(working_directory):\n            print(\n                \"Cannot create working directory!!!\\n Recheck your working directory ...\"\n            )\n            exit()\n        else:\n            print(\"working directory changed into:\", working_directory)\n            self.working_directory = working_directory\n    else:\n        print(\"working directory changed into:\", working_directory)\n        self.working_directory = working_directory\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.clean_scratch","title":"clean_scratch","text":"<pre><code>clean_scratch(file_name='test.com')\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def clean_scratch(self, file_name=\"test.com\"):\n    working_directory = self.working_directory\n    chk_directory = os.path.join(working_directory, \"old.chk\")\n    os.system(f\"rm {chk_directory}\")\n    chk_directory = os.path.join(working_directory, \"new.chk\")\n    os.system(f\"rm {chk_directory}\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.get_content","title":"get_content","text":"<pre><code>get_content()\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_content(self):\n    return self.content\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.get_default_mol_params","title":"get_default_mol_params","text":"<pre><code>get_default_mol_params(molecule)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_default_mol_params(self, molecule):\n    try:\n        chg = molecule.get_chg()\n    except:\n        chg = 0\n    try:\n        multiplicity = molecule.get_multiplicity()\n    except:\n        multiplicity = None\n    if multiplicity is None:\n        try:\n            e_list = molecule.get_num_of_lone_pair_list()\n            num_of_unpaired_e = len(np.where((2 * e_list) % 2 == 1)[0])\n            multiplicity = num_of_unpaired_e + 1\n        except:\n            z_sum = np.sum(molecule.get_z_list())\n            multiplicity = (z_sum - chg) % 2 + 1\n    return chg, multiplicity\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.get_energy","title":"get_energy","text":"<pre><code>get_energy(molecule, chg=None, multiplicity=None, file_name='sp', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_energy(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"sp\",\n    extra=\"\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    if \"sp\" not in extra:\n        extra = \" sp \" + extra\n    self.make_input([molecule], chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com\")\n    # Read output\n    p = cclib.parser.Gaussian(f\"{file_name}.log\")\n    data = p.parse()\n    try:\n        data.scfenergies\n    except:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"gaussian.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Gaussian Energy Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None\n    self.move_file(file_name, save_directory)\n    converter = 1\n    os.chdir(current_directory)\n    if str.lower(self.energy_unit) == \"kcal\":\n        converter = 23.06\n    if str.lower(self.energy_unit) == \"hartree\":\n        converter = 0.036749326681\n    # os.system('mv new.chk old.chk')\n    os.chdir(current_directory)\n    return converter * data.scfenergies[-1]\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.get_force","title":"get_force","text":"<pre><code>get_force(molecule, chg=None, multiplicity=None, file_name='force', extra=' Symmetry = None', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_force(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"force\",\n    extra=\" Symmetry = None\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    if \"force\" not in extra:\n        extra = \" force \" + extra\n    if \"Symmetry\" not in extra:\n        extra = extra + \" Symmetry = None \"\n    self.make_input([molecule], chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com\")\n    # Read output\n    p = cclib.parser.Gaussian(f\"{file_name}.log\")\n    data = p.parse()\n    bohr_to_angstrom = 0.529177\n    try:\n        data.grads\n    except:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"gaussian.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Gaussian Force Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None\n    self.move_file(file_name, save_directory)\n    # os.system('mv new.chk old.chk')\n    os.chdir(current_directory)\n    return data.grads[-1] / bohr_to_angstrom\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.get_hessian","title":"get_hessian","text":"<pre><code>get_hessian(molecule, chg=None, multiplicity=None, file_name='hessian', extra=' Symmetry = None', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def get_hessian(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"hessian\",\n    extra=\" Symmetry = None\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    original_content = self.content\n    if \"chk\" not in self.content:\n        self.content = \"%chk=hessian.chk\\n\" + self.content\n    if \"freq\" not in extra:\n        extra = \" freq \" + extra\n    if \"Symmetry\" not in extra:\n        extra = extra + \" Symmetry = None \"\n    self.make_input([molecule], chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com\")\n    os.system(\"formchk hessian.chk\")\n    force = []\n    hessian = []\n    bohr_to_angstrom = 0.529177  # Units are Hartree/bohr in chkpoint file\n\n    if not os.path.exists(\"hessian.chk\"):\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"gaussian.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Gaussian Hessian Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None\n\n    # Read fchk file\n    with open(\"hessian.fchk\", \"r\") as f:\n        lines = f.readlines()\n        index = 0\n        while index &lt; len(lines):\n            line = lines[index]\n            if \"Cartesian Gradient\" in line:\n                index += 1\n                line = lines[index]\n                infos = line.strip().split()\n                # Read line\n                while True:\n                    try:\n                        float(infos[0])\n                    except:\n                        break\n                    force = force + [float(info) for info in infos]\n                    index += 1\n                    line = lines[index]\n                    infos = line.strip().split()\n\n            if \"Cartesian Force Constant\" in line:\n                index += 1\n                line = lines[index]\n                infos = line.strip().split()\n                # Read line\n                while True:\n                    try:\n                        float(infos[0])\n                    except:\n                        break\n                    hessian = hessian + [float(info) for info in infos]\n                    index += 1\n                    line = lines[index]\n                    infos = line.strip().split()\n\n            index += 1\n            if len(force) &gt; 0 and len(hessian) &gt; 0:\n                break\n\n    n = len(molecule.atom_list)\n    force = -np.array(force)\n    force = np.reshape(force, (n, 3))\n    new_hessian = np.zeros((3 * n, 3 * n))\n    cnt = 0\n    for i in range(3 * n):\n        for j in range(i + 1):\n            new_hessian[i][j] = new_hessian[j][i] = hessian[cnt]\n            cnt += 1\n    hessian = new_hessian\n    self.move_file(file_name, save_directory)\n    # os.system('mv new.chk old.chk')\n    os.chdir(current_directory)\n    self.content = original_content\n    return force / bohr_to_angstrom, hessian / bohr_to_angstrom**2\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.load_basis","title":"load_basis","text":"<pre><code>load_basis(basis_directory)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def load_basis(self, basis_directory):\n    if os.path.exists(basis_directory):\n        basis = \"\"\n        with open(basis_directory) as f:\n            for line in f:\n                basis = basis + line\n        self.basis = basis\n    else:\n        print(\"basis file does not exist!!!\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.load_content","title":"load_content","text":"<pre><code>load_content(template_directory)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def load_content(self, template_directory):\n    if os.path.exists(template_directory):\n        content = \"\"\n        with open(template_directory) as f:\n            lines = f.readlines()\n            n = len(lines)\n            for i, line in enumerate(lines):\n                if i == n - 1:\n                    line = line.strip()\n                content = content + line\n        self.content = content\n    else:\n        print(\"qc input file does not exist!!!\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.make_input","title":"make_input","text":"<pre><code>make_input(molecules, chg=None, multiplicity=None, file_name='test', constraints={}, extra='')\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def make_input(\n    self,\n    molecules,\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    constraints={},\n    extra=\"\",\n):\n    f = open(f\"{file_name}.com\", \"w\")\n    if chg is None or multiplicity is None:\n        if molecules[0] is not None:\n            chg, multiplicity = self.get_default_mol_params(molecules[0])\n        elif molecules[-1] is not None:\n            chg, multiplicity = self.get_default_mol_params(molecules[-1])\n    content = self.get_content()\n    if len(constraints) &gt; 0:\n        if \"modredundant\" not in extra:\n            print(\"WARNING! Fixed optimization is not working ...\")\n            print(\"constraints:\", constraints, extra)\n    content = content + f\"{extra}\\n\\n\"\n    f.write(content)\n    labels = [\"R\", \"P\", \"TS\"]\n    for i, molecule in enumerate(molecules):\n        if molecule is not None:\n            f.write(f\"{labels[i]}\\n\\n\")\n            self.write_molecule_info(f, molecule, chg, multiplicity)\n    ### Write constraints\n    for constraint in constraints:\n        constraint_info = []\n        if len(constraint) == 1:\n            constraint_info.append(\"X\")\n        elif len(constraint) == 2:\n            constraint_info.append(\"B\")\n        elif len(constraint) == 3:\n            constraint_info.append(\"A\")\n        else:\n            constraint_info.append(\"D\")\n        for index in constraint:\n            constraint_info.append(str(index + 1))\n        constraint_info.append(\"F\")\n        f.write(\" \".join(constraint_info) + \"\\n\")\n    f.write(\"\\n\")  # Additional empty line required\n    self.write_basis(f)\n    f.write(\"\\n\")\n    f.close()\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.make_uff_input","title":"make_uff_input","text":"<pre><code>make_uff_input(molecule, chg=None, multiplicity=None, option='opt', file_name='test', constraints={})\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def make_uff_input(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    option=\"opt\",\n    file_name=\"test\",\n    constraints={},\n):\n    bo_matrix = molecule.get_bo_matrix()\n    if bo_matrix is None:\n        bo_matrix = molecule.get_adj_matrix()\n        if bo_matrix is None:\n            bo_matrix = process.get_adj_matrix_from_distance(molecule, 1.2)\n            if bo_matrix is None:\n                print(\"Cannot define connectivity !!!\")\n                return None\n    # bo matrix is now defined ...\n    f = open(f\"{file_name}.com\", \"w\")\n    if chg is None or multiplicity is None:\n        chg, multiplicity = self.get_default_mol_params(molecule)\n    content = \"\"\n    content = content + option + \"\\n\\ntest\\n\\n\"\n    f.write(content)\n    self.write_molecule_info(f, molecule, chg, multiplicity)\n    ### Write constraints\n    for constraint in constraints:\n        constraint_info = []\n        if len(constraint) == 1:\n            constraint_info.append(\"X\")\n        elif len(constraint) == 2:\n            constraint_info.append(\"B\")\n        elif len(constraint) == 3:\n            constraint_info.append(\"A\")\n        else:\n            constraint_info.append(\"D\")\n        for index in constraint:\n            constraint_info.append(str(index + 1))\n        constraint_info.append(\"F\")\n        f.write(\" \".join(constraint_info) + \"\\n\")\n    f.write(\"\\n\")  # Additional empty line required\n    self.write_basis(f)\n    f.write(\"\\n\")\n    f.close()\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.move_file","title":"move_file","text":"<pre><code>move_file(file_name, save_directory)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def move_file(self, file_name, save_directory):\n    if file_name is not None and save_directory is not None:\n        os.system(f\"mv {file_name}.com {save_directory}/\")\n        os.system(f\"mv {file_name}.log {save_directory}/\")\n        os.system(f\"mv *chk {save_directory}/\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.optimize_geometry","title":"optimize_geometry","text":"<pre><code>optimize_geometry(molecule, constraints={}, chg=None, multiplicity=None, file_name='test', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def optimize_geometry(\n    self,\n    molecule,\n    constraints={},\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    extra=\"\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    if \"opt\" not in extra:\n        extra = \" opt \" + extra\n    self.make_input([molecule], chg, multiplicity, file_name, constraints, extra)\n    os.system(f\"{self.command} {file_name}.com\")\n    # Read output\n    p = cclib.parser.Gaussian(f\"{file_name}.log\")\n    data = p.parse()\n    self.move_file(file_name, save_directory)\n    trajectory = []\n\n    try:\n        geometries = data.atomcoords\n        energies = data.scfenergies\n    except:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"gaussian.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Gaussian Optimization Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return []\n\n    if len(geometries) &lt; 1:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"gaussian.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Gaussian Optimization Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return []\n\n    converter = 1\n    if str.lower(self.energy_unit) == \"kcal\":\n        converter = 23.06\n    if str.lower(self.energy_unit) == \"hartree\":\n        converter = 0.036749326681\n        # converter = 1/27.2114\n\n    energies *= converter\n    minimum_energy = 10000000\n    min_index = 0\n\n    for i, coordinate_list in enumerate(geometries):\n        copied_molecule = molecule.copy()\n        process.locate_molecule(copied_molecule, coordinate_list)\n        copied_molecule.adj_matrix = None\n        copied_molecule.bo_matrix = None\n        copied_molecule.energy = energies[i]\n        trajectory.append(copied_molecule)\n        if minimum_energy &gt; energies[i]:\n            min_index = i\n            minimum_energy = energies[i]\n\n    coordinate_list = geometries[\n        min_index\n    ]  # Sometimes length is not matched, it performs extra scfenergy calculation\n    process.locate_molecule(molecule, coordinate_list)\n    molecule.energy = energies[min_index]\n    # os.system('mv new.chk old.chk')\n    os.chdir(current_directory)\n    return trajectory\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.relax_geometry","title":"relax_geometry","text":"<pre><code>relax_geometry(molecule, constraints, chg=None, multiplicity=None, file_name='test', num_relaxation=10000, maximal_displacement=1000, extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def relax_geometry(\n    self,\n    molecule,\n    constraints,\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    num_relaxation=10000,\n    maximal_displacement=1000,\n    extra=\"\",\n    save_directory=None,\n):\n    options = []\n    if len(constraints) &gt; 0:\n        options.append(\"modredundant,loose\")\n    else:\n        options.append(\"loose\")\n    if maximal_displacement is not None and maximal_displacement &lt; 100:\n        max_step = int(maximal_displacement * 100) + 1\n        options.append(f\"maxstep={max_step},notrust\")\n    if num_relaxation is not None and num_relaxation &lt; 10000:\n        options.append(f\"maxcycles={num_relaxation}\")\n    if len(options) &gt; 0:\n        content = \" opt(\" + \",\".join(options) + \") \"\n    else:\n        content = \" opt \"\n    extra = content + extra + \" Symmetry = None\"\n    return self.optimize_geometry(\n        molecule, constraints, chg, multiplicity, file_name, extra, save_directory\n    )\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.run","title":"run","text":"<pre><code>run(molecule, chg=None, multiplicity=None, file_name='test', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def run(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"test\",\n    save_directory=None,\n):  # Running with user defined result and return raw data\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    self.make_input(molecule, chg, multiplicity, file_name, {}, \"\")\n    os.system(f\"{self.command} {file_name}.com\")\n    # Read output\n    p = cclib.parser.Gaussian(f\"{file_name}.log\")\n    data = p.parse()\n    self.move_file(file_name, save_directory)\n    converter = 1\n    if str.lower(self.energy_unit) == \"kcal\":\n        converter = 23.06\n    if str.lower(self.energy_unit) == \"hartree\":\n        converter = 0.036749326681\n    if \"opt\" in self.content:\n        print(\"Running optimization !!!\")\n        index = np.argmin(data.scfenergies)\n        if index &gt; len(data.atomcoords) - 1:\n            index = -1\n        coordinate_list = data.atomcoords[\n            index\n        ]  # Sometimes length is not matched, it performs extra scfenergy calculation\n        energy = data.scfenergies[index] * converter\n        process.locate_molecule(molecule, coordinate_list)\n        molecule.energy = energy\n    os.chdir(current_directory)\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.set_error_directory","title":"set_error_directory","text":"<pre><code>set_error_directory(error_directory)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def set_error_directory(self, error_directory):\n    try:\n        if os.path.exists(error_directory):\n            self.error_directory = error_directory\n        else:\n            print(f\"Given error directory: {error_directory} does not exist!!! \")\n    except:\n        print(error_directory)\n        print(\"Check your error directory !!!\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.write_basis","title":"write_basis","text":"<pre><code>write_basis(f)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def write_basis(self, f):\n    if self.basis != \"\":\n        f.write(f\"{self.basis}\\n\")\n</code></pre>"},{"location":"reference/himatcal/calculator/gaussian_mcd.html#himatcal.calculator.gaussian_mcd.Gaussian.write_molecule_info","title":"write_molecule_info","text":"<pre><code>write_molecule_info(f, molecule, chg, multiplicity)\n</code></pre> Source code in <code>himatcal/calculator/gaussian_mcd.py</code> <pre><code>def write_molecule_info(self, f, molecule, chg, multiplicity):\n    f.write(f\"{int(chg)} {int(multiplicity)}\\n\")\n    for atom in molecule.atom_list:\n        f.write(atom.get_content())\n    f.write(\"\\n\")\n</code></pre>"},{"location":"reference/himatcal/calculator/mlp.html","title":"mlp","text":""},{"location":"reference/himatcal/calculator/mlp.html#himatcal.calculator.mlp.get_calc","title":"get_calc","text":"<pre><code>get_calc(label, kwargs: dict | None = None)\n</code></pre> Source code in <code>himatcal/calculator/mlp.py</code> <pre><code>def get_calc(label, kwargs: dict | None = None):\n    \"\"\" \"\"\"\n    kwargs = kwargs or {}\n    device = kwargs.get(\"device\", \"cuda\" if label.startswith(\"orb\") else \"cpu\")\n\n    if label.startswith(\"orb\"):  # * orb_v2, orb_d3_v2, orb_d3_xm_v2, orb_d3_sm_v2\n        from orb_models.forcefield import pretrained\n        from orb_models.forcefield.calculator import ORBCalculator\n\n        model_path = kwargs.get(\"model\")\n        orbff = (\n            getattr(pretrained, label)(device=device, weight_path=model_path)\n            if model_path\n            else getattr(pretrained, label)(device=device)\n        )\n        return ORBCalculator(orbff, device=device)\n\n    if label == \"mace_mp\":\n        from mace.calculators import mace_mp\n\n        return mace_mp(\n            model=kwargs.get(\"model\", \"medium\"),  # * small , medium, large\n            device=device,  # * cpu, cuda\n            default_dtype=kwargs.get(\"default_type\", \"float32\"),\n            dispersion=kwargs.get(\"dispersion\", True),\n            damping=kwargs.get(\"damping\", \"bj\"),\n            dispersion_xc=kwargs.get(\"dispersion_xc\", \"pbe\"),\n            dispersion_cutoff=kwargs.get(\"dispersion_cutoff\", 40 * units.Bohr),\n        )\n\n    if label == \"mace_off\":\n        from mace.calculators import mace_off\n\n        return mace_off(\n            model=kwargs.get(\"model\", \"medium\"),\n            device=device,\n            default_dtype=kwargs.get(\"default_dtype\", \"float64\"),\n        )\n\n    if label == \"mace_anicc\":\n        from mace.calculators import mace_anicc\n\n        return mace_anicc(model_path=kwargs.get(\"model\"), device=device)\n\n    if label == \"chgnet\":\n        from chgnet.model.dynamics import CHGNetCalculator\n\n        return CHGNetCalculator(model_path=kwargs.get(\"model\"), use_device=device)\n    if label == \"aimnet2\":\n        from himatcal.calculator.aimnet import AIMNet2ASE\n\n        return AIMNet2ASE(\"aimnet2_b973c\", charge=kwargs.get(\"charge\", 0), mult=kwargs.get(\"mult\", 1))\n    return None\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html","title":"orca_mcd","text":""},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.data","title":"data  <code>module-attribute</code>","text":"<pre><code>data = parse_hessian(directory)\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.directory","title":"directory  <code>module-attribute</code>","text":"<pre><code>directory = argv[1]\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca","title":"Orca","text":"<pre><code>Orca(command='orca', working_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def __init__(self, command=\"orca\", working_directory=None):\n    check = distutils.spawn.find_executable(command)\n    self.name = \"orca\"\n    if check is None:\n        print(\"orca not found!\")\n        exit()\n    self.command = command\n    self.nproc = 1\n    self.content = \"! XTB2 \"\n    self.energy_unit = \"Hartree\"\n    # self.distance_unit = 'Bohr'\n    # self.radian_unit = 'Radian'\n\n    if working_directory is not None:\n        if not os.path.exists(working_directory):\n            os.system(f\"mkdir {working_directory}\")\n            if not os.path.exists(working_directory):\n                print(\"Defined working directory does not exist!!!\")\n                working_directory = None\n\n    if working_directory is None:\n        working_directory = os.getcwd()\n        print(\"working directory is set to current diretory:\", working_directory)\n\n    self.working_directory = working_directory\n    self.error_directory = None\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.command","title":"command  <code>instance-attribute</code>","text":"<pre><code>command = command\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.content","title":"content  <code>instance-attribute</code>","text":"<pre><code>content = '! XTB2 '\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.energy_unit","title":"energy_unit  <code>instance-attribute</code>","text":"<pre><code>energy_unit = 'Hartree'\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.error_directory","title":"error_directory  <code>instance-attribute</code>","text":"<pre><code>error_directory = None\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.name","title":"name  <code>instance-attribute</code>","text":"<pre><code>name = 'orca'\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.nproc","title":"nproc  <code>instance-attribute</code>","text":"<pre><code>nproc = 1\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.working_directory","title":"working_directory  <code>instance-attribute</code>","text":"<pre><code>working_directory = working_directory\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.__str__","title":"__str__","text":"<pre><code>__str__()\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def __str__(self):\n    content = \"\"\n    content = content + f\"working_directory: {self.working_directory}\\n\"\n    content = content + f\"command: {self.command}\\n\"\n    content = content + f\"Energy: {self.energy_unit}\\n\\n\"\n    content = content + f\"###### qc_input ######\\n{self.content}\\n\"\n    return content\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.change_working_directory","title":"change_working_directory","text":"<pre><code>change_working_directory(working_directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def change_working_directory(self, working_directory):\n    # Get current reaction coordinate\n    if not os.path.exists(working_directory):\n        print(\"Working directory does not exist! Creating new directory ...\")\n        os.system(f\"mkdir {working_directory}\")\n        if not os.path.exists(working_directory):\n            print(\n                \"Cannot create working directory!!!\\n Recheck your working directory ...\"\n            )\n            exit()\n        else:\n            print(\"working directory changed into:\", working_directory)\n            self.working_directory = working_directory\n    else:\n        print(\"working directory changed into:\", working_directory)\n        self.working_directory = working_directory\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.get_default_mol_params","title":"get_default_mol_params","text":"<pre><code>get_default_mol_params(molecule)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def get_default_mol_params(self, molecule):\n    try:\n        chg = molecule.get_chg()\n    except:\n        chg = 0\n    try:\n        e_list = molecule.get_num_of_lone_pair_list()\n        num_of_unpaired_e = len(np.where((2 * e_list) % 2 == 1)[0])\n        multiplicity = num_of_unpaired_e + 1\n    except:\n        z_sum = np.sum(molecule.get_z_list())\n        multiplicity = (z_sum - chg) % 2 + 1\n    return chg, multiplicity\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.get_energy","title":"get_energy","text":"<pre><code>get_energy(molecule, chg=None, multiplicity=None, file_name='sp', extra='', save_directory=None)\n</code></pre> <p>Must return energy with desired unit defined in the Calculator</p> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def get_energy(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"sp\",\n    extra=\"\",\n    save_directory=None,\n):\n    \"\"\"\n    Must return energy with desired unit defined in the Calculator\n    \"\"\"\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    self.make_input(molecule, chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com &gt; {file_name}.log\")\n    energy = parse_energy(\n        os.path.join(self.working_directory, f\"{file_name}.energy\")\n    )\n    self.move_file(file_name, save_directory)\n    converter = 1\n    if energy is None:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"orca.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Orca Energy Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None\n    if self.energy_unit == \"kcal\":\n        converter = 627.509\n    if self.energy_unit == \"eV\":\n        converter = 27.2114079527\n    os.chdir(current_directory)\n    return converter * energy\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.get_force","title":"get_force","text":"<pre><code>get_force(molecule, chg=None, multiplicity=None, file_name='force', extra='', save_directory=None)\n</code></pre> <p>Must return force with desired unit defined in the Calculator</p> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def get_force(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"force\",\n    extra=\"\",\n    save_directory=None,\n):\n    \"\"\"\n    Must return force with desired unit defined in the Calculator\n    \"\"\"\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    if \"engrad\" not in extra:\n        extra = \" engrad \" + extra\n    self.make_input(molecule, chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com &gt; {file_name}.log\")\n    self.move_file(file_name, save_directory)\n    energy, force = parse_force(\n        os.path.join(self.working_directory, f\"{file_name}.engrad\")\n    )\n    bohr_to_angstrom = 0.529177  # Units are Hartree/bohr in chkpoint file\n    if force is None:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"orca.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Orca Force Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None\n    os.chdir(current_directory)\n    return force / bohr_to_angstrom\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.get_hessian","title":"get_hessian","text":"<pre><code>get_hessian(molecule, chg=None, multiplicity=None, file_name='hessian', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def get_hessian(\n    self,\n    molecule,\n    chg=None,\n    multiplicity=None,\n    file_name=\"hessian\",\n    extra=\"\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    original_content = self.content\n    if \"engrad\" not in extra:\n        extra = \"engrad \" + extra\n    if \"freq\" not in extra:\n        extra = \" freq \" + extra\n    self.make_input(molecule, chg, multiplicity, file_name=file_name, extra=extra)\n    os.system(f\"{self.command} {file_name}.com &gt; {file_name}.log\")\n    energy, force = parse_force(\n        os.path.join(self.working_directory, f\"{file_name}.engrad\")\n    )\n    hessian = parse_hessian(\n        os.path.join(self.working_directory, f\"{file_name}.hess\")\n    )\n    bohr_to_angstrom = 0.529177  # Units are Hartree/bohr in chkpoint file\n    if force is None:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"orca.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Orca Force Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None, None\n    if hessian is None:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"orca.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Orca Hessian Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return None, None\n    self.move_file(file_name, save_directory)\n    os.chdir(current_directory)\n    return force / bohr_to_angstrom, hessian / bohr_to_angstrom**2\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.load_basis","title":"load_basis","text":"<pre><code>load_basis(basis_directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def load_basis(self, basis_directory):\n    basis = \"\"\n    with open(basis_directory) as f:\n        for line in f:\n            basis = basis + line\n    self.basis = basis\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.load_content","title":"load_content","text":"<pre><code>load_content(template_directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def load_content(self, template_directory):\n    content = \"\"\n    with open(template_directory) as f:\n        for line in f:\n            content = content + line\n    self.content = content\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.make_input","title":"make_input","text":"<pre><code>make_input(molecule, chg, multiplicity, file_name='test', constraints={}, extra='')\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def make_input(\n    self, molecule, chg, multiplicity, file_name=\"test\", constraints={}, extra=\"\"\n):\n    if chg is None or multiplicity is None:\n        chg, multiplicity = self.get_default_mol_params(molecule)\n\n    inpstring = self.content.strip()\n    if inpstring[0] == \"#\":\n        inpstring = inpstring[1:]\n    inpstring = inpstring + extra\n\n    \"\"\"\n    inpstring += '%scf\\nMaxIter 300\\nconvergence strong\\n sthresh 1e-7\\n'\n    inpstring += 'thresh 1e-11\\n tcut 1e-13 \\n directresetfreq 1 \\n SOSCFStart 0.00033\\nend\\n'\n    inpstring += '%scf\\nMaxIter 300\\nend\\n'\n    inpstring += '\\n%maxcore 1000\\n\\n'\n    inpstring += '%pal\\nnproc {}\\nend\\n\\n'.format(self.nproc)\n    \"\"\"\n    # if len(constraints) &gt; 0:\n    inpstring += f\"\\n*xyz {chg} {multiplicity}\\n\"\n    for atom in molecule.atom_list:\n        inpstring += atom.get_content()\n\n    inpstring += \"*\"\n    with open(f\"{file_name}.com\", \"w\") as f:\n        f.write(inpstring)\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.move_file","title":"move_file","text":"<pre><code>move_file(file_name, save_directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def move_file(self, file_name, save_directory):\n    if file_name is not None and save_directory is not None:\n        os.system(f\"mv {file_name}.* {save_directory}/\")\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.optimize_geometry","title":"optimize_geometry","text":"<pre><code>optimize_geometry(molecule, constraints={}, chg=None, multiplicity=None, file_name='opt', extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def optimize_geometry(\n    self,\n    molecule,\n    constraints={},\n    chg=None,\n    multiplicity=None,\n    file_name=\"opt\",\n    extra=\"\",\n    save_directory=None,\n):\n    current_directory = os.getcwd()\n    os.chdir(self.working_directory)\n    if \"opt\" not in extra:\n        extra = \" opt \" + extra\n\n    # Additional constraint\n    if len(constraints) &gt; 0:\n        if \"geom\" not in extra:\n            extra = extra + \"\\n\\n%geom\\nConstraints\\n\"\n        else:\n            extra = extra + \"Constraints\\n\"\n        for constraint in constraints:\n            constraint_info = []\n            if len(constraint) == 2:\n                constraint_info.append(\"{B\")\n            elif len(constraint) == 3:\n                constraint_info.append(\"{A\")\n            else:\n                constraint_info.append(\"{D\")\n            for index in constraint:\n                constraint_info.append(str(index))\n            constraint_info.append(\"C}\")\n            extra += \" \".join(constraint_info) + \"\\n\"\n        extra += \"end\\n\"\n        extra += \"end\\n\"\n\n    self.make_input(\n        molecule,\n        chg,\n        multiplicity,\n        file_name=file_name,\n        extra=extra,\n        constraints=constraints,\n    )\n    os.system(f\"{self.command} {file_name}.com &gt; {file_name}.log\")\n    relaxing_path = parse_opt(\n        os.path.join(self.working_directory, f\"{file_name}_trj.xyz\")\n    )\n    if len(relaxing_path) &lt; 2:\n        if self.error_directory is not None:\n            file_directory = os.path.join(self.error_directory, \"orca.err\")\n            with open(file_directory, \"w\") as f:\n                f.write(\"Orca Optimization Calculation failed !!!\\n\")\n                name = f\"{file_name}.log\"\n                f.write(f\"Check {os.path.join(self.working_directory,name)} ...\\n\")\n        return []\n    energy, force = parse_force(\n        os.path.join(self.working_directory, f\"{file_name}.engrad\")\n    )\n    print(\"energy\", energy)\n    process.locate_molecule(molecule, relaxing_path[-1].get_coordinate_list())\n    molecule.energy = energy\n    os.chdir(current_directory)\n    return relaxing_path\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.relax_geometry","title":"relax_geometry","text":"<pre><code>relax_geometry(molecule, constraints, chg=None, multiplicity=None, file_name='opt', num_relaxation=5, maximal_displacement=1000, extra='', save_directory=None)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def relax_geometry(\n    self,\n    molecule,\n    constraints,\n    chg=None,\n    multiplicity=None,\n    file_name=\"opt\",\n    num_relaxation=5,\n    maximal_displacement=1000,\n    extra=\"\",\n    save_directory=None,\n):\n    \"\"\" \"\"\"\n    extra = \"\\n%geom\\n\"\n    if maximal_displacement &lt; 1000:\n        maximal_displacement = -abs(maximal_displacement)\n        extra = extra + f\"Trust {maximal_displacement}\\n\"\n    if num_relaxation is not None and num_relaxation &gt; 0:\n        extra = extra + f\"MaxIter {num_relaxation}\\n\"\n    return self.optimize_geometry(\n        molecule, constraints, chg, multiplicity, file_name, extra, save_directory\n    )\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.Orca.set_error_directory","title":"set_error_directory","text":"<pre><code>set_error_directory(error_directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def set_error_directory(self, error_directory):\n    try:\n        if os.path.exists(error_directory):\n            self.error_directory = error_directory\n        else:\n            print(f\"Given error directory: {error_directory} does not exist!!! \")\n    except:\n        print(error_directory)\n        print(\"Check your error directory !!!\")\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.parse_energy","title":"parse_energy","text":"<pre><code>parse_energy(directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def parse_energy(directory):  # Read {file_name}.energy\n    try:\n        with open(directory, \"r\") as f:\n            lines = f.readlines()\n    except:\n        return None\n\n    temp = 100000\n    for i, line in enumerate(lines):\n        if \"$energy\\n\" in line:\n            temp = i\n        if i &gt; temp:\n            energy = float(line.split()[-1])\n            return energy\n    return None\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.parse_force","title":"parse_force","text":"<pre><code>parse_force(directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def parse_force(directory):  # Read {file_name}.engrad\n    with open(directory) as f:\n        lines = f.readlines()\n\n    temp = 100000\n    grads = []\n    energy = None\n    for i, line in enumerate(lines):\n        if \"# The current total energy\" in line:\n            energy = float(lines[i + 2].strip())\n        if \"# The current gradient in Eh/bohr\" in line:\n            temp = i\n        if i &gt; temp + 1:\n            if \"#\" in line:\n                break\n            grads.append(float(line.strip()))\n    try:\n        n = len(grads)\n    except:\n        return None, None\n\n    if n == 0:\n        return None, None\n\n    if n % 3 != 0:\n        print(\"what?\")\n        return None, None\n\n    n = int(n / 3)\n    force = -np.array(grads)  # F = -g\n    force = np.reshape(force, (n, 3))\n    return energy, force\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.parse_hessian","title":"parse_hessian","text":"<pre><code>parse_hessian(directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def parse_hessian(directory):  # Read {file_name}.hess\n    target_line = 0\n    # Find $hessian\n    try:\n        with open(directory, \"r\") as f:\n            lines = f.readlines()\n            for idx, line in enumerate(lines):\n                if \"$hessian\" in line:\n                    index = idx\n                    index += 1\n                    break\n    except:\n        return None\n    n = int(lines[index])\n    index += 1\n    hessian = np.zeros((n, n))\n    cnt = 0\n    while cnt &lt; n:\n        index_infos = lines[index].strip().split()\n        index += 1\n        for i in range(n):\n            values = lines[index].strip().split()\n            index += 1\n            for j, index_info in enumerate(index_infos):\n                index_info = int(index_info)\n                hessian[i][index_info] = float(values[j + 1])\n        cnt += len(index_infos)\n        # print (cnt)\n    return hessian\n</code></pre>"},{"location":"reference/himatcal/calculator/orca_mcd.html#himatcal.calculator.orca_mcd.parse_opt","title":"parse_opt","text":"<pre><code>parse_opt(directory)\n</code></pre> Source code in <code>himatcal/calculator/orca_mcd.py</code> <pre><code>def parse_opt(directory):  # Read {file_name}.trj.xyz\n    # Open ORCA output file and read its contents\n    try:\n        with open(directory) as f:\n            lines = f.readlines()\n    except:\n        return []\n\n    trajectory = []\n    index = 0\n    while index &lt; len(lines):\n        num_atom = int(lines[index].strip())  # read num_atom\n        index += 1\n        infos = lines[index].strip().split()  # Read energy\n        energy = float(infos[-1])\n        index += 1\n        atom_list = []\n        for i in range(num_atom):\n            atom_info = lines[index].strip().split()\n            index += 1\n            element = atom_info[0]\n            x = float(atom_info[1])\n            y = float(atom_info[2])\n            z = float(atom_info[3])\n            atom = chem.Atom(element)\n            atom.x = x\n            atom.y = y\n            atom.z = z\n            atom_list.append(atom)\n        if len(atom_list) &gt; 0:\n            molecule = chem.Molecule()\n            molecule.atom_list = atom_list\n            molecule.energy = energy\n            trajectory.append(molecule)\n        else:\n            break\n    return trajectory\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html","title":"pyscf_calculator","text":"<p>ASE pySCF calcuator, from scm</p>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.atoms","title":"atoms  <code>module-attribute</code>","text":"<pre><code>atoms = molecule('H2O')\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator","title":"PySCFCalculator","text":"<pre><code>PySCFCalculator(xc: str = 'pbe', basis: str = '631g*', symmetry: bool = True, **kwargs)\n</code></pre> <p>               Bases: <code>Calculator</code></p> <p>Example DFT calculator for PySCF. Only some minimal options are supported.</p> Source code in <code>himatcal/calculator/pyscf_calculator.py</code> <pre><code>def __init__(\n    self,\n    xc: str = \"pbe\",  # https://pyscf.org/_modules/pyscf/dft/xcfun.html\n    basis: str = \"631g*\",  # https://pyscf.org/_modules/pyscf/gto/basis.html\n    symmetry: bool = True,\n    **kwargs,\n):\n    super().__init__(**kwargs)\n    self.xc = xc\n    self.basis = basis\n    self.symmetry = symmetry\n    self.M = pyscf.M()\n    self.dm1 = None  # density matrix\n    self.ams_capabilities: Any = None\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.M","title":"M  <code>instance-attribute</code>","text":"<pre><code>M = M()\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.ams_capabilities","title":"ams_capabilities  <code>instance-attribute</code>","text":"<pre><code>ams_capabilities: Any = None\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.basis","title":"basis  <code>instance-attribute</code>","text":"<pre><code>basis = basis\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.dm1","title":"dm1  <code>instance-attribute</code>","text":"<pre><code>dm1 = None\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.implemented_properties","title":"implemented_properties  <code>class-attribute</code>","text":"<pre><code>implemented_properties: list[str] = ['energy', 'forces', 'dipole', 'charges']\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.symmetry","title":"symmetry  <code>instance-attribute</code>","text":"<pre><code>symmetry = symmetry\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.xc","title":"xc  <code>instance-attribute</code>","text":"<pre><code>xc = xc\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.atoms2pyscf","title":"atoms2pyscf  <code>staticmethod</code>","text":"<pre><code>atoms2pyscf(atoms: Atoms) -&gt; list[tuple[str, tuple[float, float, float]]]\n</code></pre> <p>Convert ASE Atoms to the list of symbols and coordinates required by pySCF</p> Source code in <code>himatcal/calculator/pyscf_calculator.py</code> <pre><code>@staticmethod\ndef atoms2pyscf(atoms: ase.Atoms) -&gt; list[tuple[str, tuple[float, float, float]]]:\n    \"\"\"Convert ASE Atoms to the list of symbols and coordinates required by pySCF\"\"\"\n    return [\n        (symbol, (xyz[0], xyz[1], xyz[2]))\n        for symbol, xyz in zip(atoms.get_chemical_symbols(), atoms.get_positions())\n    ]\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.PySCFCalculator.calculate","title":"calculate","text":"<pre><code>calculate(atoms=None, properties=None, system_changes=None) -&gt; None\n</code></pre> <p>Perform DFT calculation, populate self.results with energy, forces, dipole, charge</p> Source code in <code>himatcal/calculator/pyscf_calculator.py</code> <pre><code>def calculate(self, atoms=None, properties=None, system_changes=None) -&gt; None:\n    \"\"\"Perform DFT calculation, populate self.results with energy, forces, dipole, charge\"\"\"\n    Calculator.calculate(\n        self, atoms=atoms, properties=properties, system_changes=system_changes\n    )\n    self.results = {}\n    if atoms is None:\n        return\n\n    pyscf_atoms = self.atoms2pyscf(atoms)\n    pyscf_mol = pyscf.M(\n        atom=pyscf_atoms,\n        basis=self.basis,\n        symmetry=self.symmetry,\n    )\n\n    self.mf = pyscf.dft.RKS(pyscf_mol)\n    self.mf.xc = self.xc\n\n    self.mf.kernel(verbose=0, dm0=self.dm1)\n    self.dm1 = (\n        self.mf.make_rdm1()\n    )  # try to reuse density matrix for next calculation\n\n    self.mf.analyze(verbose=0)\n    _, charges = self.mf.mulliken_pop(verbose=0)\n\n    self.results = {\"energy\": self.mf.energy_tot() * ase.units.Hartree}\n    self.results[\"forces\"] = (\n        -np.array(self.mf.Gradients().kernel()) * ase.units.Hartree / ase.units.Bohr\n    )\n    self.results[\"dipole\"] = (\n        self.mf.dip_moment(verbose=0, unit=\"atomic\") * ase.units.Bohr\n    )\n    self.results[\"charges\"] = np.array(charges)\n</code></pre>"},{"location":"reference/himatcal/calculator/pyscf_calculator.html#himatcal.calculator.pyscf_calculator.get_calculator","title":"get_calculator","text":"<pre><code>get_calculator(**kwargs) -&gt; PySCFCalculator\n</code></pre> <p>Function used by the AMS-ASE interface</p> Source code in <code>himatcal/calculator/pyscf_calculator.py</code> <pre><code>def get_calculator(**kwargs) -&gt; PySCFCalculator:\n    \"\"\"Function used by the AMS-ASE interface\"\"\"\n    from scm.amspipe import AMSExternalCapabilities\n\n    calc = PySCFCalculator(**kwargs)\n    calc.ams_capabilities = AMSExternalCapabilities()\n    calc.ams_capabilities.apply_implemented_properties(calc.implemented_properties)\n    return calc\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html","title":"aimnet2ase","text":"<p>https://github.com/isayevlab/AIMNet2/blob/main/aimnet2calc/aimnet2ase.py</p>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE","title":"AIMNet2ASE","text":"<pre><code>AIMNet2ASE(base_calc: AIMNet2Calculator | str = 'aimnet2', charge=0, mult=1)\n</code></pre> <p>               Bases: <code>Calculator</code></p> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def __init__(\n    self, base_calc: AIMNet2Calculator | str = \"aimnet2\", charge=0, mult=1\n):\n    super().__init__()\n    if isinstance(base_calc, str):\n        base_calc = AIMNet2Calculator(base_calc)\n    self.base_calc = base_calc\n    self.charge = charge\n    self.mult = mult\n    self.reset()\n    # list of implemented species\n    if hasattr(base_calc, \"implemented_species\"):\n        self.implemented_species = base_calc.implemented_species.cpu().numpy()\n    else:\n        self.implemented_species = None\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.base_calc","title":"base_calc  <code>instance-attribute</code>","text":"<pre><code>base_calc = base_calc\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.charge","title":"charge  <code>instance-attribute</code>","text":"<pre><code>charge = charge\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.implemented_properties","title":"implemented_properties  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>implemented_properties = ['energy', 'forces', 'free_energy', 'charges', 'stress']\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.implemented_species","title":"implemented_species  <code>instance-attribute</code>","text":"<pre><code>implemented_species = numpy()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.mult","title":"mult  <code>instance-attribute</code>","text":"<pre><code>mult = mult\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.calculate","title":"calculate","text":"<pre><code>calculate(atoms=None, properties=None, system_changes=all_changes)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def calculate(self, atoms=None, properties=None, system_changes=all_changes):\n    if properties is None:\n        properties = [\"energy\"]\n    super().calculate(atoms, properties, system_changes)\n    self.update_tensors()\n\n    if self.atoms.cell is not None and self.atoms.pbc.any():\n        # assert self.base_calc.cutoff_lr &lt; float('inf'), 'Long-range cutoff must be finite for PBC'\n        cell = self.atoms.cell.array\n    else:\n        cell = None\n\n    results = self.base_calc(\n        {\n            \"coord\": torch.tensor(\n                self.atoms.positions,\n                dtype=torch.float32,\n                device=self.base_calc.device,\n            ),\n            \"numbers\": self._t_numbers,\n            \"cell\": cell,\n            \"mol_idx\": self._t_mol_idx,\n            \"charge\": self._t_charge,\n            \"mult\": self._t_mult,\n        },\n        forces=\"forces\" in properties,\n        stress=\"stress\" in properties,\n    )\n    for k, v in results.items():\n        results[k] = v.detach().cpu().numpy()\n\n    self.results[\"energy\"] = results[\"energy\"][0]\n    self.results[\"charges\"] = results[\"charges\"]\n    if \"forces\" in properties:\n        self.results[\"forces\"] = results[\"forces\"]\n    if \"stress\" in properties:\n        self.results[\"stress\"] = results[\"stress\"]\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.reset","title":"reset","text":"<pre><code>reset()\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def reset(self):\n    super().reset()\n    self._t_numbers = None\n    self._t_charge = None\n    self._t_mult = None\n    self._t_mol_idx = None\n    self.charge = 0.0\n    self.mult = 1.0\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.set_atoms","title":"set_atoms","text":"<pre><code>set_atoms(atoms)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def set_atoms(self, atoms):\n    if (\n        self.implemented_species is not None\n        and not np.isin(atoms.numbers, self.implemented_species).all()\n    ):\n        raise ValueError(\n            \"Some species are not implemented in the AIMNet2Calculator\"\n        )\n    self.reset()\n    self.atoms = atoms\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.set_charge","title":"set_charge","text":"<pre><code>set_charge(charge)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def set_charge(self, charge):\n    self.charge = charge\n    self._t_charge = None\n    self.update_tensors()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.set_mult","title":"set_mult","text":"<pre><code>set_mult(mult)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def set_mult(self, mult):\n    self.mult = mult\n    self._t_mult = None\n    self.update_tensors()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2ase.html#himatcal.calculator.aimnet.aimnet2ase.AIMNet2ASE.update_tensors","title":"update_tensors","text":"<pre><code>update_tensors()\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2ase.py</code> <pre><code>def update_tensors(self):\n    if self._t_numbers is None:\n        self._t_numbers = torch.tensor(\n            self.atoms.numbers, dtype=torch.int64, device=self.base_calc.device\n        )\n    if self._t_charge is None:\n        self._t_charge = torch.tensor(\n            self.charge, dtype=torch.float32, device=self.base_calc.device\n        )\n    if self._t_mult is None:\n        self._t_mult = torch.tensor(\n            self.mult, dtype=torch.float32, device=self.base_calc.device\n        )\n    if self._t_mol_idx is None:\n        self.mol_idx = torch.zeros(\n            len(self.atoms), dtype=torch.int64, device=self.base_calc.device\n        )\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html","title":"aimnet2pysis","text":""},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.EV2AU","title":"EV2AU  <code>module-attribute</code>","text":"<pre><code>EV2AU = 1 / AU2EV\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis","title":"AIMNet2Pysis","text":"<pre><code>AIMNet2Pysis(model: Union[AIMNet2Calculator, str] = 'aimnet2', charge=0, mult=1, **kwargs)\n</code></pre> <p>               Bases: <code>Calculator</code></p> Source code in <code>himatcal/calculator/aimnet/aimnet2pysis.py</code> <pre><code>def __init__(\n    self,\n    model: Union[AIMNet2Calculator, str] = \"aimnet2\",\n    charge=0,\n    mult=1,\n    **kwargs,\n):\n    super().__init__(charge=charge, mult=mult, **kwargs)\n    if isinstance(model, str):\n        model = AIMNet2Calculator(model)\n    self.model = model\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis.implemented_properties","title":"implemented_properties  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>implemented_properties = ['energy', 'forces', 'free_energy', 'charges', 'stress']\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis.model","title":"model  <code>instance-attribute</code>","text":"<pre><code>model = model\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis.get_energy","title":"get_energy","text":"<pre><code>get_energy(atoms, coords)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2pysis.py</code> <pre><code>def get_energy(self, atoms, coords):\n    _in = self._prepere_input(atoms, coords)\n    res = self.model(_in)\n    energy = self._results_get_energy(res)\n    return dict(energy=energy)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis.get_forces","title":"get_forces","text":"<pre><code>get_forces(atoms, coords)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2pysis.py</code> <pre><code>def get_forces(self, atoms, coords):\n    _in = self._prepere_input(atoms, coords)\n    res = self.model(_in, forces=True)\n    energy = self._results_get_energy(res)\n    forces = self._results_get_forces(res)\n    return dict(energy=energy, forces=forces)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.AIMNet2Pysis.get_hessian","title":"get_hessian","text":"<pre><code>get_hessian(atoms, coords)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2pysis.py</code> <pre><code>def get_hessian(self, atoms, coords):\n    _in = self._prepere_input(atoms, coords)\n    res = self.model(_in, forces=True, hessian=True)\n    energy = self._results_get_energy(res)\n    forces = self._results_get_forces(res)\n    hessian = self._results_get_hessian(res)\n    return dict(energy=energy, forces=forces, hessian=hessian)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/aimnet2pysis.html#himatcal.calculator.aimnet.aimnet2pysis.run_pysis","title":"run_pysis","text":"<pre><code>run_pysis()\n</code></pre> Source code in <code>himatcal/calculator/aimnet/aimnet2pysis.py</code> <pre><code>def run_pysis():\n    from pysisyphus import run\n\n    run.CALC_DICT[\"aimnet\"] = AIMNet2Pysis\n    run.run()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html","title":"core","text":""},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator","title":"AIMNet2Calculator","text":"<pre><code>AIMNet2Calculator(model: str | Module = 'aimnet2')\n</code></pre> <p>Genegic AIMNet2 calculator A helper class to load AIMNet2 models and perform inference.</p> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def __init__(self, model: str | torch.nn.Module = \"aimnet2\"):\n    self.device = \"cuda\" if torch.cuda.is_available() else \"cpu\"\n    if isinstance(model, str):\n        p = get_model_path(model)\n        self.model = torch.jit.load(p, map_location=self.device)\n    elif isinstance(model, nn.Module):\n        self.model = model.to(self.device)\n    else:\n        raise AttributeError(\"Invalid model type/name.\")\n\n    self.cutoff = self.model.cutoff\n    self.lr = hasattr(self.model, \"cutoff_lr\")\n    self.cutoff_lr = getattr(self.model, \"cutoff_lr\", float(\"inf\"))\n\n    # indicator if input was flattened\n    self._batch = None\n    # placeholder for tensors that require grad\n    self._saved_for_grad = None\n    # set flag of current Coulomb model\n    coul_methods = {\n        getattr(mod, \"method\", None) for mod in iter_lrcoulomb_mods(self.model)\n    }\n    assert len(coul_methods) &lt;= 1, \"Multiple Coulomb modules found.\"\n    self._coulomb_method = coul_methods.pop() if len(coul_methods) else None\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.atom_feature_keys","title":"atom_feature_keys  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>atom_feature_keys = ['coord', 'numbers', 'charges', 'forces']\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.cutoff","title":"cutoff  <code>instance-attribute</code>","text":"<pre><code>cutoff = cutoff\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.cutoff_lr","title":"cutoff_lr  <code>instance-attribute</code>","text":"<pre><code>cutoff_lr = getattr(model, 'cutoff_lr', float('inf'))\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.device","title":"device  <code>instance-attribute</code>","text":"<pre><code>device = 'cuda' if is_available() else 'cpu'\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.keys_in","title":"keys_in  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>keys_in = {'coord': float, 'numbers': int, 'charge': float}\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.keys_in_optional","title":"keys_in_optional  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>keys_in_optional = {'mult': float, 'mol_idx': int, 'nbmat': int, 'nbmat_lr': int, 'nb_pad_mask': bool, 'nb_pad_mask_lr': bool, 'shifts': float, 'shifts_lr': float, 'cell': float}\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.keys_out","title":"keys_out  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>keys_out = ['energy', 'charges', 'forces', 'hessian', 'stress']\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.lr","title":"lr  <code>instance-attribute</code>","text":"<pre><code>lr = hasattr(model, 'cutoff_lr')\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.model","title":"model  <code>instance-attribute</code>","text":"<pre><code>model = load(p, map_location=device)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.__call__","title":"__call__","text":"<pre><code>__call__(*args, **kwargs)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def __call__(self, *args, **kwargs):\n    return self.eval(*args, **kwargs)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.calculate_hessian","title":"calculate_hessian  <code>staticmethod</code>","text":"<pre><code>calculate_hessian(forces, coord)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>@staticmethod\ndef calculate_hessian(forces, coord):\n    # here forces have shape (N, 3) and coord has shape (N+1, 3)\n    # return hessian with shape (N, 3, N, 3)\n    hessian = -torch.stack(\n        [\n            torch.autograd.grad(_f, coord, retain_graph=True)[0]\n            for _f in forces.flatten().unbind()\n        ]\n    ).view(-1, 3, coord.shape[0], 3)[:-1, :, :-1, :]\n    return hessian\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.eval","title":"eval","text":"<pre><code>eval(data: dict[str, Any], forces=False, stress=False, hessian=False) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def eval(\n    self, data: dict[str, Any], forces=False, stress=False, hessian=False\n) -&gt; dict[str, Tensor]:\n    data = self.prepare_input(data)\n    if hessian and data[\"mol_idx\"][-1] &gt; 0:\n        raise NotImplementedError(\n            \"Hessian calculation is not supported for multiple molecules\"\n        )\n    data = self.set_grad_tensors(\n        data, forces=forces, stress=stress, hessian=hessian\n    )\n    with torch.jit.optimized_execution(False):\n        data = self.model(data)\n    data = self.get_derivatives(data, forces=forces, stress=stress, hessian=hessian)\n    data = self.process_output(data)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.get_derivatives","title":"get_derivatives","text":"<pre><code>get_derivatives(data: dict[str, Tensor], forces=False, stress=False, hessian=False) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def get_derivatives(\n    self, data: dict[str, Tensor], forces=False, stress=False, hessian=False\n) -&gt; dict[str, Tensor]:\n    training = getattr(self.model, \"training\", False)\n    _create_graph = hessian or training\n    x = []\n    if hessian:\n        forces = True\n    if forces and (\n        \"forces\" not in data or (_create_graph and not data[\"forces\"].requires_grad)\n    ):\n        forces = True\n        x.append(self._saved_for_grad[\"coord\"])\n    if stress:\n        x.append(self._saved_for_grad[\"scaling\"])\n    if x:\n        tot_energy = data[\"energy\"].sum()\n        deriv = torch.autograd.grad(tot_energy, x, create_graph=_create_graph)\n        if forces:\n            data[\"forces\"] = -deriv[0]\n        if stress:\n            dedc = deriv[1] if forces else deriv[0]\n            data[\"stress\"] = dedc / data[\"cell\"].detach().det().abs()\n    if hessian:\n        data[\"hessian\"] = self.calculate_hessian(\n            data[\"forces\"], self._saved_for_grad[\"coord\"]\n        )\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.keep_only","title":"keep_only","text":"<pre><code>keep_only(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def keep_only(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    ret = {}\n    for k, v in data.items():\n        if k in self.keys_out or (k.endswith(\"_std\") and k[:-4] in self.keys_out):\n            ret[k] = v\n    return ret\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.make_nbmat","title":"make_nbmat","text":"<pre><code>make_nbmat(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def make_nbmat(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    if \"cell\" in data and data[\"cell\"] is not None:\n        assert data[\"cell\"].ndim == 2, \"Expected 2D tensor for cell\"\n        if \"nbmat\" not in data:\n            data[\"coord\"] = move_coord_to_cell(data[\"coord\"], data[\"cell\"])\n            mat_idxj, mat_pad, mat_S = nblists_torch_pbc(\n                data[\"coord\"], data[\"cell\"], self.cutoff\n            )\n            data[\"nbmat\"], data[\"nb_pad_mask\"], data[\"shifts\"] = (\n                mat_idxj,\n                mat_pad,\n                mat_S,\n            )\n            if self.lr:\n                if \"nbmat_lr\" not in data:\n                    assert (\n                        self.cutoff_lr &lt; torch.inf\n                    ), \"Long-range cutoff must be finite for PBC\"\n                    data[\"nbmat_lr\"], data[\"nb_pad_mask_lr\"], data[\"shifts_lr\"] = (\n                        nblists_torch_pbc(\n                            data[\"coord\"], data[\"cell\"], self.cutoff_lr\n                        )\n                    )\n                    data[\"cutoff_lr\"] = torch.tensor(\n                        self.cutoff_lr, device=self.device\n                    )\n    else:\n        if \"nbmat\" not in data:\n            data[\"nbmat\"] = nblist_torch_cluster(\n                data[\"coord\"], self.cutoff, data[\"mol_idx\"], max_nb=128\n            )\n            if self.lr:\n                if \"nbmat_lr\" not in data:\n                    data[\"nbmat_lr\"] = nblist_torch_cluster(\n                        data[\"coord\"], self.cutoff_lr, data[\"mol_idx\"], max_nb=1024\n                    )\n                data[\"cutoff_lr\"] = torch.tensor(self.cutoff_lr, device=self.device)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.mol_flatten","title":"mol_flatten","text":"<pre><code>mol_flatten(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def mol_flatten(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    assert data[\"coord\"].ndim in {2, 3}, \"Expected 2D or 3D tensor for coord\"\n    if data[\"coord\"].ndim == 3:\n        B, N = data[\"coord\"].shape[:2]\n        self._batch = B\n        data[\"mol_idx\"] = torch.repeat_interleave(\n            torch.arange(0, B, device=self.device),\n            torch.full((B,), N, device=self.device),\n        )\n        for k, v in data.items():\n            if k in self.atom_feature_keys:\n                assert (\n                    v.ndim &gt;= 2\n                ), f\"Expected at least 2D tensor for {k}, got {v.ndim}D\"\n                data[k] = v.flatten(0, 1)\n    else:\n        self._batch = None\n        if \"mol_idx\" not in data:\n            data[\"mol_idx\"] = torch.zeros(\n                data[\"coord\"].shape[0], device=self.device\n            )\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.mol_unflatten","title":"mol_unflatten","text":"<pre><code>mol_unflatten(data: dict[str, Tensor], batch=None) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def mol_unflatten(self, data: dict[str, Tensor], batch=None) -&gt; dict[str, Tensor]:\n    batch = batch or self._batch\n    if batch is not None:\n        for k, v in data.items():\n            if k in self.atom_feature_keys:\n                data[k] = v.view(self._batch, -1, *v.shape[1:])\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.pad_input","title":"pad_input","text":"<pre><code>pad_input(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def pad_input(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    N = data[\"nbmat\"].shape[0]\n    data[\"coord\"] = maybe_pad_dim0(data[\"coord\"], N)\n    data[\"numbers\"] = maybe_pad_dim0(data[\"numbers\"], N)\n    data[\"mol_idx\"] = maybe_pad_dim0(data[\"mol_idx\"], N, value=data[\"mol_idx\"][-1])\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.prepare_input","title":"prepare_input","text":"<pre><code>prepare_input(data: dict[str, Any]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def prepare_input(self, data: dict[str, Any]) -&gt; dict[str, Tensor]:\n    data = self.to_input_tensors(data)\n    data = self.mol_flatten(data)\n    if data.get(\"cell\") is not None:\n        if data[\"mol_idx\"][-1] &gt; 0:\n            raise NotImplementedError(\n                \"PBC with multiple molecules is not implemented yet.\"\n            )\n        if self._coulomb_method == \"simple\":\n            print(\"Switching to DSF Coulomb for PBC\")\n            self.set_lrcoulomb_method(\"dsf\")\n    data = self.make_nbmat(data)\n    data = self.pad_input(data)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.process_output","title":"process_output","text":"<pre><code>process_output(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def process_output(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    data = self.unpad_output(data)\n    data = self.mol_unflatten(data)\n    data = self.keep_only(data)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.set_grad_tensors","title":"set_grad_tensors","text":"<pre><code>set_grad_tensors(data: dict[str, Tensor], forces=False, stress=False, hessian=False) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def set_grad_tensors(\n    self, data: dict[str, Tensor], forces=False, stress=False, hessian=False\n) -&gt; dict[str, Tensor]:\n    self._saved_for_grad = {}\n    if forces or hessian:\n        data[\"coord\"].requires_grad_(True)\n        self._saved_for_grad[\"coord\"] = data[\"coord\"]\n    if stress:\n        assert \"cell\" in data, \"Stress calculation requires cell\"\n        scaling = torch.eye(\n            3,\n            requires_grad=True,\n            dtype=data[\"cell\"].dtype,\n            device=data[\"cell\"].device,\n        )\n        data[\"coord\"] = data[\"coord\"] @ scaling\n        data[\"cell\"] = data[\"cell\"] @ scaling\n        self._saved_for_grad[\"scaling\"] = scaling\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.set_lrcoulomb_method","title":"set_lrcoulomb_method","text":"<pre><code>set_lrcoulomb_method(method, cutoff=15.0, dsf_alpha=0.2)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def set_lrcoulomb_method(self, method, cutoff=15.0, dsf_alpha=0.2):\n    assert method in (\"simple\", \"dsf\", \"ewald\"), f\"Invalid method: {method}\"\n    if method == \"simple\":\n        for mod in iter_lrcoulomb_mods(self.model):\n            mod.method = \"simple\"\n            self.cutoff_lr = float(\"inf\")\n    elif method == \"dsf\":\n        for mod in iter_lrcoulomb_mods(self.model):\n            mod.method = \"dsf\"\n            self.cutoff_lr = cutoff\n            mod.dsf_alpha = dsf_alpha\n    elif method == \"ewald\":\n        for mod in iter_lrcoulomb_mods(self.model):\n            mod.method = \"ewald\"\n            self.cutoff_lr = cutoff\n    self._coulomb_method = method\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.to_input_tensors","title":"to_input_tensors","text":"<pre><code>to_input_tensors(data: dict[str, Any]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def to_input_tensors(self, data: dict[str, Any]) -&gt; dict[str, Tensor]:\n    ret = dict()\n    for k in self.keys_in:\n        assert k in data, f\"Missing key {k} in the input data\"\n        # always detach !!\n        ret[k] = torch.as_tensor(\n            data[k], device=self.device, dtype=self.keys_in[k]\n        ).detach()\n    for k in self.keys_in_optional:\n        if k in data and data[k] is not None:\n            ret[k] = torch.as_tensor(\n                data[k], device=self.device, dtype=self.keys_in_optional[k]\n            ).detach()\n    # convert any scalar tensors to shape (1,) tensors\n    for k, v in ret.items():\n        if v.ndim == 0:\n            ret[k] = v.unsqueeze(0)\n    return ret\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.AIMNet2Calculator.unpad_output","title":"unpad_output","text":"<pre><code>unpad_output(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def unpad_output(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    N = data[\"nbmat\"].shape[0] - 1\n    for k, v in data.items():\n        if k in self.atom_feature_keys:\n            data[k] = maybe_unpad_dim0(v, N)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.iter_lrcoulomb_mods","title":"iter_lrcoulomb_mods","text":"<pre><code>iter_lrcoulomb_mods(model)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def iter_lrcoulomb_mods(model):\n    for name, module in _named_children_rec(model):\n        if name == \"lrcoulomb\":\n            yield module\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.maybe_pad_dim0","title":"maybe_pad_dim0","text":"<pre><code>maybe_pad_dim0(a: Tensor, N: int, value=0.0) -&gt; Tensor\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def maybe_pad_dim0(a: Tensor, N: int, value=0.0) -&gt; Tensor:\n    _shape_diff = N - a.shape[0]\n    assert _shape_diff in [0, 1], \"Invalid shape\"\n    if _shape_diff == 1:\n        a = pad_dim0(a, value=value)\n    return a\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.maybe_unpad_dim0","title":"maybe_unpad_dim0","text":"<pre><code>maybe_unpad_dim0(a: Tensor, N: int) -&gt; Tensor\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def maybe_unpad_dim0(a: Tensor, N: int) -&gt; Tensor:\n    _shape_diff = a.shape[0] - N\n    assert _shape_diff in [0, 1], \"Invalid shape\"\n    if _shape_diff == 1:\n        a = a[:-1]\n    return a\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.move_coord_to_cell","title":"move_coord_to_cell","text":"<pre><code>move_coord_to_cell(coord, cell)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def move_coord_to_cell(coord, cell):\n    coord_f = coord @ cell.inverse()\n    coord_f = coord_f % 1\n    return coord_f @ cell\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/core.html#himatcal.calculator.aimnet.core.pad_dim0","title":"pad_dim0","text":"<pre><code>pad_dim0(a: Tensor, value=0.0) -&gt; Tensor\n</code></pre> Source code in <code>himatcal/calculator/aimnet/core.py</code> <pre><code>def pad_dim0(a: Tensor, value=0.0) -&gt; Tensor:\n    shapes = [0] * ((a.ndim - 1) * 2) + [0, 1]\n    a = torch.nn.functional.pad(a, shapes, mode=\"constant\", value=value)\n    return a\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html","title":"ensemble","text":""},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.args","title":"args  <code>module-attribute</code>","text":"<pre><code>args = parse_args()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.ens","title":"ens  <code>module-attribute</code>","text":"<pre><code>ens = EnsembledModel(models, out=out_keys, detach=detach)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.models","title":"models  <code>module-attribute</code>","text":"<pre><code>models = [load(m, map_location='cpu') for m in models]\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.parser","title":"parser  <code>module-attribute</code>","text":"<pre><code>parser = ArgumentParser()\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.EnsembledModel","title":"EnsembledModel","text":"<pre><code>EnsembledModel(models: List[Module], out=['energy', 'forces', 'charges'], detach=False)\n</code></pre> <p>               Bases: <code>Module</code></p> Source code in <code>himatcal/calculator/aimnet/ensemble.py</code> <pre><code>def __init__(\n    self, models: List[nn.Module], out=[\"energy\", \"forces\", \"charges\"], detach=False\n):\n    super().__init__()\n    self.models = nn.ModuleList(models)\n    self.out = out\n    self.detach = detach\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.EnsembledModel.detach","title":"detach  <code>instance-attribute</code>","text":"<pre><code>detach = detach\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.EnsembledModel.models","title":"models  <code>instance-attribute</code>","text":"<pre><code>models = ModuleList(models)\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.EnsembledModel.out","title":"out  <code>instance-attribute</code>","text":"<pre><code>out = out\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.EnsembledModel.forward","title":"forward","text":"<pre><code>forward(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/ensemble.py</code> <pre><code>def forward(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    res: List[dict[str, Tensor]] = []\n    for model in self.models:\n        _in = dict()\n        for k in data:\n            _in[k] = data[k]\n        _out = model(_in)\n        _r = dict()\n        for k in _out:\n            if k in self.out:\n                _r[k] = _out[k]\n                if self.detach:\n                    _r[k] = _r[k].detach()\n        res.append(_r)\n\n    for k in res[0]:\n        v = [x[k] for x in res]\n        vv = torch.stack(v, dim=0)\n        data[k] = vv.mean(dim=0)\n        data[f\"{k}_std\"] = vv.std(dim=0)\n\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces","title":"Forces","text":"<pre><code>Forces(module: Module, x: str = 'coord', y: str = 'energy', key_out: str = 'forces', detach: bool = True)\n</code></pre> <p>               Bases: <code>Module</code></p> <p>Compute forces from energy using autograd.</p> Source code in <code>himatcal/calculator/aimnet/ensemble.py</code> <pre><code>def __init__(\n    self,\n    module: nn.Module,\n    x: str = \"coord\",\n    y: str = \"energy\",\n    key_out: str = \"forces\",\n    detach: bool = True,\n):\n    super().__init__()\n    self.add_module(\"module\", module)\n    self.x = x\n    self.y = y\n    self.key_out = key_out\n    self.detach = detach\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces.detach","title":"detach  <code>instance-attribute</code>","text":"<pre><code>detach = detach\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces.key_out","title":"key_out  <code>instance-attribute</code>","text":"<pre><code>key_out = key_out\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces.x","title":"x  <code>instance-attribute</code>","text":"<pre><code>x = x\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces.y","title":"y  <code>instance-attribute</code>","text":"<pre><code>y = y\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/ensemble.html#himatcal.calculator.aimnet.ensemble.Forces.forward","title":"forward","text":"<pre><code>forward(data: dict[str, Tensor]) -&gt; dict[str, Tensor]\n</code></pre> Source code in <code>himatcal/calculator/aimnet/ensemble.py</code> <pre><code>def forward(self, data: dict[str, Tensor]) -&gt; dict[str, Tensor]:\n    prev = torch.is_grad_enabled()\n    torch.set_grad_enabled(True)\n    data[self.x].requires_grad_(True)\n    data = self.module(data)\n    y = data[self.y]\n    create_graph = self.training or not self.detach\n    g = torch.autograd.grad([y.sum()], [data[self.x]], create_graph=create_graph)[0]\n    assert g is not None\n    data[self.key_out] = -g\n    torch.set_grad_enabled(prev)\n    return data\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/models.html","title":"models","text":""},{"location":"reference/himatcal/calculator/aimnet/models.html#himatcal.calculator.aimnet.models.model_registry_aliases","title":"model_registry_aliases  <code>module-attribute</code>","text":"<pre><code>model_registry_aliases = {}\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/models.html#himatcal.calculator.aimnet.models.get_model_path","title":"get_model_path","text":"<pre><code>get_model_path(s: str)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/models.py</code> <pre><code>def get_model_path(s: str):\n    # direct file path\n    if os.path.isfile(s):\n        print(\"Found model file:\", s)\n        return s\n    # check aliases\n    if s in model_registry_aliases:\n        s = model_registry_aliases[s]\n    # add jpt extension\n    if not s.endswith(\".jpt\"):\n        s = s + \".jpt\"\n    sdir = os.path.dirname(s)\n    os.makedirs(os.path.join(os.path.dirname(__file__), \"assets\", sdir), exist_ok=True)\n    s_local = os.path.join(os.path.dirname(__file__), \"assets\", s)\n    if os.path.isfile(s_local):\n        print(\"Found model file:\", s_local)\n    else:\n        url = f\"https://github.com/zubatyuk/aimnet-model-zoo/raw/main/{s}\"\n        print(\"Downloading model file from\", url)\n        r = requests.get(url)\n        r.raise_for_status()\n        with open(s_local, \"wb\") as f:\n            f.write(r.content)\n        print(\"Saved to \", s_local)\n    return s_local\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/nblist.html","title":"nblist","text":""},{"location":"reference/himatcal/calculator/aimnet/nblist.html#himatcal.calculator.aimnet.nblist.nblist_torch_cluster","title":"nblist_torch_cluster","text":"<pre><code>nblist_torch_cluster(coord: Tensor, cutoff: float, mol_idx: Tensor | None = None, max_nb: int = 256)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/nblist.py</code> <pre><code>def nblist_torch_cluster(\n    coord: Tensor, cutoff: float, mol_idx: Tensor | None = None, max_nb: int = 256\n):\n    device = coord.device\n    assert coord.ndim == 2, \"Expected 2D tensor for coord, got {coord.ndim}D\"\n    assert coord.shape[0] &lt; 2147483646, \"Too many atoms, max supported is 2147483646\"\n    max_num_neighbors = max_nb\n    while True:\n        sparse_nb = radius_graph(\n            coord, batch=mol_idx, r=cutoff, max_num_neighbors=max_nb\n        ).to(torch.int32)\n        nnb = torch.unique(sparse_nb[0], return_counts=True)[1]\n        if nnb.numel() == 0:\n            break\n        max_num_neighbors = nnb.max().item()\n        if max_num_neighbors &lt; max_nb:\n            break\n        max_nb *= 2\n    sparse_nb_half = sparse_nb[:, sparse_nb[0] &gt; sparse_nb[1]]\n    dense_nb = sparse_nb_to_dense_half(\n        sparse_nb_half.mT.cpu().numpy(), coord.shape[0], max_num_neighbors\n    )\n    dense_nb = torch.as_tensor(dense_nb, device=device)\n    return dense_nb\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/nblist.html#himatcal.calculator.aimnet.nblist.nblists_torch_pbc","title":"nblists_torch_pbc","text":"<pre><code>nblists_torch_pbc(coord: Tensor, cell: Tensor, cutoff: float) -&gt; tuple[Tensor, Tensor, Tensor]\n</code></pre> <p>Compute dense neighbor lists for periodic boundary conditions case. Coordinates must be in cartesian coordinates and be within the unit cell. Single crystal only, no support for batched coord or multiple unit cells.</p> Source code in <code>himatcal/calculator/aimnet/nblist.py</code> <pre><code>def nblists_torch_pbc(\n    coord: Tensor, cell: Tensor, cutoff: float\n) -&gt; tuple[Tensor, Tensor, Tensor]:\n    \"\"\"Compute dense neighbor lists for periodic boundary conditions case.\n    Coordinates must be in cartesian coordinates and be within the unit cell.\n    Single crystal only, no support for batched coord or multiple unit cells.\n    \"\"\"\n    assert coord.ndim == 2, \"Expected 2D tensor for coord, got {coord.ndim}D\"\n    # non-PBC version\n    device = coord.device\n\n    reciprocal_cell = cell.inverse().t()\n    inv_distances = reciprocal_cell.norm(2, -1)\n    shifts = _calc_shifts(inv_distances, cutoff)\n    d = torch.cdist(\n        coord.unsqueeze(0), coord.unsqueeze(0) + (shifts @ cell).unsqueeze(1)\n    )\n    conn_mat = ((d &lt; cutoff) &amp; (d &gt; 0.1)).transpose(0, 1).contiguous()\n    if device.type == \"cuda\" and _numba_cuda_available:\n        _fn = _nblist_pbc_cuda\n    else:\n        _fn = _nblist_pbc_cpu\n    mat_idxj, mat_pad, mat_S = _fn(conn_mat, shifts)\n    return mat_idxj, mat_pad, mat_S\n</code></pre>"},{"location":"reference/himatcal/calculator/aimnet/nblist.html#himatcal.calculator.aimnet.nblist.sparse_nb_to_dense_half","title":"sparse_nb_to_dense_half","text":"<pre><code>sparse_nb_to_dense_half(idx, natom, max_nb)\n</code></pre> Source code in <code>himatcal/calculator/aimnet/nblist.py</code> <pre><code>@numba.njit(cache=True)\ndef sparse_nb_to_dense_half(idx, natom, max_nb):\n    dense_nb = np.full((natom + 1, max_nb), natom, dtype=np.int32)\n    last_idx = np.zeros((natom,), dtype=np.int32)\n    for k in range(idx.shape[0]):\n        i, j = idx[k]\n        il, jl = last_idx[i], last_idx[j]\n        dense_nb[i, il] = j\n        dense_nb[j, jl] = i\n        last_idx[i] += 1\n        last_idx[j] += 1\n    return dense_nb\n</code></pre>"},{"location":"reference/himatcal/recipes/crest/_base.html","title":"_base","text":"<p>crest recipes</p>"},{"location":"reference/himatcal/recipes/crest/_base.html#himatcal.recipes.crest._base.write_general_input","title":"write_general_input","text":"<pre><code>write_general_input(input_type: str = 'struc.xyz', runtype: Literal['none', 'ancopt', 'optimize', 'ancopt_ensemble', 'optimize_ensemble', 'md', 'mtd', 'dynamics', 'metadynamics', 'mecp', 'mecp_search'] = 'none', threads: int = 4, preopt: bool = False, topo: bool = 'False')\n</code></pre> Source code in <code>himatcal/recipes/crest/_base.py</code> <pre><code>def write_general_input(\n    input_type: str = \"struc.xyz\",\n    runtype: Literal[\n        \"none\",\n        \"ancopt\",\n        \"optimize\",\n        \"ancopt_ensemble\",\n        \"optimize_ensemble\",\n        \"md\",\n        \"mtd\",\n        \"dynamics\",\n        \"metadynamics\",\n        \"mecp\",\n        \"mecp_search\",\n    ] = \"none\",\n    threads: int = 4,\n    preopt: bool = False,\n    topo: bool = \"False\",\n):\n    with Path.open(Path(\"input.toml\"),\"w\") as f:\n        toml.dump(\n            {\n                \"input\": input_type,\n                \"runtype\": runtype,\n                \"threads\": threads,\n                \"preopt\": preopt,\n                \"topo\": topo,\n                \"calculation\":{\n                    \"type\" : \"mecp\",\n                    \"hess_update\": \"bfgs\",\n                    \"level\":{\n                        \"method\":\"xtb\",\n                    }\n                }\n            },\n            f,\n        )\n</code></pre>"},{"location":"reference/himatcal/recipes/crest/core.html","title":"core","text":"<p>core recipes for crest calculations</p>"},{"location":"reference/himatcal/recipes/crest/core.html#himatcal.recipes.crest.core.logger","title":"logger  <code>module-attribute</code>","text":"<pre><code>logger = getLogger(__name__)\n</code></pre>"},{"location":"reference/himatcal/recipes/crest/core.html#himatcal.recipes.crest.core.iMTD_GC","title":"iMTD_GC","text":"<pre><code>iMTD_GC(atoms: Atoms, chg: int = 0, mult: int = 1, gfn_level: Literal['gfn1', 'gfn2', 'gfnff', 'gfn2//gfnff'] = 'gfn2', alpb: str | None = None, topo_change: bool = False, threads: int = 16)\n</code></pre> Source code in <code>himatcal/recipes/crest/core.py</code> <pre><code>def iMTD_GC(\n    atoms: Atoms,\n    chg: int = 0,\n    mult: int = 1,\n    gfn_level: Literal[\"gfn1\", \"gfn2\", \"gfnff\", \"gfn2//gfnff\"] = \"gfn2\",\n    alpb: str | None = None,\n    topo_change: bool = False,\n    threads: int = 16,\n):\n    scratch_folder = Path(f\"crest_opt_{datetime.now(timezone.utc).strftime('%Y-%m-%d-%H-%M-%S-%f')}\")\n    Path.mkdir(scratch_folder)\n    with cd(scratch_folder):\n        atoms_name = \"input.xyz\"\n        write(atoms_name, atoms)\n        uhf = mult - 1\n        protonate_cmd = f\"{SETTINGS.CREST_EXE_PATH_V3} {atoms_name} --{gfn_level} -chrg {chg} -uhf {uhf} --T {threads}\"\n        if alpb:\n            protonate_cmd += f\" -alpb {alpb}\"\n        if topo_change:\n            protonate_cmd += \" --noreftopo\"\n        with Path.open(Path(\"crest_opt.sh\"), \"w\") as f:\n            f.write(f\"#!/bin/bash\\n{protonate_cmd}\")\n        log_file_path = Path(\"crest_opt.log\")\n        with log_file_path.open(\"w\") as log_file:\n            subprocess.run(\n                [\"bash\", \"crest_opt.sh\"],\n                stdout=log_file,\n                stderr=subprocess.STDOUT,\n                check=True,\n            )\n        try:\n            return read(\"crest_best.xyz\")\n        except FileNotFoundError:\n            logger.error(\n                \"The computation did not finish successfully, please check the log file.\"\n            )\n            return None\n</code></pre>"},{"location":"reference/himatcal/recipes/crest/core.html#himatcal.recipes.crest.core.protonate","title":"protonate","text":"<pre><code>protonate(atoms: Atoms, ion: str = 'li+', chg: int = 0, mult: int = 1, gfn_level: Literal['gfn1', 'gfn2', 'gfnff', 'gfn2//gfnff'] = 'gfn2', alpb: str | None = None, threads: int = 16)\n</code></pre> <p>Protonate a structure using CREST, default is to protonate with Li</p> Source code in <code>himatcal/recipes/crest/core.py</code> <pre><code>def protonate(\n    atoms: Atoms,\n    ion: str = \"li+\",\n    chg: int = 0,\n    mult: int = 1,\n    gfn_level: Literal[\"gfn1\", \"gfn2\", \"gfnff\", \"gfn2//gfnff\"] = \"gfn2\",\n    alpb: str | None = None,\n    threads: int = 16,\n):\n    \"\"\"\n    Protonate a structure using CREST, default is to protonate with Li\n    \"\"\"\n    scratch_folder = Path(f\"crest_opt_{datetime.now(timezone.utc).strftime('%Y-%m-%d-%H-%M-%S-%f')}\")\n    Path.mkdir(scratch_folder)\n    with cd(scratch_folder):\n        atoms_name = \"input.xyz\"\n        write(atoms_name, atoms)\n        uhf = mult - 1\n        protonate_cmd = f\"{SETTINGS.CREST_EXE_PATH_V3} {atoms_name} --protonate --swel {ion} --{gfn_level} -chrg {chg} -uhf {uhf} --T {threads}\"\n        if alpb:\n            protonate_cmd += f\" -alpb {alpb}\"\n        with Path.open(Path(\"crest_opt.sh\"), \"w\") as f:\n            f.write(f\"#!/bin/bash\\n{protonate_cmd}\")\n        log_file_path = Path(\"crest_opt.log\")\n        with log_file_path.open(\"w\") as log_file:\n            subprocess.run(\n                [\"bash\", \"crest_opt.sh\"],\n                stdout=log_file,\n                stderr=subprocess.STDOUT,\n                check=True,\n            )\n        try:\n            return read(\"protonated.xyz\", index=0)\n        except FileNotFoundError:\n            logger.error(\n                \"The protonation did not complete successfully, please check the log file.\"\n            )\n            return None\n</code></pre>"},{"location":"reference/himatcal/recipes/crest/core.html#himatcal.recipes.crest.core.relax","title":"relax","text":"<pre><code>relax(atoms: Atoms, chg: int = 0, mult: int = 1, gfn_level: Literal['gfn1', 'gfn2', 'gfnff', 'gfn2//gfnff'] = 'gfn2', alpb: str | None = None, threads: int = 16)\n</code></pre> <p>Relax a molecular system using the CREST optimization program.</p> <p>Args:     atoms: The molecular system to relax.     chg: The charge of the system.     mult: The multiplicity of the system.     gfn_level: The level of the GFN method to use (default is \"gfn2\").     alpb: The solvent model to use (default is \"acetone\").     threads: The number of threads to use for optimization (default is 4).</p> <p>Returns:     The relaxed molecular system.</p> <p>Raises:     FileNotFoundError: If the output file \"crestopt.xyz\" is not found after optimization.</p> Source code in <code>himatcal/recipes/crest/core.py</code> <pre><code>def relax(\n    atoms: Atoms,\n    chg: int = 0,\n    mult: int = 1,\n    gfn_level: Literal[\"gfn1\", \"gfn2\", \"gfnff\", \"gfn2//gfnff\"] = \"gfn2\",\n    alpb: str | None = None,\n    threads: int = 16,\n):\n    \"\"\"\n    Relax a molecular system using the CREST optimization program.\n\n    Args:\n        atoms: The molecular system to relax.\n        chg: The charge of the system.\n        mult: The multiplicity of the system.\n        gfn_level: The level of the GFN method to use (default is \"gfn2\").\n        alpb: The solvent model to use (default is \"acetone\").\n        threads: The number of threads to use for optimization (default is 4).\n\n    Returns:\n        The relaxed molecular system.\n\n    Raises:\n        FileNotFoundError: If the output file \"crestopt.xyz\" is not found after optimization.\n    \"\"\"\n    scratch_folder = Path(f\"crest_opt_{datetime.now(timezone.utc).strftime('%Y-%m-%d-%H-%M-%S-%f')}\")\n    Path.mkdir(scratch_folder)\n    with cd(scratch_folder):\n        atoms_name = \"input.xyz\"\n        write(atoms_name, atoms)\n        uhf = mult - 1\n        protonate_cmd = f\"{SETTINGS.CREST_EXE_PATH_V3} {atoms_name} --opt --{gfn_level} -chrg {chg} -uhf {uhf} --T {threads}\"\n        if alpb:\n            protonate_cmd += f\" -alpb {alpb}\"\n        with Path.open(Path(\"crest_opt.sh\"), \"w\") as f:\n            f.write(f\"#!/bin/bash\\n{protonate_cmd}\")\n        log_file_path = Path(\"crest_opt.log\")\n        with log_file_path.open(\"w\") as log_file:\n            subprocess.run(\n                [\"bash\", \"crest_opt.sh\"],\n                stdout=log_file,\n                stderr=subprocess.STDOUT,\n                check=True,\n            )\n        try:\n            return read(\"crestopt.xyz\")\n        except FileNotFoundError:\n            logger.error(\n                \"The relaxation did not complete successfully, please check the log file.\"\n            )\n            return None\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential","title":"RedoxPotential","text":"<pre><code>RedoxPotential(neutral_molecule: Atoms | None = None, charged_molecule: Atoms | None = None, chg_mult: list[int] | None = None, calc_type: Literal['ox', 're'] = 'ox', calc_kwards: dict | None = None)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/core.py</code> <pre><code>def __init__(\n    self,\n    neutral_molecule: Atoms | None = None,\n    charged_molecule: Atoms | None = None,\n    chg_mult: list[int]\n    | None = None,  # * default for oxdiation potential calculation, for reduction, set [1, 1, 0, 2]\n    calc_type: Literal[\"ox\", \"re\"] = \"ox\",\n    calc_kwards: dict | None = None,\n):\n    if calc_kwards is None:\n        calc_kwards = {\n            \"opt_xc\": \"b3lyp\",\n            \"opt_basis\": \"6-31G* em=GD3BJ\",\n            \"gas_xc\": \"b3lyp\",\n            \"gas_basis\": \"6-311+G**\",\n            \"sol_xc\": \"m062x\",\n            \"sol_basis\": \"6-31G*\", # only for solvent gibbs free energy correction\n            \"solvent\": \"Acetone\",\n        }\n    if chg_mult is None:\n        chg_mult = [-1, 1, 0, 2]\n    self.neutral_molecule = neutral_molecule\n    self.charged_molecule = charged_molecule\n    self.chg_mult = chg_mult\n    self.calc_type = calc_type\n    self.calc_kwards = calc_kwards\n    # Ensure 'gas_xc' and 'gas_basis' keys exist\n    self.calc_kwards.setdefault(\"gas_xc\", \"m062x\")\n    self.calc_kwards.setdefault(\"gas_basis\", \"6-311G**\")\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.calc_kwards","title":"calc_kwards  <code>instance-attribute</code>","text":"<pre><code>calc_kwards = calc_kwards\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.calc_type","title":"calc_type  <code>instance-attribute</code>","text":"<pre><code>calc_type = calc_type\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.charged_molecule","title":"charged_molecule  <code>instance-attribute</code>","text":"<pre><code>charged_molecule = charged_molecule\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.chg_mult","title":"chg_mult  <code>instance-attribute</code>","text":"<pre><code>chg_mult = chg_mult\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.neutral_molecule","title":"neutral_molecule  <code>instance-attribute</code>","text":"<pre><code>neutral_molecule = neutral_molecule\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.cal_cycle","title":"cal_cycle","text":"<pre><code>cal_cycle()\n</code></pre> <p>calculate the potential from neutral and charged molecule, return the potential, the unit is eV real_potential = potential - 1.44 eV</p> Source code in <code>himatcal/recipes/electrolyte/core.py</code> <pre><code>def cal_cycle(self):\n    \"\"\"\n    calculate the potential from neutral and charged molecule, return the potential, the unit is eV\n    real_potential = potential - 1.44 eV\n    \"\"\"\n    neutral_gas_gibbs, neutral_gas_spe = self.cal_energy(\n        chg_status=\"neutral\", phase_status=\"gas\"\n    )\n    charged_gas_gibbs, charged_gas_spe = self.cal_energy(\n        chg_status=\"charged\", phase_status=\"gas\"\n    )\n    neutral_solvent_gibbs, neutral_solvent_spe = self.cal_energy(\n        chg_status=\"neutral\", phase_status=\"solvent\"\n    )\n    charged_solvent_gibbs, charged_solvent_spe = self.cal_energy(\n        chg_status=\"charged\", phase_status=\"solvent\"\n    )\n\n    # * \\delta G_{gas} = G_{charged}^{gas} - G_{neutral}^{gas}\n    delta_G_gas = charged_gas_gibbs - neutral_gas_gibbs\n\n    # * \\delta G_{solvention}(neutral) = E_{neutral}^{solvent} - E_{neutral}^{gas}\n    # * \\delta G_{solvention}(charged) = E_{charged}^{solvent} - E_{charged}^{gas}\n    delta_G_solvention_neutral = neutral_solvent_spe - neutral_gas_spe\n    delta_G_solvention_charged = charged_solvent_spe - charged_gas_spe\n\n    if self.calc_type == \"ox\":\n        potential = (\n            delta_G_gas - delta_G_solvention_neutral + delta_G_solvention_charged\n        )\n    if self.calc_type == \"re\":\n        potential = -(\n            delta_G_gas - delta_G_solvention_neutral + delta_G_solvention_charged\n        )\n    return potential - 1.44\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.cal_energy","title":"cal_energy","text":"<pre><code>cal_energy(chg_status: Literal['neutral', 'charged'], phase_status: Literal['gas', 'solvent'])\n</code></pre> <p>Calculates the Gibbs free energy and single point energy of a molecular system.</p> <p>This function determines the energy of a molecule based on its charge and phase status, performing necessary calculations to obtain the Gibbs free energy and single point energy. It adjusts the molecule's properties according to the specified charge and phase, and logs the results.</p> <p>Args:     chg_status: A string indicating the charge status of the molecule, either \"neutral\" or \"charged\".     phase_status: A string indicating the phase of the molecule, either \"gas\" or \"solvent\".</p> <p>Returns:     tuple: A tuple containing the Gibbs free energy and single point energy in eV.</p> Source code in <code>himatcal/recipes/electrolyte/core.py</code> <pre><code>def cal_energy(\n    self,\n    chg_status: Literal[\"neutral\", \"charged\"],\n    phase_status: Literal[\"gas\", \"solvent\"],\n):\n    \"\"\"\n    Calculates the Gibbs free energy and single point energy of a molecular system.\n\n    This function determines the energy of a molecule based on its charge and phase status, performing necessary calculations to obtain the Gibbs free energy and single point energy. It adjusts the molecule's properties according to the specified charge and phase, and logs the results.\n\n    Args:\n        chg_status: A string indicating the charge status of the molecule, either \"neutral\" or \"charged\".\n        phase_status: A string indicating the phase of the molecule, either \"gas\" or \"solvent\".\n\n    Returns:\n        tuple: A tuple containing the Gibbs free energy and single point energy in eV.\n\n    \"\"\"\n\n    if chg_status == \"neutral\":\n        self.molecule = self.neutral_molecule.copy()\n        self.chg = self.chg_mult[0]\n        self.mult = self.chg_mult[1]\n    elif chg_status == \"charged\":\n        self.molecule = self.charged_molecule.copy()\n        self.chg = self.chg_mult[2]\n        self.mult = self.chg_mult[3]\n    if phase_status == \"solvent\":\n        kwargs = {\n            \"xc\": self.calc_kwards[\"sol_xc\"],\n            \"basis\": self.calc_kwards[\"sol_basis\"],\n            \"scrf\": [\"SMD\", f\"solvent={self.calc_kwards['solvent']}\"],\n        }\n    elif phase_status == \"gas\":\n        kwargs = {\n            \"xc\": self.calc_kwards[\"gas_xc\"],\n            \"basis\": self.calc_kwards[\"gas_basis\"],\n        }\n    # * 1. relax the molecule in low level of theory\n    opt_kwargs = {\n        \"xc\": self.calc_kwards[\"opt_xc\"],\n        \"basis\": self.calc_kwards[\"opt_basis\"],\n    }\n    relax_results, relax_cclib_results = self.relax_llot(\n        chg=self.chg, mult=self.mult, kwargs=opt_kwargs\n    )\n    self.molecule = relax_results[\"atoms\"]\n    # * 2.calculate the single point energy from low level of theory to get the Gibbs free energy\n    sp_results, sp_cclib_results = self.sp_hlot(\n        chg=self.chg, mult=self.mult, kwargs=kwargs\n    )\n\n    # * 3.calculate the single point energy at solvation level to get the spe energy\n\n    Gibbs_energy = (\n        sp_cclib_results.scfenergies[0]\n        + relax_cclib_results.freeenergy * 27.211\n        - relax_cclib_results.scfenergies[0]\n    )\n    SPE_energy = sp_cclib_results.scfenergies[0]\n    logging.info(\n        f\"{chg_status} molecule in {phase_status} phase Gibbs free energy: {Gibbs_energy} eV, Single point energy: {SPE_energy} eV\"\n    )\n    return Gibbs_energy, SPE_energy\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.relax_llot","title":"relax_llot","text":"<pre><code>relax_llot(chg: int, mult: int, kwargs: dict | None = None)\n</code></pre> <p>low level of theory calculation for neutral and charged molecule, using for structure optimization and gibbs free energy correction if using in solvent, please pass {\"scrf\": [\"SMD\", f\"solvent={self.calc_kwards[\"solvent\"}\"]}  to kwargs</p> Source code in <code>himatcal/recipes/electrolyte/core.py</code> <pre><code>def relax_llot(self, chg: int, mult: int, kwargs: dict | None = None):\n    # sourcery skip: class-extract-method\n    \"\"\"\n    low level of theory calculation for neutral and charged molecule, using for structure optimization and gibbs free energy correction\n    if using in solvent, please pass {\"scrf\": [\"SMD\", f\"solvent={self.calc_kwards[\"solvent\"}\"]}  to kwargs\n    \"\"\"\n    if kwargs is None:\n        kwargs = {}\n    calc_keywords = {\n        \"label\": \"relax_llot\",\n        \"mem\": \"64GB\",\n        \"chk\": \"Gaussian.chk\",\n        \"nprocshared\": 64,\n        \"xc\": \"b3lyp\",\n        \"basis\": \"6-31G* em=GD3BJ\",\n        \"opt\": \"\",\n        \"scf\": [\"maxcycle=250\", \"xqc\"],\n        \"integral\": \"ultrafine\",\n        \"nosymmetry\": \"\",\n        \"pop\": \"CM5\",\n        \"ioplist\": [\"2/9=2000\"],\n    } | kwargs\n    logging.info(f\"Relaxing {chg} charge molecule in low level of theory\")\n    quacc_results = relax_job(\n        self.molecule,\n        charge=chg,\n        spin_multiplicity=mult,\n        freq=True,\n        **calc_keywords,\n    )\n    cclib_results = cclib_result(Path(quacc_results[\"dir_name\"]))\n    logging.info(f\"Relaxation of {chg} charge molecule in low level of theory done\")\n    return (quacc_results, cclib_results)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/core.html#himatcal.recipes.electrolyte.core.RedoxPotential.sp_hlot","title":"sp_hlot","text":"<pre><code>sp_hlot(chg: int, mult: int, kwargs: dict)\n</code></pre> <p>high level of theory single point energy calculation for neutral and charged molecule, using for gibbs the base of free energy if using in solvent, please pass {\"scrf\": [\"SMD\", f\"solvent={self.calc_kwards[\"solvent\"}\"]}  to kwargs</p> Source code in <code>himatcal/recipes/electrolyte/core.py</code> <pre><code>def sp_hlot(self, chg: int, mult: int, kwargs: dict):\n    \"\"\"\n    high level of theory single point energy calculation for neutral and charged molecule, using for gibbs the base of free energy\n    if using in solvent, please pass {\"scrf\": [\"SMD\", f\"solvent={self.calc_kwards[\"solvent\"}\"]}  to kwargs\n    \"\"\"\n    calc_keywords = {\n        \"label\": \"sp_hlot\",\n        \"mem\": \"64GB\",\n        \"chk\": \"Gaussian.chk\",\n        \"nprocshared\": 64,\n        \"xc\": \"m062x\",\n        \"basis\": \"6-311G**\",\n        \"scf\": [\"maxcycle=250\", \"xqc\"],\n        \"integral\": \"ultrafine\",\n        \"nosymmetry\": \"\",\n        \"pop\": \"CM5\",\n        \"ioplist\": [\"2/9=2000\"],\n    } | kwargs\n    logging.info(\n        f\"Calculating single point energy for {chg} charge molecule in high level of theory\"\n    )\n    quacc_results = static_job(\n        self.molecule, charge=chg, spin_multiplicity=mult, **calc_keywords\n    )\n    cclib_results = cclib_result(Path(quacc_results[\"dir_name\"]))\n    logging.info(\n        f\"Single point energy calculation for {chg} charge molecule in high level of theory done\"\n    )\n    return (quacc_results, cclib_results)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/reaction.html","title":"reaction","text":"<p>reaction calculations</p>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html","title":"redox","text":""},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal","title":"RedoxCal","text":"<p>               Bases: <code>BaseModel</code></p> <p>A class to calculate the oxidation and reduction potentials of a molecular system.</p> <p>This class provides methods to compute the oxidation and reduction potentials based on the molecular structure and specified ions. It allows for the inclusion of ions and various calculation parameters to tailor the analysis.</p> <p>Attributes:     molecule (Atoms | None): The molecular structure for the calculations.     chg_mult (list[int] | None): Charge multiplicities for the calculations.     add_ion (bool): Indicates whether to include an anion in the system.     ions (list[Atoms | str] | None): Ions involved in the calculations.     label (str): A label for the calculations.     calc_kwards (dict | None): Keyword arguments for calculation methods.     machine_kwards (dict | None): Machine-specific keyword arguments.</p> <p>Methods:     get_ox(): Calculates the oxidation potential of the molecular system.     get_re(): Calculates the reduction potential of the molecular system.     get_redox(): Retrieves both oxidation and reduction potentials.</p>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.add_ion","title":"add_ion  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>add_ion: bool = Field(True, description='Indicates whether to include an ion in the system.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.calc_kwards","title":"calc_kwards  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>calc_kwards: dict = Field(default_factory=lambda: {'opt_xc': 'b3lyp', 'opt_basis': '6-311+G(d,p)', 'sol_xc': 'm062x', 'sol_basis': '6-31G*', 'solvent': 'Acetone'}, description='Keyword arguments for calculation methods.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.charged_molecule","title":"charged_molecule  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>charged_molecule: Atoms | None = None\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.chg_mult","title":"chg_mult  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>chg_mult: list[int] = Field(default_factory=lambda: [-1, 1, 0, 2, 1, 1, 0, 2], description='Charge multiplicities for the calculations.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.ions","title":"ions  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>ions: list[Atoms | str] = Field(default_factory=lambda: [PF6, 'Li'], description='Ions involved in the calculations.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.label","title":"label  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>label: str = Field('redox', description='A label for the calculations.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.machine_kwards","title":"machine_kwards  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>machine_kwards: dict = Field(default_factory=lambda: {'xtb_proc': 16}, description='keyword arguments for Machine-specific.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.molecule","title":"molecule  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>molecule: Atoms | None = Field(None, description='The molecular structure for the calculations.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.neutral_molecule","title":"neutral_molecule  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>neutral_molecule: Atoms | None = None\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.protonate_ion_string","title":"protonate_ion_string  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>protonate_ion_string: bool = Field(True, description='Indicates whether to protonate the ion.')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.Config","title":"Config","text":""},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.Config.arbitrary_types_allowed","title":"arbitrary_types_allowed  <code>class-attribute</code> <code>instance-attribute</code>","text":"<pre><code>arbitrary_types_allowed = True\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.cal_ox","title":"cal_ox","text":"<pre><code>cal_ox()\n</code></pre> <p>Calculates the oxidation potential of a molecular system.</p> <p>This function generates the neutral and charged molecules required for calculating the oxidation potential, either by docking with ions or relaxing the molecule, depending on the presence of ions. It then computes the redox potential based on these generated molecules.</p> <p>Args:     None</p> <p>Returns:     float: The calculated oxidation potential in eV.</p> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def cal_ox(self):\n    \"\"\"\n    Calculates the oxidation potential of a molecular system.\n\n    This function generates the neutral and charged molecules required for calculating the oxidation potential, either by docking with ions or relaxing the molecule, depending on the presence of ions. It then computes the redox potential based on these generated molecules.\n\n    Args:\n        None\n\n    Returns:\n        float: The calculated oxidation potential in eV.\n\n    \"\"\"\n\n    # * calculate the oxidation state energies (in eV)\n    redox_potential = RedoxPotential(\n        neutral_molecule=self.neutral_molecule,\n        charged_molecule=self.charged_molecule,\n        chg_mult=self.chg_mult[:4],\n        calc_type=\"ox\",\n        calc_kwards=self.calc_kwards,\n    ).cal_cycle()\n    logging.info(f\"{self.label} oxidation potential: {redox_potential} eV\")\n    return redox_potential\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.cal_re","title":"cal_re","text":"<pre><code>cal_re()\n</code></pre> <p>Calculates the reduction potential of a molecular system.</p> <p>This function generates the neutral and charged molecules required for calculating the reduction potential, either by protonation or relaxation, depending on the presence of ions. It utilizes a helper function to streamline the process of generating molecules and logs the resulting reduction potential.</p> <p>Args:     add_ion: A boolean indicating whether to include an anion in the system.     molecule: An Atoms object representing the molecule for the calculation.     ions: A list containing Atoms or strings representing the ions involved in the calculation.     chg_mult: A list of integers specifying the charge multiplicities for the calculation.     calc_kwards: A dictionary containing keyword arguments for the calculation methods.</p> <p>Returns:     float: The calculated reduction potential in eV.</p> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def cal_re(self):\n    \"\"\"\n    Calculates the reduction potential of a molecular system.\n\n    This function generates the neutral and charged molecules required for calculating the reduction potential, either by protonation or relaxation, depending on the presence of ions. It utilizes a helper function to streamline the process of generating molecules and logs the resulting reduction potential.\n\n    Args:\n        add_ion: A boolean indicating whether to include an anion in the system.\n        molecule: An Atoms object representing the molecule for the calculation.\n        ions: A list containing Atoms or strings representing the ions involved in the calculation.\n        chg_mult: A list of integers specifying the charge multiplicities for the calculation.\n        calc_kwards: A dictionary containing keyword arguments for the calculation methods.\n\n    Returns:\n        float: The calculated reduction potential in eV.\n\n    \"\"\"\n    # * calculate the oxidation state energies (in eV)\n    redox_potential = RedoxPotential(\n        neutral_molecule=self.neutral_molecule,\n        charged_molecule=self.charged_molecule,\n        chg_mult=self.chg_mult[4:8],\n        calc_type=\"re\",\n        calc_kwards=self.calc_kwards,\n    ).cal_cycle()\n    logging.info(f\"{self.label} reduction potential: {redox_potential} eV\")\n    return redox_potential\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.get_ox","title":"get_ox","text":"<pre><code>get_ox()\n</code></pre> <p>Calculates the oxidation potential of a molecular system.</p> <p>This function generates the neutral and charged molecules required for calculating the oxidation potential, either by docking with ions or relaxing the molecule, depending on the presence of ions. It then computes the redox potential based on these generated molecules.</p> <p>Args:     None</p> <p>Returns:     float: The calculated oxidation potential in eV.</p> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def get_ox(self):\n    \"\"\"\n    Calculates the oxidation potential of a molecular system.\n\n    This function generates the neutral and charged molecules required for calculating the oxidation potential, either by docking with ions or relaxing the molecule, depending on the presence of ions. It then computes the redox potential based on these generated molecules.\n\n    Args:\n        None\n\n    Returns:\n        float: The calculated oxidation potential in eV.\n\n    \"\"\"\n    self.prepare_ox()\n    return self.cal_ox()\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.get_re","title":"get_re","text":"<pre><code>get_re()\n</code></pre> <p>Calculates the reduction potential of a molecular system.</p> <p>This function generates the neutral and charged molecules required for calculating the reduction potential, either by protonation or relaxation, depending on the presence of ions. It utilizes a helper function to streamline the process of generating molecules and logs the resulting reduction potential.</p> <p>Args:     None</p> <p>Returns:     float: The calculated reduction potential in eV.</p> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def get_re(self):\n    \"\"\"\n    Calculates the reduction potential of a molecular system.\n\n    This function generates the neutral and charged molecules required for calculating the reduction potential, either by protonation or relaxation, depending on the presence of ions. It utilizes a helper function to streamline the process of generating molecules and logs the resulting reduction potential.\n\n    Args:\n        None\n\n    Returns:\n        float: The calculated reduction potential in eV.\n\n    \"\"\"\n    self.prepare_re()\n    return self.cal_re()\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.get_redox","title":"get_redox","text":"<pre><code>get_redox()\n</code></pre> <p>Calculates the oxidation and reduction potentials of a molecular system.</p> <p>This function retrieves the oxidation and reduction potentials by calling the respective methods and returns them as a list. It provides a convenient way to access both potentials in a single call.</p> <p>Args:     None</p> <p>Returns:     list: A list containing the oxidation potential and reduction potential.</p> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def get_redox(self):\n    \"\"\"\n    Calculates the oxidation and reduction potentials of a molecular system.\n\n    This function retrieves the oxidation and reduction potentials by calling the respective methods and returns them as a list. It provides a convenient way to access both potentials in a single call.\n\n    Args:\n        None\n\n    Returns:\n        list: A list containing the oxidation potential and reduction potential.\n\n    \"\"\"\n\n    oxidation_potential = self.get_ox()\n    reduction_potential = self.get_re()\n    return [oxidation_potential, reduction_potential]\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.prepare_ox","title":"prepare_ox","text":"<pre><code>prepare_ox()\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def prepare_ox(self):\n    # * generate solvated molecules using ion and counter-ion\n    if self.add_ion:\n        logging.info(\"Generate and relax molecules clusters using crest\")\n        self.neutral_molecule = dock_atoms(\n            self.molecule,\n            dock=self.ions[0],\n            crest_sampling=True,\n            chg=self.chg_mult[0],\n            mult=self.chg_mult[1],\n        )\n        self.charged_molecule = dock_atoms(\n            self.molecule,\n            dock=self.ions[0],\n            crest_sampling=True,\n            chg=self.chg_mult[2],\n            mult=self.chg_mult[3],\n        )\n    else:\n        logging.info(\"Relaxing molecules using crest\")\n        self.neutral_molecule = relax(\n            self.molecule, chg=self.chg_mult[0], mult=self.chg_mult[1]\n        )\n        self.charged_molecule = relax(\n            self.molecule, chg=self.chg_mult[2], mult=self.chg_mult[3]\n        )\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.prepare_re","title":"prepare_re","text":"<pre><code>prepare_re()\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>def prepare_re(self):\n    def generate_molecule(\n        molecule, ion, chg, mult, protonate_ion_string, threads=16\n    ):\n        \"\"\"\n        Generates a molecular structure by either protonating or docking the specified molecule.\n\n        This function attempts to protonate the given molecule using the specified ion and charge parameters. If protonation fails, it falls back to docking the molecule with the specified ion, logging the failure of the protonation attempt.\n\n        If the protonation will fail or results a mis-protonated molecule, please consider docking your ion into it by setting 'protonate_ion_string' to False in class RedoxCal. This will allow the docking attempt to work normally.\n\n        Args:\n            molecule: The molecular structure to be modified.\n            ion: The ion used for protonation or docking.\n            chg: The charge associated with the ion.\n            mult: The multiplicity of the ion.\n            protonate_ion_string: A boolean indicating whether to attempt protonation.\n            threads (int, optional): The number of threads to use for the operation. Defaults to 16.\n\n        Returns:\n            The modified molecular structure after protonation or docking, or None if both attempts fail.\n        \"\"\"\n\n        mol = (\n            protonate(molecule, ion=ion, chg=chg, mult=mult, threads=threads)\n            if protonate_ion_string is True and isinstance(ion, str)\n            else None\n        )\n        if mol is None:\n            logging.info(\"Protonation failed or skipped, trying docking\")\n            mol = dock_atoms(\n                molecule, dock=ion, crest_sampling=True, chg=chg, mult=mult\n            )\n        return mol\n\n    if self.add_ion:\n        logging.info(\"Generate and relax molecules clusters using crest\")\n        self.neutral_molecule = generate_molecule(\n            self.molecule,\n            self.ions[1],\n            self.chg_mult[4],\n            self.chg_mult[5],\n            protonate_ion_string=self.protonate_ion_string,\n        )\n        self.charged_molecule = generate_molecule(\n            self.molecule,\n            self.ions[1],\n            self.chg_mult[6],\n            self.chg_mult[7],\n            protonate_ion_string=self.protonate_ion_string,\n        )\n    else:\n        logging.info(\"Relaxing molecules using crest\")\n        self.neutral_molecule = relax(\n            self.molecule, chg=self.chg_mult[4], mult=self.chg_mult[5]\n        )\n        self.charged_molecule = relax(\n            self.molecule, chg=self.chg_mult[6], mult=self.chg_mult[7]\n        )\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.set_calc_kwards","title":"set_calc_kwards","text":"<pre><code>set_calc_kwards(v)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>@field_validator(\"calc_kwards\")\ndef set_calc_kwards(cls, v):\n    return v or {\n        \"opt_xc\": \"b3lyp\",\n        \"opt_basis\": \"6-311+G(d,p)\",\n        \"sol_xc\": \"m062x\",\n        \"sol_basis\": \"6-31G*\",\n        \"solvent\": \"Acetone\",\n    }\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.set_chg_mult","title":"set_chg_mult","text":"<pre><code>set_chg_mult(v)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>@field_validator(\"chg_mult\")\ndef set_chg_mult(cls, v):\n    return v or [-1, 1, 0, 2, 1, 1, 0, 2]\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/redox.html#himatcal.recipes.electrolyte.redox.RedoxCal.set_ions","title":"set_ions","text":"<pre><code>set_ions(v)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/redox.py</code> <pre><code>@field_validator(\"ions\")\ndef set_ions(cls, v):\n    return v or [PF6, \"Li\"]\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html","title":"_base","text":""},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.formchkpath","title":"formchkpath  <code>module-attribute</code>","text":"<pre><code>formchkpath = str(getattr(SETTINGS, 'FORMCHK_PATH', ''))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.multiwfnpath","title":"multiwfnpath  <code>module-attribute</code>","text":"<pre><code>multiwfnpath = str(getattr(SETTINGS, 'MULTIWFN_PATH', ''))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.charges_to_json","title":"charges_to_json","text":"<pre><code>charges_to_json(charges, label)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def charges_to_json(charges, label):\n    charge_data = []\n    for charge in charges:\n        import re\n\n        if match := re.match(r\"(\\d+)\\((\\w+)\\s*\\)\", charge):\n            atom_index, atom_type = match.groups()\n        else:\n            raise ValueError(f\"Unexpected charge format: {charge}\")\n        atom_charge = float(charge.split()[2])\n        charge_data.append(\n            {\n                \"atom_index\": atom_index,\n                \"atom_type\": atom_type,\n                \"atom_charge\": atom_charge,\n            }\n        )\n    return json.dumps({\"label\": label, \"charges\": charge_data}, indent=4)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.extract_resp2","title":"extract_resp2","text":"<pre><code>extract_resp2(fchk_file)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def extract_resp2(fchk_file):\n    label = Path(fchk_file).stem\n    result = subprocess.Popen(\n        multiwfnpath,\n        stdin=subprocess.PIPE,\n        stdout=subprocess.PIPE,\n        stderr=subprocess.PIPE,\n        universal_newlines=True,\n    )\n    if result.stdin:\n        result.stdin.write(f\"{fchk_file}\\n\")\n        result.stdin.write(\"7\\n18\\n1\\ny\\n0\\n0\\nq\\n\")  # * Multiwfn RESP2 calculation\n    else:\n        raise RuntimeError(\"Failed to write to stdin of the subprocess\")\n    out, err = result.communicate()\n    charges = []\n    capture = False\n    for line in out.splitlines():\n        if \"Center       Charge\" in line:\n            capture = True\n            continue\n        if capture:\n            if line.strip() == \"\" or \"Sum of charges\" in line:\n                break\n            charges.append(line.strip())\n    return charges_to_json(charges, label)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.formchk","title":"formchk","text":"<pre><code>formchk(chk_file: str)\n</code></pre> <p>Convert a check file to a formatted check file using an external command.</p> <p>This function takes a check file as input, executes a subprocess to convert it to a formatted check file, and returns the path of the newly created file. It ensures that the conversion process is executed correctly by checking for errors during the subprocess call.</p> <p>Args:     chk_file (str): The path to the check file to be converted.</p> <p>Returns:     Path: The path to the newly created formatted check file with a .fchk suffix.</p> <p>Raises:     subprocess.CalledProcessError: If the subprocess command fails.</p> <p>Examples:     fchk_file = formchk(\"/path/to/file.chk\")</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def formchk(chk_file: str):\n    \"\"\"\n    Convert a check file to a formatted check file using an external command.\n\n    This function takes a check file as input, executes a subprocess to convert it to a formatted check file, and returns the path of the newly created file. It ensures that the conversion process is executed correctly by checking for errors during the subprocess call.\n\n    Args:\n        chk_file (str): The path to the check file to be converted.\n\n    Returns:\n        Path: The path to the newly created formatted check file with a .fchk suffix.\n\n    Raises:\n        subprocess.CalledProcessError: If the subprocess command fails.\n\n    Examples:\n        fchk_file = formchk(\"/path/to/file.chk\")\n    \"\"\"\n\n    chk_file_path = Path(chk_file)\n    subprocess.run(f\"{formchkpath} {chk_file}\", shell=True, check=True)\n    return chk_file_path.with_suffix(\".fchk\")\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.gen_resp2_chg","title":"gen_resp2_chg","text":"<pre><code>gen_resp2_chg(chk_file: str)\n</code></pre> <p>Generate a charge file from a given check file by performing a RESP calculation.</p> <p>This function converts a check file to a formatted check file, runs a RESP calculation to extract charge data, and writes the results to a JSON file. It returns the path to the generated charge file with a .chg suffix.</p> <p>Args:     chk_file (str): The path to the check file to be processed, both .chk and .fchk files are supported.</p> <p>Returns:     Path: The path to the generated charge file with a .chg suffix.</p> <p>Examples:     charge_file = gen_resp2_chg(\"path/to/check_file.chk\")</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def gen_resp2_chg(chk_file: str):\n    \"\"\"\n    Generate a charge file from a given check file by performing a RESP calculation.\n\n    This function converts a check file to a formatted check file, runs a RESP calculation to extract charge data, and writes the results to a JSON file. It returns the path to the generated charge file with a .chg suffix.\n\n    Args:\n        chk_file (str): The path to the check file to be processed, both .chk and .fchk files are supported.\n\n    Returns:\n        Path: The path to the generated charge file with a .chg suffix.\n\n    Examples:\n        charge_file = gen_resp2_chg(\"path/to/check_file.chk\")\n    \"\"\"\n    # * Convert the check files to formatted check files.\n    fchk_file = chk_file if chk_file.endswith(\".fchk\") else str(formchk(chk_file))\n    # * Run the RESP calculation using Multiwfn.\n    with cd(Path(fchk_file).parent):\n        charges_json = extract_resp2(fchk_file=fchk_file)\n        # write the chages to a json file\n        json_file_path = Path(chk_file).with_suffix(\".json\")\n        with json_file_path.open(\"w\") as f:\n            f.write(charges_json)\n        return Path(chk_file).with_suffix(\".chg\")\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.merge_chgs","title":"merge_chgs","text":"<pre><code>merge_chgs(chg_file_1, chg_file_2)\n</code></pre> <p>Merge two charge files by averaging the charges of corresponding atoms.</p> <p>This function reads two charge files, parses their contents to extract atom data and charges, and computes the average charge for each atom. The results are then written to a new charge file, which is returned with a modified filename.</p> <p>Args:     chg_file_1 (str): The path to the first charge file to be merged.     chg_file_2 (str): The path to the second charge file to be merged.</p> <p>Returns:     Path: The path to the newly created merged charge file with a .merged.chg suffix.</p> <p>Raises:     ValueError: If there is a mismatch in atom data between the two charge files.</p> <p>Examples:     merged_file = merge_chgs(\"path/to/first.chg\", \"path/to/second.chg\")</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def merge_chgs(chg_file_1, chg_file_2):\n    \"\"\"\n    Merge two charge files by averaging the charges of corresponding atoms.\n\n    This function reads two charge files, parses their contents to extract atom data and charges, and computes the average charge for each atom. The results are then written to a new charge file, which is returned with a modified filename.\n\n    Args:\n        chg_file_1 (str): The path to the first charge file to be merged.\n        chg_file_2 (str): The path to the second charge file to be merged.\n\n    Returns:\n        Path: The path to the newly created merged charge file with a .merged.chg suffix.\n\n    Raises:\n        ValueError: If there is a mismatch in atom data between the two charge files.\n\n    Examples:\n        merged_file = merge_chgs(\"path/to/first.chg\", \"path/to/second.chg\")\n    \"\"\"\n\n    def parse_chg_file(chg_file):\n        with Path(chg_file).open() as f:\n            lines = f.readlines()\n        parsed_data = []\n        for line in lines:\n            parts = line.split()\n            atom_data = parts[:-1]\n            charge = float(parts[-1])\n            parsed_data.append((atom_data, charge))\n        return parsed_data\n\n    def average_charges(data1, data2):\n        averaged_data = []\n        for (atom_data1, charge1), (atom_data2, charge2) in zip(data1, data2):\n            if atom_data1 != atom_data2:\n                raise ValueError(\"Atom data mismatch between charge files\")\n            averaged_charge = (charge1 + charge2) / 2\n            averaged_data.append((atom_data1, averaged_charge))\n        return averaged_data\n\n    def write_chg_file(data, output_file):\n        with Path(output_file).open(\"w\") as f:\n            for atom_data, charge in data:\n                f.write(\" \".join(atom_data) + f\" {charge:.10f}\\n\")\n\n    data1 = parse_chg_file(chg_file_1)\n    data2 = parse_chg_file(chg_file_2)\n    averaged_data = average_charges(data1, data2)\n    output_file = Path(chg_file_1).with_suffix(\".merged.chg\")\n    write_chg_file(averaged_data, output_file)\n    return output_file\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/_base.html#himatcal.recipes.electrolyte.sol_stru._base.write_sobtopini","title":"write_sobtopini","text":"<pre><code>write_sobtopini()\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/_base.py</code> <pre><code>def write_sobtopini():\n    ## * write a sobtop.ini file in the current directory\n    content = f\"\"\"  nthreads= 4  // Number of threads used for parallel calculation\n        iskipgendih= 0  // 1: Skip generating dihedral terms, 0: Do not skip\n        ioutatminfo= 0  // 1: Output atomic coordinates and connectivities when to atminfo.txt in current folder when loading input file, 0: Do not output to file but shown on screen\n        ichggeom= 1  // 1: When loading .chg file, replace current geometry with that in .chg file, 0: Do not replace\n        k_method= 2  // Default method of determining k. 1: Seminario, 2: mSeminario, 3: m2Seminario, 4: DRIH\n        bondcrit= 1.15  // When pdb/pqr is used as input, two atoms are considered as bonded if their distance is smaller than sum of their covalent radii multiplied by this factor. Priority is lower than the criteria defined in bondcrit.dat\n        Multiwfn_cmd= \"{SETTINGS.MULTIWFN_PATH}\"// Path of executable file of Multiwfn\n        OpenBabel_cmd= \"{SETTINGS.OBABEL_PATH}\" // Path of executable file of OpenBabel\"\"\"\n    with Path.cwd().joinpath(\"sobtop.ini\").open(\"w\") as f:\n        f.write(content)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html","title":"build_box","text":""},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder","title":"ElectrolyteBuilder","text":"<pre><code>ElectrolyteBuilder(mol_path, mol_name_list: list | None = None)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/build_box.py</code> <pre><code>def __init__(self, mol_path, mol_name_list: list | None = None):\n    self.mol_path = Path(mol_path)\n    self.EC = mb.load(str(self.mol_path / \"EC.pdb\"))\n    self.DEC = mb.load(str(self.mol_path / \"DEC.pdb\"))\n    self.EMC = mb.load(str(self.mol_path / \"EMC.pdb\"))\n    self.DMC = mb.load(str(self.mol_path / \"DMC.pdb\"))\n    self.Li = mb.load(str(self.mol_path / \"Li.pdb\"))\n    self.PF6 = mb.load(str(self.mol_path / \"PF6.pdb\"))\n    if mol_name_list:\n        for mol_name in mol_name_list:\n            setattr(self, mol_name, mb.load(str(self.mol_path / f\"{mol_name}.pdb\")))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.DEC","title":"DEC  <code>instance-attribute</code>","text":"<pre><code>DEC = load(str(mol_path / 'DEC.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.DMC","title":"DMC  <code>instance-attribute</code>","text":"<pre><code>DMC = load(str(mol_path / 'DMC.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.EC","title":"EC  <code>instance-attribute</code>","text":"<pre><code>EC = load(str(mol_path / 'EC.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.EMC","title":"EMC  <code>instance-attribute</code>","text":"<pre><code>EMC = load(str(mol_path / 'EMC.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.Li","title":"Li  <code>instance-attribute</code>","text":"<pre><code>Li = load(str(mol_path / 'Li.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.PF6","title":"PF6  <code>instance-attribute</code>","text":"<pre><code>PF6 = load(str(mol_path / 'PF6.pdb'))\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.mol_path","title":"mol_path  <code>instance-attribute</code>","text":"<pre><code>mol_path = Path(mol_path)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.build_box","title":"build_box","text":"<pre><code>build_box(box_electrolyte_composition, density, box, save_path, capital=True)\n</code></pre> <p>\u4f7f\u7528mbuild\u586b\u5145\u76d2\u5b50\u5e76\u4fee\u6b63\u6b8b\u57fa\u540d\u548c\u6b8b\u57fa\u5e8f\u53f7</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/build_box.py</code> <pre><code>def build_box(\n    self, box_electrolyte_composition, density, box, save_path, capital=True\n):\n    \"\"\"\n    \u4f7f\u7528mbuild\u586b\u5145\u76d2\u5b50\u5e76\u4fee\u6b63\u6b8b\u57fa\u540d\u548c\u6b8b\u57fa\u5e8f\u53f7\n    \"\"\"\n    box_compound = [getattr(self, key) for key in box_electrolyte_composition]\n    box_n_compounds = [\n        box_electrolyte_composition[key][\"mol\"]\n        for key in box_electrolyte_composition\n    ]\n    if density:\n        box_electrolyte = mb.packing.fill_box(\n            compound=box_compound,\n            n_compounds=box_n_compounds,\n            density=density * 1000,  # kg/m^3\n            # ratio=[1,1,1],\n            # box=[3,3,3]\n        )\n    else:\n        box_electrolyte = mb.packing.fill_box(\n            compound=box_compound,\n            n_compounds=box_n_compounds,\n            density=density *1000,# kg/m^3\n            # ratio=[1,1,1],\n            box=box,\n        )\n\n    box_electrolyte.save(save_path, overwrite=True)\n    self.fix_pdb(save_path, box_electrolyte_composition, save_path, capital=capital)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.extracted_LiPF6","title":"extracted_LiPF6","text":"<pre><code>extracted_LiPF6(round_componds_dict, arg1)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/build_box.py</code> <pre><code>def extracted_LiPF6(self, round_componds_dict, arg1):\n    MOL_LPF6 = round_componds_dict[arg1][\"mol\"]\n    del round_componds_dict[arg1]\n    round_componds_dict[\"PF6\"] = {\"mol\": MOL_LPF6, \"n_atoms\": MOL_LPF6 * 7}\n    round_componds_dict[\"Li\"] = {\"mol\": MOL_LPF6, \"n_atoms\": MOL_LPF6 * 1}\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/build_box.html#himatcal.recipes.electrolyte.sol_stru.build_box.ElectrolyteBuilder.fix_pdb","title":"fix_pdb","text":"<pre><code>fix_pdb(pdb_path, round_componds_dict, pdb_save_path, capital=True)\n</code></pre> <p>\u5c06build_electrolytes\u751f\u6210\u7684\u7535\u89e3\u6db2\u7ec4\u6210\u7684pdb\u6587\u4ef6\u4e2d\u7684RESIDUE NAME\u548cRESIDUE INDEX\u4fee\u6539\u4e3a\u6b63\u786e\u7684\u503c</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/build_box.py</code> <pre><code>def fix_pdb(self, pdb_path, round_componds_dict, pdb_save_path, capital=True):\n    # The same code as before...\n    \"\"\"\n    \u5c06build_electrolytes\u751f\u6210\u7684\u7535\u89e3\u6db2\u7ec4\u6210\u7684pdb\u6587\u4ef6\u4e2d\u7684RESIDUE NAME\u548cRESIDUE INDEX\u4fee\u6539\u4e3a\u6b63\u786e\u7684\u503c\n    \"\"\"\n    mb_compound_list = list(round_componds_dict.keys())\n    if \"LiPF6(M)\" in mb_compound_list:\n        self.extracted_LiPF6(round_componds_dict, \"LiPF6(M)\")\n    if \"LiPF6\" in mb_compound_list:\n        self.extracted_LiPF6(round_componds_dict, \"LiPF6\")\n    mb_compound_list = list(round_componds_dict.keys())\n    # print(mb_compound_list)\n    line_start = 1\n    line_stop = 1\n    with Path.open(Path(pdb_path), \"r\") as f:\n        lines = f.readlines()\n    for compound_index in range(len(mb_compound_list)):\n        if compound_index == 0:\n            line_start = 1\n            line_stop = (\n                1 + round_componds_dict[mb_compound_list[compound_index]][\"n_atoms\"]\n            )\n        else:\n            line_start = line_stop\n            line_stop = (\n                line_start\n                + round_componds_dict[mb_compound_list[compound_index]][\"n_atoms\"]\n            )\n        # print(line_start, line_stop)\n        compound = mb_compound_list[compound_index]\n        resdiue_index = 1\n        for j in range(line_start, line_stop):\n            n_compounds = round_componds_dict[compound][\"mol\"]\n            atom_per_compound = (\n                round_componds_dict[compound][\"n_atoms\"] / n_compounds\n            )\n            resdiue_index = int((j - line_start) / atom_per_compound) + 1\n            if capital:\n                resdiue_name = mb_compound_list[compound_index]\n            else:\n                resdiue_name = mb_compound_list[compound_index].lower()\n            # resdiue_name = mb_compound_list[compound_index]\n            lines[j] = (\n                (\n                    (\n                        lines[j][:17]\n                        + str(\" \" * (3 - len(resdiue_name)) + str(resdiue_name))\n                    )\n                    + lines[j][20:22]\n                )\n                + str(\" \" * (4 - len(str(resdiue_index))) + str(resdiue_index))\n                + lines[j][26:]\n            )\n            # lines[j] = lines[j].replace('HETATM','ATOM  ')\n    with Path.open(Path(pdb_save_path), \"w\") as f:\n        f.writelines(lines)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.mdp_min","title":"mdp_min  <code>module-attribute</code>","text":"<pre><code>mdp_min = '\\n;define                  = -DFLEXIBLE\\n; run control\\nintegrator      = steep                 ; steepest descents minimization\\nemtol           = 100.0                 ; stop when max force &lt; 100.0 kJ/mol/nm\\nemstep          = 0.01                  ; energy step size\\nnsteps          = 50000                 ; max number of steps\\n\\n\\n; output control\\nnstxout     = 500                       ; steps per position save\\nnstlog      = 500                       ; steps per log entry\\nnstenergy   = 50                        ; steps per energy file entry\\n\\n; cutoffs\\ncutoff-scheme   = Verlet\\nnstlist                 = 10            ; neighbor list update frequency\\nns_type                 = grid          ; neighbor list method (simple, grid)\\npbc                     = xyz           ; periodic boundary conditions\\n\\ncoulombtype             = PME           ; method for electrostatics\\nrcoulomb                = 1.2           ; Short-range electrostatic cutoff\\nrvdw                    = 1.2           ; van der Waals cutoff\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.mdp_npt","title":"mdp_npt  <code>module-attribute</code>","text":"<pre><code>mdp_npt = '\\n; run control\\nintegrator      = md\\ndt              = 0.001                 ; 2 fs\\nnsteps          = 100000                ; steps, =100 ps\\n\\n; Ooutput control\\nnstxout     = 500                       ; steps per position save\\nnstlog      = 500                       ; steps per log entry\\nnstenergy   = 50                        ; steps per energy file entry\\n\\n; cutoffs\\ncutoff-scheme   = Verlet\\nnstlist                 = 10            ; neighbor list update frequency\\nns_type                 = grid          ; neighbor list method (simple, grid)\\npbc                     = xyz           ; periodic boundary conditions\\n\\ncoulombtype             = PME           ; method for electrostatics\\nrcoulomb                = 1.2           ; Short-range electrostatic cutoff\\nrvdw                    = 1.2           ; van der Waals cutoff\\nDispCorr                = EnerPres      ; long-distance contributions to E, P\\n\\n; temperature control\\ntcoupl          = v-rescale ; velocity rescaling thermostat\\ntc_grps         = system        ; coupled to entire system\\ntau_t           = 1.0           ; time constant\\nref_t           = 300           ; temperature (K)\\n\\n; pressure control\\npcoupl          = berendsen ; barostat type\\ntau_p           = 10.0                  ; time constant\\nref_p           = 1.0                   ; pressure (bar)\\ncompressibility = 4.5e-5                ; pressure bath compressibility (of water, bar^-1)\\n\\n; bond parameters\\ncontinuation    = yes                   ; restart from NVT\\nconstraints     = h-bonds                       ; h-bond lengths constrained\\nconstraint_algorithm = LINCS    ; constraint method\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.mdp_nvt","title":"mdp_nvt  <code>module-attribute</code>","text":"<pre><code>mdp_nvt = '\\n; run control\\nintegrator      = md\\ndt              = 0.002                 ; 2 fs\\nnsteps          = 50000         ; steps, = 100 ps\\n\\n; Ooutput control\\nnstxout     = 500                       ; steps per position save\\nnstlog      = 500                       ; steps per log entry\\nnstenergy   = 50                        ; steps per energy file entry\\n\\n; cutoffs\\ncutoff-scheme   = Verlet\\nnstlist                 = 10            ; neighbor list update frequency\\nns_type                 = grid          ; neighbor list method (simple, grid)\\npbc                     = xyz           ; periodic boundary conditions\\n\\ncoulombtype             = PME           ; method for electrostatics\\nrcoulomb                = 1.2           ; Short-range electrostatic cutoff\\nrvdw                    = 1.2           ; van der Waals cutoff\\nDispCorr                = EnerPres      ; long-distance contributions to E, P\\n\\n; temperature control\\ntcoupl          = v-rescale ; velocity rescaling thermostat\\ntc_grps         = system        ; coupled to entire system\\ntau_t           = 1.0           ; time constant\\nref_t           = 300           ; temperature (K)\\n\\n; pressure control\\npcoupl          = no                    ; no pressure control in NVT\\n\\n; velocity generation\\ngen_vel         = yes                   ; generate velocities from Maxwell distribution\\ngen_temp        = 300                   ; temperature for Maxwell distribution\\n\\n; bond parameters\\ncontinuation    = no                    ; first dynamics run\\nconstraints     = h-bonds                       ; h-bond lengths constrained\\nconstraint_algorithm = LINCS    ; constraint method\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.mdp_pro","title":"mdp_pro  <code>module-attribute</code>","text":"<pre><code>mdp_pro = '\\n; Run control\\nintegrator               = md\\ntinit                    = 0\\ndt                       = 0.002\\nnsteps                   = 2500000    ; 10 ns\\n\\n; Output control\\nnstxout                  = 5000\\nnstlog                   = 5000\\nnstenergy                = 500\\n\\n; cutoffs\\ncutoff-scheme            = verlet\\nnstlist                  = 20\\nns_type                  = grid\\npbc                      = xyz\\n\\ncoulombtype              = PME\\nrcoulomb                 = 1.2\\nvdwtype                  = cutoff\\nrvdw                     = 1.2\\nDispCorr                = EnerPres\\n\\n; Temperature coupling\\ntcoupl                   = v-rescale\\ntc_grps                  = system\\ntau_t                    = 1.0\\nref_t                    = 300\\n\\n; Pressure coupling\\nPcoupl                   = berendsen\\ntau_p                    = 10.\\ncompressibility          = 4.5e-05\\nref_p                    = 1.0\\n\\n; bond parameters\\ncontinuation    = yes                   ; restart from NPT\\nconstraints     = h-bonds                       ; h-bond lengths constrained\\nconstraint_algorithm = LINCS    ; constraint method\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal","title":"DielectricConstantCal","text":"<pre><code>DielectricConstantCal(label: str, molecular_data: Atoms, charge: int, mult: int, mem='64GB', np=64)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/core.py</code> <pre><code>def __init__(\n    self,\n    label: str,\n    molecular_data: Atoms,\n    charge: int,\n    mult: int,\n    mem=\"64GB\",\n    np=64,\n):\n    self.label = label\n    self.molecular_data = molecular_data\n    self.charge = charge\n    self.mult = mult\n    self.mem = mem\n    self.np = np\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.charge","title":"charge  <code>instance-attribute</code>","text":"<pre><code>charge = charge\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.label","title":"label  <code>instance-attribute</code>","text":"<pre><code>label = label\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.mem","title":"mem  <code>instance-attribute</code>","text":"<pre><code>mem = mem\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.molecular_data","title":"molecular_data  <code>instance-attribute</code>","text":"<pre><code>molecular_data = molecular_data\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.mult","title":"mult  <code>instance-attribute</code>","text":"<pre><code>mult = mult\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.np","title":"np  <code>instance-attribute</code>","text":"<pre><code>np = np\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.get_dielect_constant","title":"get_dielect_constant","text":"<pre><code>get_dielect_constant()\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/core.py</code> <pre><code>def get_dielect_constant(self):\n    opt_method = \"b3lyp\"\n    opt_basis = \"6-31G*\"\n    gas_basis = \"def2tzvp\"\n    solvent = \"Acetone\"\n    work_path = os.getcwd()\n\n    # *  opt at the b3lyp/6-31G* level\n    opt_atoms = Gaussiancal(\n        method=opt_method, basis=opt_basis, mem=self.mem, nprocshared=self.np\n    ).run(\n        self.molecular_data,\n        self.charge,\n        self.mult,\n        cal_type=\"em=GD3BJ opt\",\n        label=f\"{self.label}-opt\",\n    )\n    # gas_sp\n    Gaussiancal(\n        method=opt_method, basis=gas_basis, mem=self.mem, nprocshared=self.np\n    ).run(\n        opt_atoms,\n        self.charge,\n        self.mult,\n        cal_type=\"em=GD3BJ\",\n        label=f\"{self.label}-gas\",\n        chk=f\"./{self.label}-gas.chk\",\n    )\n    # sol_sp\n    sol_atoms = Gaussiancal(\n        method=opt_method, basis=gas_basis, mem=self.mem, nprocshared=self.np\n    ).run(\n        opt_atoms,\n        self.charge,\n        self.mult,\n        cal_type=\"em=GD3BJ freq\",\n        label=f\"{self.label}-sol\",\n        scrf=f\"SMD, solvent={solvent}\",\n        chk=f\"./{self.label}-sol.chk\",\n    )\n    with open(get_software_json_path(), \"r\") as f:\n        sobtoppath = json.load(f)[\"sobtop_path\"]\n    self.resp2_chg(f\"./{self.label}-gas.chk\", f\"./{self.label}-sol.chk\")\n    with open(get_software_json_path(), \"r\") as f:\n        obabelpath = json.load(f)[\"obabel_path\"]\n    write(f\"./{self.label}-tmp.xyz\", sol_atoms)\n    subprocess.run(\n        f\"{obabelpath} -ixyz ./{self.label}-tmp.xyz -omol2 -O ./{self.label}.mol2\",\n        shell=True,\n    )\n    subprocess.run(\n        f\"cp ./{self.label}-gas.fchk ./{self.label}-sol.fchk ./{self.label}.chg ./{self.label}.mol2 {sobtoppath}\",\n        shell=True,\n    )\n    os.chdir(sobtoppath)\n    sobtopexe = \"./sobtop\"\n    process = subprocess.Popen(\n        sobtopexe,\n        stdin=subprocess.PIPE,\n        stdout=subprocess.PIPE,\n        stderr=subprocess.PIPE,\n        universal_newlines=True,\n    )\n    process.stdin.write(f\"./{self.label}.mol2\\n\")\n    process.stdin.write(\n        f\"7\\n10\\n{self.label}.chg\\n0\\n2\\n\\n1\\n2\\n7\\n{self.label}-sol.fchk\\n\\n\\n0\\n\"\n    )\n    out, err = process.communicate()\n    subprocess.run(\n        f\"cp ./{self.label}.gro ./{self.label}.top ./{self.label}.itp {work_path}\",\n        shell=True,\n    )\n\n\n    os.chdir(work_path)\n    with open(get_software_json_path(), \"r\") as f:\n        gromacpath = json.load(f)[\"gromacs_path\"]\n    subprocess.run(\n        f\"{gromacpath} insert-molecules -ci {self.label}.gro -nmol 1200 -box 5 5 5 -o {self.label}-box.gro\",\n        shell=True,\n    )\n    box_num = int(\n        int(open(f\"./{self.label}-box.gro\", \"r\").readlines()[1].rstrip().split()[0])\n        / len(self.molecular_data)\n    )\n    top_file = open(f\"./{self.label}.top\", \"r\").readlines()\n    top_file_result = \"\"\n    for i in top_file:\n        if self.label in i.rstrip().split() and len(i.rstrip().split()) &gt; 1:\n            top_file_result = top_file_result + f\"{self.label}\\t{box_num}\\n\"\n        else:\n            top_file_result = top_file_result + i\n    open(f\"./{self.label}.top\", \"w\").write(top_file_result)\n    open(\"./min.mdp\", \"w\").write(mdp_min)\n    open(\"./nvt.mdp\", \"w\").write(mdp_nvt)\n    open(\"./npt.mdp\", \"w\").write(mdp_npt)\n    open(\"./pro.mdp\", \"w\").write(mdp_pro)\n    subprocess.run(\n        f\"mkdir min; cp {self.label}.top {self.label}.itp min.mdp {self.label}-box.gro min ; cd min ; {gromacpath} grompp -f min.mdp  -c {self.label}-box.gro  -p {self.label}.top -o min.tpr; {gromacpath} mdrun -nt {self.np} -deffnm min; cd ..\",\n        shell=True,\n    )\n    subprocess.run(\n        f\"mkdir nvt; cp {self.label}.top {self.label}.itp nvt.mdp nvt ; cd nvt ; cp ../min/min.gro . ; {gromacpath} grompp -f nvt.mdp  -c min.gro  -p {self.label}.top -o nvt.tpr; {gromacpath} mdrun -nt {self.np} -deffnm nvt; cd ..\",\n        shell=True,\n    )\n    subprocess.run(\n        f\"mkdir npt; cp {self.label}.top {self.label}.itp npt.mdp npt ;cd npt ; cp ../nvt/nvt.gro . ; {gromacpath} grompp -f npt.mdp  -c nvt.gro  -p {self.label}.top -o npt.tpr -maxwarn 1; {gromacpath} mdrun -nt {self.np} -deffnm npt; cd ..\",\n        shell=True,\n    )\n    subprocess.run(\n        f\"mkdir pro; cp {self.label}.top {self.label}.itp pro.mdp pro ;cd pro ; cp ../npt/npt.gro . ; {gromacpath} grompp -f pro.mdp  -c npt.gro  -p {self.label}.top -o pro.tpr -maxwarn 1; {gromacpath} mdrun -nt {self.np} -deffnm pro; cd ..\",\n        shell=True,\n    )\n    subprocess.run(f\"cp pro/pro.trr pro/pro.tpr .\", shell=True)\n    process = subprocess.Popen(\n        f\"{gromacpath} current -f pro.trr -s pro.tpr\",\n        stdin=subprocess.PIPE,\n        stdout=subprocess.PIPE,\n        stderr=subprocess.PIPE,\n        universal_newlines=True,\n        shell=True,\n    )\n    process.stdin.write(f\"0\\n\")\n    out, err = process.communicate()\n    open(f\"./{self.label}-constant.out\", \"w\").write(out + \"\\n\" + err)\n    result = open(f\"./{self.label}-constant.out\", \"r\").readlines()\n    for i in range(0, len(result)):\n        if \"Absolute\" in result[i].rstrip().split():\n            constant = result[i + 1].rstrip().split(\"=\")[1]\n            break\n    return float(constant)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/core.html#himatcal.recipes.electrolyte.sol_stru.core.DielectricConstantCal.resp2_chg","title":"resp2_chg","text":"<pre><code>resp2_chg(gas_chk, sol_chk)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/core.py</code> <pre><code>def resp2_chg(self, gas_chk, sol_chk):\n    with open(get_software_json_path(), \"r\") as f:\n        formchkpath = json.load(f)[\"formchk_path\"]\n    subprocess.run(f\"{formchkpath} {self.label}-gas.chk\", shell=True)\n    subprocess.run(f\"{formchkpath} {self.label}-sol.chk\", shell=True)\n    with open(get_software_json_path(), \"r\") as f:\n        multiwfnpath = f\"{json.load(f)['multiwfn_path']}\"\n    process = subprocess.Popen(\n        multiwfnpath,\n        stdin=subprocess.PIPE,\n        stdout=subprocess.PIPE,\n        stderr=subprocess.PIPE,\n        universal_newlines=True,\n    )\n    process.stdin.write(f\"{self.label}-gas.fchk\\n\")\n    process.stdin.write(\"7\\n18\\n1\\ny\\n0\\n0\\nq\\n\")\n    out, err = process.communicate()\n    process = subprocess.Popen(\n        multiwfnpath,\n        stdin=subprocess.PIPE,\n        stdout=subprocess.PIPE,\n        stderr=subprocess.PIPE,\n        universal_newlines=True,\n    )\n    process.stdin.write(f\"{self.label}-sol.fchk\\n\")\n    process.stdin.write(\"7\\n18\\n1\\ny\\n0\\n0\\nq\\n\")\n    out, err = process.communicate()\n    gas_chg = open(f\"{self.label}-gas.chg\", \"r\").readlines()\n    sol_chg = open(f\"{self.label}-sol.chg\", \"r\").readlines()\n    result = \"\"\n    for gas_chg_line, sol_chg_line in zip(gas_chg, sol_chg):\n        gas_chg = float(gas_chg_line.rstrip().split()[4])\n        sol_chg = float(sol_chg_line.rstrip().split()[4])\n        element = gas_chg_line.rstrip().split()[0]\n        x_corr = gas_chg_line.rstrip().split()[1]\n        y_corr = gas_chg_line.rstrip().split()[2]\n        z_corr = gas_chg_line.rstrip().split()[3]\n        chg = (gas_chg + sol_chg) / 2\n        result = result + f\"{element}\\t{x_corr}\\t{y_corr}\\t{z_corr}\\t{chg}\\n\"\n    open(f\"./{self.label}.chg\", \"w\").write(result)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/genFF.html","title":"genFF","text":"<p>generate the GAFF force field with/without the RESP2 charge, better use the chk file form desired level of theory</p>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/genFF.html#himatcal.recipes.electrolyte.sol_stru.genFF.genChk","title":"genChk","text":"<pre><code>genChk(atoms: Atoms, chg: int = 0, mult: int = 1, label='mol')\n</code></pre> <p>generate the check file with the b3lyp/def2tzvp level of theory</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/genFF.py</code> <pre><code>def genChk(atoms: Atoms, chg: int = 0, mult: int = 1, label=\"mol\"):\n    \"\"\"generate the check file with the b3lyp/def2tzvp level of theory\"\"\"\n    # * relax the structure at the b3lyp/6-31G* level\n    result = relax_job(\n        atoms,\n        charge=chg,\n        spin_multiplicity=mult,\n        xc=\"b3lyp\",\n        basis=\"6-31G*\",\n        label=f\"{label}-relax\",\n    )\n    relaxed_atoms = result[\"atoms\"]\n    # * run the single point calculation at the b3lyp/def2tzvp level default\n    static_job_result = static_job(\n        relaxed_atoms,\n        charge=chg,\n        spin_multiplicity=mult,\n        xc=\"b3lyp\",\n        basis=\"def2tzvp\",\n        freq=True,\n        label=f\"{label}-static\",\n    )\n\n    # * get the check file\n    chkfile_path = (\n        Path(static_job_result[\"dir_name\"]) / static_job_result[\"parameters\"][\"chk\"]\n    )\n    gzfile_path = chkfile_path.with_suffix(\".chk.gz\")\n\n    if not chkfile_path.exists() and gzfile_path.exists():\n        subprocess.run([\"gunzip\", str(gzfile_path)], check=True)\n\n    if not chkfile_path.exists():\n        raise FileNotFoundError(f\"Neither {chkfile_path} nor {gzfile_path} exists.\")\n\n    return chkfile_path\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/genFF.html#himatcal.recipes.electrolyte.sol_stru.genFF.genFF","title":"genFF","text":"<pre><code>genFF(atoms: Atoms, chg: int = 0, mult: int = 1, label='mol')\n</code></pre> <p>generate the GAFF force field with the RESP2 charge</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/genFF.py</code> <pre><code>def genFF(atoms: Atoms, chg: int = 0, mult: int = 1, label=\"mol\"):\n    \"\"\"generate the GAFF force field with the RESP2 charge\"\"\"\n    chkfile_path = genChk(atoms, chg, mult, label)\n    fchkfile_path = formchk(chkfile_path)\n    sobtop_genFF(str(fchkfile_path))\n    logging.info(f\"GAFF force field generated for {atoms.get_chemical_formula()}\")\n    # copy the gro,pdb,top and itp files to the current directory\n    for suffix in [\"gro\", \"pdb\", \"top\", \"itp\"]:\n        source = chkfile_path.with_suffix(f\".{suffix}\")\n        target = Path(f\"{label}.{suffix}\")\n        source.replace(target)\n    return {\n        \"atoms\": atoms,\n        \"chkfile_path\": str(chkfile_path),\n        \"grofile_path\": str(chkfile_path.with_suffix(\".gro\")),\n        \"topfile_path\": str(chkfile_path.with_suffix(\".top\")),\n        \"itpfile_path\": str(chkfile_path.with_suffix(\".itp\")),\n    }\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/genFF.html#himatcal.recipes.electrolyte.sol_stru.genFF.genFF_noRESP2","title":"genFF_noRESP2","text":"<pre><code>genFF_noRESP2(atoms: Atoms, label='mol')\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/genFF.py</code> <pre><code>def genFF_noRESP2(atoms: Atoms, label=\"mol\"):\n    obabelpath = SETTINGS.OBABEL_PATH\n    sobtop_path = SETTINGS.SOBTOP_PATH\n    pdbfile_path = Path(f\"{label}.pdb\")\n    topofile_path = Path(f\"{label}.top\")\n    itpfile_path = Path(f\"{label}.itp\")\n    mol2file_path = Path(f\"{label}.mol2\")\n    grofile_path = Path(f\"{label}.gro\")\n\n    atoms.write(\"tmp.pdb\")\n    # * convert the pdb file to mol2 file using obabel\n    subprocess.run(\n        [\n            obabelpath,\n            \"-ipdb\",\n            str(pdbfile_path),\n            \"-omol2\",\n            \"-O\",\n            str(mol2file_path),\n        ],\n        check=True,\n    )\n    # * generate the GAFF force field with the RESP2 charge using sobtop\n    sobtop_command = f\"{mol2file_path}\\n2\\n{grofile_path}\\n1\\n2\\n4{topofile_path}\\n{itpfile_path}\\n0\\n\"\n    subprocess.run([sobtop_path], input=sobtop_command, text=True, check=True)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/genFF.html#himatcal.recipes.electrolyte.sol_stru.genFF.sobtop_genFF","title":"sobtop_genFF","text":"<pre><code>sobtop_genFF(fchk_file: str, chg_file: str | None = None)\n</code></pre> <p>Generate a force field using the Sobtop method from a formatted check file.</p> <p>This function processes a formatted check file by converting it to various molecular formats and generating a GAFF force field with RESP2 charges. It utilizes external tools such as Multiwfn and Open Babel to perform the necessary conversions and calculations.</p> <p>Args:     fchk_file (str): The path to the formatted check file to be processed.     chg_file (str | None): The path to the charge file; if None, a charge file will be generated from the formatted check file.</p> <p>Returns:     None</p> <p>Raises:     subprocess.CalledProcessError: If any of the subprocess commands fail.</p> <p>Examples:     sobtop_genFF(\"path/to/file.fchk\")</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/genFF.py</code> <pre><code>def sobtop_genFF(fchk_file: str, chg_file: str | None = None):\n    \"\"\"\n    Generate a force field using the Sobtop method from a formatted check file.\n\n    This function processes a formatted check file by converting it to various molecular formats and generating a GAFF force field with RESP2 charges. It utilizes external tools such as Multiwfn and Open Babel to perform the necessary conversions and calculations.\n\n    Args:\n        fchk_file (str): The path to the formatted check file to be processed.\n        chg_file (str | None): The path to the charge file; if None, a charge file will be generated from the formatted check file.\n\n    Returns:\n        None\n\n    Raises:\n        subprocess.CalledProcessError: If any of the subprocess commands fail.\n\n    Examples:\n        sobtop_genFF(\"path/to/file.fchk\")\n    \"\"\"\n\n    sobtop_path = SETTINGS.SOBTOP_PATH\n    sobtop_parent_path = Path(sobtop_path).parent\n    multiwfn_path = SETTINGS.MULTIWFN_PATH\n    obabelpath = SETTINGS.OBABEL_PATH\n    pdbfile_path = Path(fchk_file).with_suffix(\".pdb\")\n    mol2file_path = Path(fchk_file).with_suffix(\".mol2\")\n    grofile_path = Path(fchk_file).with_suffix(\".gro\")\n    topofile_path = Path(fchk_file).with_suffix(\".top\")\n    itpfile_path = Path(fchk_file).with_suffix(\".itp\")\n    with cd(str(sobtop_parent_path)):\n        # * convert the fchk file to pdb file using Multiwfn\n        subprocess.run(\n            [multiwfn_path],\n            input=f\"{fchk_file}\\n100\\n2\\n1\\n{pdbfile_path}\\n0\\nq\\n\",\n            text=True,\n            check=True,\n        )\n\n        # * convert the pdb file to mol2 file using obabel\n        subprocess.run(\n            [\n                obabelpath,\n                \"-ipdb\",\n                str(pdbfile_path),\n                \"-omol2\",\n                \"-O\",\n                str(mol2file_path),\n            ],\n            check=True,\n        )\n\n        # * generate the GAFF force field with the RESP2 charge using sobtop\n        chg_file = str(gen_resp2_chg(fchk_file)) if chg_file is None else str(chg_file)\n        sobtop_command = f\"{mol2file_path}\\n7\\n10\\n{chg_file}\\n0\\n2\\n{grofile_path}\\n1\\n2\\n7\\n{fchk_file}\\n{topofile_path}\\n{itpfile_path}\\n0\\n\"\n        subprocess.run([sobtop_path], input=sobtop_command, text=True, check=True)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html","title":"md","text":""},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.mdp_min","title":"mdp_min  <code>module-attribute</code>","text":"<pre><code>mdp_min = '\\ntitle                      = minimization\\n; run control\\nintegrator                 = steep      ; steepest descents minimization\\nemtol                      = 100        ; stop when max force &lt; 100.0 kJ/mol/nm\\nemstep                     = 0.01       ; energy step size\\nnsteps                     = 50000     ; max number of steps\\n; output control\\nnstxout                    = 1000       ; steps per position save\\nnstlog                     = 1000       ; steps per log entry\\nnstenergy                  = 1000       ; steps per energy file entry\\n; cutoffs\\ncutoff-scheme              = Verlet     ; Buffered neighbor searching\\nnstlist                    = 10         ; neighbor list update frequency\\nns_type                    = grid       ; neighbor list method (simple, grid)\\npbc                        = xyz        ; periodic boundary conditions\\ncoulombtype                = PME        ; method for electrostatics\\nrcoulomb                   = 1.2        ; Short-range electrostatic cutoff\\nrvdw                       = 1.2        ; van der Waals cutoff\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.mdp_npt1","title":"mdp_npt1  <code>module-attribute</code>","text":"<pre><code>mdp_npt1 = 'title                     = 0.1ns npt berendsen\\n; run control\\nintegrator                = md\\ndt                        = 0.001            ; 1 fs\\nnsteps                    = 10000        ; steps, 0.1ns\\n; Ooutput control\\nnstxout                   = 0\\nnstvout                   = 0\\nnstfout                   = 0\\nnstlog                    = 5000\\nnstenergy                 = 1000\\nnstxout-compressed        = 1000\\n;Vel\\ngen_vel                   = no              ; generate velocities\\n;gen_temp                  = 300\\n;gen_seed                  = -1\\n; cutoffs\\ncutoff-scheme             = Verlet\\npbc                       = xyz         ; periodic boundary conditions\\ncoulombtype               = PME        ; method for electrostatics\\nrcoulomb                  = 1.0        ; Short-range electrostatic cutoff\\nrvdw                      = 1.0        ; van der Waals cutoff\\nDispCorr                  = EnerPres    ; long-distance contributions to E, P\\n; temperature control\\ntcoupl                    = v-rescale ; velocity rescaling thermostat\\ntc_grps                   = system    ; coupled to entire system\\ntau_t                     = 0.2        ; time constant\\nref_t                     = 298.15        ; temperature (K)\\n; pressure control\\npcoupl                    = C-rescale ; barostat type: Parrinello-Rahman, berendsen,\\npcoupltype                = isotropic\\ntau_p                     = 4            ; time constant\\nref_p                     = 1.0            ; pressure (bar)\\ncompressibility           = 5e-5        ; pressure bath compressibility (of water, bar^-1)\\n; bond parameters\\ncontinuation              = yes            ; restart from NVT\\n; constraints               = hbonds            ; h-bond lengths constrained\\n; constraint_algorithm      = LINCS    ; constraint method\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.mdp_npt2","title":"mdp_npt2  <code>module-attribute</code>","text":"<pre><code>mdp_npt2 = '\\ntitle                     = 1ns npt berendsen 1.8T annealing 0.25ns 500K 0.25ns 298K\\n; run control\\nintegrator                = md\\ndt                        = 0.001          ; 1 fs\\nnsteps                    = 1000000        ; steps, 1 ns\\n; Ooutput control\\nnstxout                   = 0\\nnstvout                   = 0\\nnstfout                   = 0\\nnstlog                    = 5000\\nnstenergy                 = 1000\\nnstxout-compressed        = 1000\\n;Vel\\ngen_vel                   = no             ; generate velocities\\n;gen_temp                  = 300\\n;gen_seed                  = -1\\n; cutoffs\\ncutoff-scheme             = Verlet\\npbc                       = xyz            ; periodic boundary conditions\\ncoulombtype               = PME            ; method for electrostatics\\nrcoulomb                  = 1.0            ; Short-range electrostatic cutoff\\nrvdw                      = 1.0            ; van der Waals cutoff\\nDispCorr                  = EnerPres       ; long-distance contributions to E, P\\n; temperature control\\ntcoupl                    = v-rescale      ; velocity rescaling thermostat\\ntc_grps                   = system         ; coupled to entire system\\ntau_t                     = 0.2            ; time constant\\nref_t                     = 298.15            ; temperature (K)\\n; pressure control\\npcoupl                    = Parrinello-Rahman ; barostat type: Parrinello-Rahman, berendsen,\\npcoupltype                = isotropic\\ntau_p                     = 4               ; time constant\\nref_p                     = 1.0             ; pressure (bar)\\ncompressibility           = 5e-5            ; pressure bath compressibility (of water, bar^-1)\\n; bond parameters\\ncontinuation              = yes             ; restart from NVT\\n; constraints               = hbonds        ; h-bond lengths constrained\\n; constraint_algorithm      = LINCS         ; constraint method\\n\\n; annealing\\nannealing                 = single          ; single or double\\nannealing_npoints         = 4               ; number of points\\nannealing_time            = 0 250 500 750       ; time points\\nannealing_temp            = 298.15 500 500 298.15  ; temperature points\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.mdp_npt3","title":"mdp_npt3  <code>module-attribute</code>","text":"<pre><code>mdp_npt3 = '\\ntitle                     = 1ns npt Parrinello-Rahman\\n; run control\\nintegrator                = md\\ndt                        = 0.001            ; 1 fs\\nnsteps                    = 1000000        ; steps, 1ns\\n; Ooutput control\\nnstxout                   = 0\\nnstvout                   = 0\\nnstfout                   = 0\\nnstlog                    = 5000\\nnstenergy                 = 1000\\nnstxout-compressed        = 1000\\n;Vel\\ngen_vel                   = no\\n;gen_temp                 = 300\\n;gen_seed                 = -1\\n; cutoffs\\ncutoff-scheme             = Verlet\\npbc                       = xyz         ; periodic boundary conditions\\ncoulombtype               = PME        ; method for electrostatics\\nrcoulomb                  = 1.0        ; Short-range electrostatic cutoff\\nrvdw                      = 1.0        ; van der Waals cutoff\\nDispCorr                  = EnerPres    ; long-distance contributions to E, P\\n; temperature control\\ntcoupl                    = v-rescale ; velocity rescaling thermostat\\ntc_grps                   = system    ; coupled to entire system\\ntau_t                     = 0.2        ; time constant\\nref_t                     = 298.15        ; temperature (K)\\n; pressure control\\npcoupl                    = Parrinello-Rahman ; barostat type: Parrinello-Rahman, berendsen,\\npcoupltype                = isotropic\\ntau_p                     = 4            ; time constant\\nref_p                     = 1.0            ; pressure (bar)\\ncompressibility           = 5e-5        ; pressure bath compressibility (of water, bar^-1)\\n; bond parameters\\ncontinuation              = yes            ; restart from NVT\\n;constraints              = hbonds            ; h-bond lengths constrained\\n;constraint_algorithm     = LINCS    ; constraint method\\n\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.mdp_nvt1","title":"mdp_nvt1  <code>module-attribute</code>","text":"<pre><code>mdp_nvt1 = 'title                     = 0.01 ns NVT\\n; Start time and timestep in ps\\nintegrator                = md\\nnsteps                    = 10000   ; 10 ps\\ndt                        = 0.001   ; set timestep to 1fs\\nnstxout\\t                  = 0\\nnstvout\\t                  = 0\\nnstenergy                 = 5000\\nnstlog                    = 5000\\ncontinuation              = no      ; first dynamics run\\nconstraint_algorithm      = Lincs   ; holonomic constraints\\nconstraints               = none    ; no constraints\\nlincs_iter                = 1\\nlincs_order               = 4\\n; cutoffs\\ncutoff-scheme             = Verlet\\nns_type                   = grid\\nnstlist                   = 10\\nrcoulomb                  = 1\\nrvdw                      = 1\\ncoulombtype               = PME\\npme_order                 = 4\\nfourierspacing            = 0.16\\n; OPTIONS FOR WEAK COUPLING ALGORITHMS\\n; Temperature coupling\\nTcoupl                    = V-rescale\\nnsttcouple                = -1\\nnh-chain-length           = 1\\n; Groups to couple separately\\ntc-grps                   = System\\n; Time constant (ps) and reference temperature (K)\\ntau_t                     = 1\\nref_t                     = 298.15\\n; Pressure coupling\\nPcoupl                    = no\\nPcoupltype                = isotropic\\n; Time constant (ps), compressibility (1/bar) and reference P (bar)\\ntau_p                     = 0.5\\ncompressibility           = 5e-5\\nref_p                     = 1.\\nrefcoord_scaling          = com\\npbc                       = xyz\\nDispcorr                  = Enerpres\\ngen_vel                   = no\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.slurm_title","title":"slurm_title  <code>module-attribute</code>","text":"<pre><code>slurm_title = '#!/bin/bash\\n#SBATCH -J gmx   ##\u4f5c\u4e1a\u540d\\n#SBATCH -p normal   ##\u961f\u5217\\n#SBATCH -n 4  ##\u6bcf\u8282\u70b9\u8fdb\u7a0b\u6570\\n\\nsource /usr/local/gromacs/bin/GMXRC.bash\\n'\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.build_box","title":"build_box","text":"<pre><code>build_box(data, compound_dict, mol_path)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def build_box(data, compound_dict, mol_path):\n    from himatcal.recipes.electrolyte.sol_stru.build_box import ElectrolyteBuilder\n\n    density = data[\"density\"]\n    box = data[\"box\"]\n    capital = True\n\n    builder = ElectrolyteBuilder(mol_path=mol_path)\n    builder.build_box(\n        box_electrolyte_composition=compound_dict,\n        density=density,\n        box=box,\n        save_path=\"init.pdb\",\n        capital=capital,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.gmx_min","title":"gmx_min","text":"<pre><code>gmx_min(pdb_file: str, submit_job=False, **calc_kwards) -&gt; None\n</code></pre> <p>Run Gromacs minimization</p> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def gmx_min(pdb_file: str, submit_job=False, **calc_kwards) -&gt; None:\n    \"\"\"\n    Run Gromacs minimization\n    \"\"\"\n    # Define file paths\n    mdp_path = Path(\"min.mdp\")\n    slurm_path = Path(\"min.slurm\")\n    pdb_path = Path(\"init.pdb\")\n\n    # Write the mdp file\n    mdp_path.write_text(mdp_min)\n\n    # Write the slurm file\n    slurm_path.write_text(slurm_title + slurm_min())\n\n    # Write the pdb file\n    pdb_path.write_text(pdb_file)\n\n    # * check the topo file\n    if not Path(\"topol.top\").exists():\n        raise FileNotFoundError(\n            \"topol.top file not found, please run gmx_write_topo() first\"\n        )\n\n    # Run the slurm job\n    if submit_job:\n        subprocess.run([\"sbatch\", str(slurm_path)], check=True, text=True)\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.gmx_solvation_md","title":"gmx_solvation_md","text":"<pre><code>gmx_solvation_md(yaml_file, submit_job=False)\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def gmx_solvation_md(yaml_file, submit_job=False):\n    with Path.open(Path(yaml_file)) as f:\n        data = yaml.safe_load(f)\n        compound_dict = data[\"compound_dict\"]\n        mdp_files = data[\"mdp_files\"]\n        build_pdb = data[\"build_pdb\"]\n        mol_path = data[\"pdb_folder\"]\n        itp_folder = data[\"itp_folder\"]\n\n    # * write the pdb file\n    if build_pdb:\n        build_box(data, compound_dict, mol_path)\n    else:\n        pdb_file = data[\"pdb_file\"]\n        # * copy  pdb_file to init.pdb\n        Path(pdb_file).rename(\"init.pdb\")\n\n    # * write the topol.top file\n    gmx_write_topo(compound_dict, itp_folder)\n\n    # * write the mdp files from the list\n    for mdp_file in mdp_files:\n        mdp_path = Path(f\"{mdp_file}.mdp\")\n        if mdp_file == \"min\":\n            mdp_path.write_text(mdp_min)\n        elif mdp_file == \"nvt1\":\n            mdp_path.write_text(mdp_nvt1)\n        elif mdp_file == \"npt1\":\n            mdp_path.write_text(mdp_npt1)\n        elif mdp_file == \"npt2\":\n            mdp_path.write_text(mdp_npt2)\n        elif mdp_file == \"npt3\":\n            mdp_path.write_text(mdp_npt3)\n        else:\n            raise ValueError(f\"mdp file {mdp_file} not found\")\n\n    # * write the slurm file for each step in the list\n    slurm_path = Path(\"md.slurm\")\n    slurm_content = slurm_title\n    if \"min\" in mdp_files:\n        slurm_content = slurm_content + slurm_min()\n    for i in range(len(mdp_files) - 1):\n        slurm_content = slurm_content + slurm_md(mdp_files[i], mdp_files[i + 1])\n    slurm_path.write_text(slurm_content)\n\n    # Run the slurm job\n    if submit_job:\n        result = subprocess.run(\n            [\"sbatch\", str(slurm_path)], check=True, text=True, capture_output=True\n        )\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.gmx_write_topo","title":"gmx_write_topo","text":"<pre><code>gmx_write_topo(compound_dict, itp_folder: str = None) -&gt; None\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def gmx_write_topo(compound_dict, itp_folder: str = None) -&gt; None:\n    with Path(\"topol.top\").open(\"w\") as f:\n        f.write(\"[ defaults ]\\n\")\n        f.write(\"  ;nbfunc  comb-rule  gen-pairs  fudgeLJ  fudgeQQ\\n\")\n        f.write(\"    1        3          yes        0.5      0.5\\n\")\n        f.write(f'#include \"{itp_folder}/head.itp\"\\n')\n        for compound in compound_dict:\n            f.write(f'#include \"{itp_folder}/{compound}.itp\"\\n')\n        f.write(\"\\n\\n[ system ]\")\n        f.write(\"\\n; Name\\n\")\n        for compound in compound_dict:\n            f.write(f\"{compound}-\")\n        f.write(\"\\n[ molecules ]\\n\")\n        f.write(\"; Compound        #mols\\n\")\n        for compound in compound_dict:\n            f.write(f'{compound}           {compound_dict[compound][\"mol\"]}\\n')\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.slurm_md","title":"slurm_md","text":"<pre><code>slurm_md(pre_step: str = 'min', current_step: str = 'nvt1') -&gt; str\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def slurm_md(pre_step: str = \"min\", current_step: str = \"nvt1\") -&gt; str:\n    return f\"\"\"# gromacs {current_step}\n## generate the tpr file for gromacs\ngmx grompp -f {current_step}.mdp -c {pre_step}.gro -o {current_step}.tpr\n## run gromacs\nmpirun -np 2 gmx mdrun -nt 4 -ntomp 2 -v -deffnm {current_step}\n\n\"\"\"\n</code></pre>"},{"location":"reference/himatcal/recipes/electrolyte/sol_stru/md.html#himatcal.recipes.electrolyte.sol_stru.md.slurm_min","title":"slurm_min","text":"<pre><code>slurm_min(pre_step: str = 'init.pdb', current_step: str = 'min') -&gt; str\n</code></pre> Source code in <code>himatcal/recipes/electrolyte/sol_stru/md.py</code> <pre><code>def slurm_min(pre_step: str = \"init.pdb\", current_step: str = \"min\") -&gt; str:\n    return f\"\"\"# gromacs minimization\n## generate the tpr file for gromacs\ngmx editconf -f {pre_step} -o conf.gro\ngmx grompp -f {current_step}.mdp -o {current_step}.tpr\n## run gromacs\nmpirun -np 2 gmx mdrun -nt 4 -ntomp 2 -deffnm min\n\n\"\"\"\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/_base.html","title":"_base","text":"<p>Base jobs for Gaussian.</p>"},{"location":"reference/himatcal/recipes/gaussian/_base.html#himatcal.recipes.gaussian._base.run_and_summarize","title":"run_and_summarize","text":"<pre><code>run_and_summarize(atoms: Atoms, charge: int = 0, spin_multiplicity: int = 1, label: str = 'Gaussian', calc_defaults: dict[str, Any] | None = None, calc_swaps: dict[str, Any] | None = None, additional_fields: dict[str, Any] | None = None, copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None) -&gt; RunSchema\n</code></pre> <p>Base job function for carrying out Gaussian recipes.</p> <p>Parameters:</p> <ul> <li> <code>atoms</code>               (<code>Atoms</code>)           \u2013            <p>Atoms object</p> </li> <li> <code>charge</code>               (<code>int</code>, default:                   <code>0</code> )           \u2013            <p>Charge of the system.</p> </li> <li> <code>spin_multiplicity</code>               (<code>int</code>, default:                   <code>1</code> )           \u2013            <p>Multiplicity of the system.</p> </li> <li> <code>label</code>               (<code>str</code>, default:                   <code>'Gaussian'</code> )           \u2013            <p>Label for the calculation</p> </li> <li> <code>calc_defaults</code>               (<code>dict[str, Any] | None</code>, default:                   <code>None</code> )           \u2013            <p>Default parameters for the calculator.</p> </li> <li> <code>calc_swaps</code>               (<code>dict[str, Any] | None</code>, default:                   <code>None</code> )           \u2013            <p>Dictionary of custom kwargs for the Gaussian calculator. Set a value to <code>quacc.Remove</code> to remove a pre-existing key entirely. For a list of available keys, refer to the ase.calculators.gaussian.Gaussian calculator.</p> </li> <li> <code>additional_fields</code>               (<code>dict[str, Any] | None</code>, default:                   <code>None</code> )           \u2013            <p>Additional fields to supply to the summarizer.</p> </li> <li> <code>copy_files</code>               (<code>SourceDirectory | dict[SourceDirectory, Filenames] | None</code>, default:                   <code>None</code> )           \u2013            <p>Files to copy (and decompress) from source to the runtime directory.</p> </li> </ul> <p>Returns:</p> <ul> <li> <code> RunSchema</code>           \u2013            <p>Dictionary of results</p> </li> </ul> Source code in <code>himatcal/recipes/gaussian/_base.py</code> <pre><code>def run_and_summarize(\n    atoms: Atoms,\n    charge: int = 0,\n    spin_multiplicity: int = 1,\n    label: str = \"Gaussian\",\n    calc_defaults: dict[str, Any] | None = None,\n    calc_swaps: dict[str, Any] | None = None,\n    additional_fields: dict[str, Any] | None = None,\n    copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None,\n) -&gt; RunSchema:\n    \"\"\"\n    Base job function for carrying out Gaussian recipes.\n\n    Parameters\n    ----------\n    atoms\n        Atoms object\n    charge\n        Charge of the system.\n    spin_multiplicity\n        Multiplicity of the system.\n    label\n        Label for the calculation\n    calc_defaults\n        Default parameters for the calculator.\n    calc_swaps\n        Dictionary of custom kwargs for the Gaussian calculator. Set a value to\n        `quacc.Remove` to remove a pre-existing key entirely. For a list of available\n        keys, refer to the [ase.calculators.gaussian.Gaussian][] calculator.\n    additional_fields\n        Additional fields to supply to the summarizer.\n    copy_files\n        Files to copy (and decompress) from source to the runtime directory.\n\n    Returns\n     -------\n     RunSchema\n         Dictionary of results\n    \"\"\"\n    settings = get_settings()\n    GAUSSIAN_CMD = f\"{settings.GAUSSIAN_CMD} &lt; {label}.com &gt; {label}.log\"\n    calc_flags = recursive_dict_merge(calc_defaults, calc_swaps)\n\n    calc = Gaussian(command=GAUSSIAN_CMD, label=label, **calc_flags)\n    final_atoms = Runner(atoms, calc, copy_files=copy_files).run_calc(\n        geom_file=f\"{label}.log\"\n    )\n\n    return Summarize(\n        charge_and_multiplicity=(charge, spin_multiplicity),\n        additional_fields=additional_fields,\n    ).run(final_atoms, atoms)\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/gaussian/core.html#himatcal.recipes.gaussian.core.relax_job","title":"relax_job","text":"<pre><code>relax_job(atoms: Atoms, charge: int, spin_multiplicity: int, label: str = 'relax', xc: str = 'wb97xd', basis: str = 'def2tzvp', freq: bool = False, copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None, **calc_kwargs) -&gt; RunSchema\n</code></pre> <p>Run a Gaussian relaxation calculation.</p> <p>Args:     atoms: Atoms - The atoms for the calculation.     charge: int - The charge of the system.     spin_multiplicity: int - The spin multiplicity of the system.     label: str - (Optional) The label for the calculation (default is \"relax\").     xc: str - (Optional) The exchange-correlation functional to use (default is \"wb97xd\").     basis: str - (Optional) The basis set to use (default is \"def2tzvp\").     freq: bool - (Optional) Whether to perform frequency calculations (default is False).     copy_files: Union[SourceDirectory, dict[SourceDirectory, Filenames], None] - (Optional) Files to copy after the calculation.     **calc_kwargs - Additional keyword arguments for the calculation.</p> <p>Returns:     RunSchema - The summarized result of the Gaussian relaxation calculation.</p> Source code in <code>himatcal/recipes/gaussian/core.py</code> <pre><code>@job\ndef relax_job(\n    atoms: Atoms,\n    charge: int,\n    spin_multiplicity: int,\n    label: str = \"relax\",\n    xc: str = \"wb97xd\",\n    basis: str = \"def2tzvp\",\n    freq: bool = False,\n    copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None,\n    **calc_kwargs,\n) -&gt; RunSchema:\n    \"\"\"\n    Run a Gaussian relaxation calculation.\n\n    Args:\n        atoms: Atoms - The atoms for the calculation.\n        charge: int - The charge of the system.\n        spin_multiplicity: int - The spin multiplicity of the system.\n        label: str - (Optional) The label for the calculation (default is \"relax\").\n        xc: str - (Optional) The exchange-correlation functional to use (default is \"wb97xd\").\n        basis: str - (Optional) The basis set to use (default is \"def2tzvp\").\n        freq: bool - (Optional) Whether to perform frequency calculations (default is False).\n        copy_files: Union[SourceDirectory, dict[SourceDirectory, Filenames], None] - (Optional) Files to copy after the calculation.\n        **calc_kwargs - Additional keyword arguments for the calculation.\n\n    Returns:\n        RunSchema - The summarized result of the Gaussian relaxation calculation.\n    \"\"\"\n\n    calc_defaults = {\n        \"mem\": \"64GB\",\n        \"chk\": \"Gaussian.chk\",\n        \"nprocshared\": psutil.cpu_count(logical=False),\n        \"xc\": xc,\n        \"basis\": basis,\n        \"charge\": charge,\n        \"mult\": spin_multiplicity,\n        \"opt\": \"\",\n        \"pop\": \"CM5\",\n        \"scf\": [\"maxcycle=250\", \"xqc\"],\n        \"integral\": \"ultrafine\",\n        \"nosymmetry\": \"\",\n        \"ioplist\": [\"2/9=2000\"], # ASE issue #660\n    }\n    if freq:\n        calc_defaults[\"freq\"] = \"\"\n\n    return run_and_summarize(\n        atoms,\n        charge=charge,\n        spin_multiplicity=spin_multiplicity,\n        label=label,\n        calc_defaults=calc_defaults,\n        calc_swaps=calc_kwargs,\n        additional_fields={\"name\": \"Gaussian Relax\"},\n        copy_files=copy_files,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/core.html#himatcal.recipes.gaussian.core.static_job","title":"static_job","text":"<pre><code>static_job(atoms: Atoms, charge: int = 0, spin_multiplicity: int = 1, label: str = 'static', xc: str = 'wb97xd', basis: str = 'def2tzvp', freq: bool = True, copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None, **calc_kwargs) -&gt; RunSchema\n</code></pre> <p>Carry out a single-point calculation.</p> <p>Parameters:</p> <ul> <li> <code>atoms</code>               (<code>Atoms</code>)           \u2013            <p>Atoms object</p> </li> <li> <code>charge</code>               (<code>int</code>, default:                   <code>0</code> )           \u2013            <p>Charge of the system.</p> </li> <li> <code>spin_multiplicity</code>               (<code>int</code>, default:                   <code>1</code> )           \u2013            <p>Multiplicity of the system.</p> </li> <li> <code>xc</code>               (<code>str</code>, default:                   <code>'wb97xd'</code> )           \u2013            <p>Exchange-correlation functional</p> </li> <li> <code>basis</code>               (<code>str</code>, default:                   <code>'def2tzvp'</code> )           \u2013            <p>Basis set</p> </li> <li> <code>copy_files</code>               (<code>SourceDirectory | dict[SourceDirectory, Filenames] | None</code>, default:                   <code>None</code> )           \u2013            <p>Files to copy (and decompress) from source to the runtime directory.</p> </li> <li> <code>**calc_kwargs</code>           \u2013            <p>Custom kwargs for the Gaussian calculator. Set a value to <code>quacc.Remove</code> to remove a pre-existing key entirely. For a list of available keys, refer to the ase.calculators.gaussian.Gaussian calculator.</p> </li> </ul> <p>Returns:</p> <ul> <li> <code>RunSchema</code>           \u2013            <p>Dictionary of results</p> </li> </ul> Source code in <code>himatcal/recipes/gaussian/core.py</code> <pre><code>@job\ndef static_job(\n    atoms: Atoms,\n    charge: int = 0,\n    spin_multiplicity: int = 1,\n    label: str = \"static\",\n    xc: str = \"wb97xd\",\n    basis: str = \"def2tzvp\",\n    freq: bool = True,\n    copy_files: SourceDirectory | dict[SourceDirectory, Filenames] | None = None,\n    **calc_kwargs,\n) -&gt; RunSchema:\n    \"\"\"\n    Carry out a single-point calculation.\n\n    Parameters\n    ----------\n    atoms\n        Atoms object\n    charge\n        Charge of the system.\n    spin_multiplicity\n        Multiplicity of the system.\n    xc\n        Exchange-correlation functional\n    basis\n        Basis set\n    copy_files\n        Files to copy (and decompress) from source to the runtime directory.\n    **calc_kwargs\n        Custom kwargs for the Gaussian calculator. Set a value to\n        `quacc.Remove` to remove a pre-existing key entirely. For a list of available\n        keys, refer to the [ase.calculators.gaussian.Gaussian][] calculator.\n\n    Returns\n    -------\n    RunSchema\n        Dictionary of results\n    \"\"\"\n    calc_defaults = {\n        \"mem\": \"16GB\",\n        \"chk\": \"Gaussian.chk\",\n        \"nprocshared\": psutil.cpu_count(logical=False),\n        \"xc\": xc,\n        \"basis\": basis,\n        \"charge\": charge,\n        \"mult\": spin_multiplicity,\n        # \"force\": \"\",\n        \"scf\": [\"maxcycle=250\", \"xqc\"],\n        \"integral\": \"ultrafine\",\n        \"nosymmetry\": \"\",\n        \"pop\": \"CM5\",\n        \"gfinput\": \"\",\n        \"ioplist\": [\"6/7=3\", \"2/9=2000\"],  # see ASE issue #660\n    }\n    if freq:\n        calc_defaults[\"freq\"] = \"\"\n\n    return run_and_summarize(\n        atoms,\n        charge=charge,\n        spin_multiplicity=spin_multiplicity,\n        label=label,\n        calc_defaults=calc_defaults,\n        calc_swaps=calc_kwargs,\n        additional_fields={\"name\": \"Gaussian Static\"},\n        copy_files=copy_files,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html","title":"flow","text":"<p>recipes for gaussian calculation</p>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.Logger","title":"Logger  <code>module-attribute</code>","text":"<pre><code>Logger = getLogger(__name__)\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy","title":"calc_free_energy","text":"<pre><code>calc_free_energy(atoms, charge=0, mult=1, label='Gaussian', relax=False, solvent='acetone', relax_stage1_params=None)\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def __init__(\n    self,\n    atoms,\n    charge=0,\n    mult=1,\n    label=\"Gaussian\",\n    relax=False,\n    solvent=\"acetone\",\n    relax_stage1_params=None,\n):\n    self.atoms = atoms\n    self.charge = charge\n    self.mult = mult\n    self.label = label\n    self.relax = relax\n    self.solvent = solvent\n\n    if relax_stage1_params:\n        self.relax_stage1_params = relax_stage1_params\n    else:\n        # * 1. relax at 6-31G(d) level\n        self.relax_stage1_params = {\n            \"xc\": \"B3LYP\",\n            \"basis\": \"6-31G(d)\",\n            \"label\": f\"{self.label}\",\n        }\n        if self.solvent:\n            self.relax_stage1_params[\"scrf\"] = f\"pcm, solvent={self.solvent}\"\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.atoms","title":"atoms  <code>instance-attribute</code>","text":"<pre><code>atoms = atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.charge","title":"charge  <code>instance-attribute</code>","text":"<pre><code>charge = charge\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.label","title":"label  <code>instance-attribute</code>","text":"<pre><code>label = label\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.mult","title":"mult  <code>instance-attribute</code>","text":"<pre><code>mult = mult\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.relax","title":"relax  <code>instance-attribute</code>","text":"<pre><code>relax = relax\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.relax_stage1_params","title":"relax_stage1_params  <code>instance-attribute</code>","text":"<pre><code>relax_stage1_params = relax_stage1_params\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.solvent","title":"solvent  <code>instance-attribute</code>","text":"<pre><code>solvent = solvent\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.extract_free_energy","title":"extract_free_energy","text":"<pre><code>extract_free_energy()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def extract_free_energy(self):\n    if not hasattr(self, \"result\"):\n        raise AttributeError(\"Please run the calculation first!\")\n\n    log_path = Path(self.result[\"dir_name\"])\n    with contextlib.suppress(FileNotFoundError):\n        return self._extracted_from_extract_free_energy(log_path)\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.relax_stage1","title":"relax_stage1","text":"<pre><code>relax_stage1()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def relax_stage1(self):\n    result = relax_job(\n        self.atoms,\n        charge=self.charge,\n        spin_multiplicity=self.mult,\n        **self.relax_stage1_params,\n    )\n    self.atoms = result[\"atoms\"]\n    return self.atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.relax_stage2","title":"relax_stage2","text":"<pre><code>relax_stage2()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def relax_stage2(self):\n    # * 2. relax at 6-311+g(d) level\n    calc_params = {\n        \"xc\": \"B3LYP\",\n        \"basis\": \"6-311+g(d) em=GD3BJ\",\n        \"label\": f\"{self.label}\",\n    }\n    if self.solvent:\n        calc_params[\"scrf\"] = f\"pcm, solvent={self.solvent}\"\n    result = relax_job(\n        self.atoms,\n        charge=self.charge,\n        spin_multiplicity=self.mult,\n        freq=True,\n        **calc_params,\n    )\n    self.atoms = result[\"atoms\"]\n    return self.atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.run","title":"run","text":"<pre><code>run()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def run(self):\n    if self.relax:\n        # * 1. relax at 6-31G(d) level\n        self.relax_stage1()\n        # * 2. relax at 6-311+g(d) level\n        self.relax_stage2()\n        # * write relaxed atoms to file\n        self.write_relaxed()\n    # * 3. Single point calculation and get the free energy.\n    result = self.single_point()\n    self.result = result\n    return result\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.single_point","title":"single_point","text":"<pre><code>single_point()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def single_point(self):\n    calc_params = {\n        \"xc\": \"B3LYP\",\n        \"basis\": \"6-311+g(d) em=GD3BJ\",\n        \"scrf\": \"pcm, solvent=acetone\",\n        \"label\": f\"{self.label}\",\n        \"freq\": \"\",\n    }\n    if self.solvent:\n        calc_params[\"scrf\"] = f\"pcm, solvent={self.solvent}\"\n    return static_job(\n        self.atoms, charge=self.charge, spin_multiplicity=self.mult, **calc_params\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gaussian/flow.html#himatcal.recipes.gaussian.flow.calc_free_energy.write_relaxed","title":"write_relaxed","text":"<pre><code>write_relaxed()\n</code></pre> Source code in <code>himatcal/recipes/gaussian/flow.py</code> <pre><code>def write_relaxed(self):\n    from ase.io import write\n\n    from himatcal.utils.os import write_chg_mult_label\n\n    relaxed_filename = write_chg_mult_label(\n        f\"{self.label}_relaxed\", self.charge, self.mult\n    )\n    write(f\"{relaxed_filename}.xyz\", self.atoms)\n    return self.atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html","title":"DE_GSM","text":""},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM","title":"ASE_DE_GSM","text":"<pre><code>ASE_DE_GSM(reactant: Atoms | str | Any = None, product: Atoms | str | Any = None, calculator: Calculator | Any = None, multiplicity: int = 1, fixed_reactant: bool | Any = False, fixed_product: bool | Any = False, coordinate_type: Literal['TRIC', 'DLC', 'HDLC'] | Any = 'TRIC', optimizer_method: Literal['eigenvector_follow', 'lbfgs'] | Any = 'eigenvector_follow', num_of_nodes: int | Any = 11, line_search: Literal['NoLineSearch', 'backtrack'] | Any = 'NoLineSearch', conv_Ediff: float | Any = 100.0, conv_gmax: float | Any = 100.0, DMAX: float | Any = 0.1, ID: int = 0, r_type: Literal[0, 1, 2] | Any = 1, max_gsm_iterations: int = 50, max_opt_steps: int = 3)\n</code></pre> Source code in <code>himatcal/recipes/gsm/DE_GSM.py</code> <pre><code>def __init__(self,\n                reactant: Atoms | str | Any = None,\n                product: Atoms | str | Any = None,\n                calculator: Calculator | Any = None,\n                multiplicity: int = 1,\n                fixed_reactant: bool | Any = False,\n                fixed_product: bool | Any = False,\n                coordinate_type: Literal[\"TRIC\", \"DLC\", \"HDLC\"] | Any = \"TRIC\",\n                optimizer_method: Literal[\"eigenvector_follow\", \"lbfgs\"] | Any = \"eigenvector_follow\",\n                num_of_nodes: int | Any = 11,\n                line_search: Literal[\"NoLineSearch\", \"backtrack\"] | Any = \"NoLineSearch\",\n                conv_Ediff: float | Any = 100.0,\n                conv_gmax: float | Any = 100.0,\n                DMAX: float | Any = 0.1,\n                ID: int = 0,\n                r_type: Literal[0, 1, 2] | Any = 1,\n                max_gsm_iterations: int = 50,\n                max_opt_steps: int = 3):\n        self.reactant = reactant\n        self.product = product\n        self.calculator = calculator\n        self.multiplicity = multiplicity\n        self.fixed_reactant = fixed_reactant\n        self.fixed_product = fixed_product\n        self.coordinate_type = coordinate_type\n        self.optimizer_method = optimizer_method\n        self.num_of_nodes = num_of_nodes\n        self.line_search = line_search\n        self.conv_Ediff = conv_Ediff\n        self.conv_gmax = conv_gmax\n        self.DMAX = DMAX\n        self.ID = ID\n        self.r_type = r_type\n        self.max_gsm_iterations = max_gsm_iterations\n        self.max_opt_steps = max_opt_steps\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.DMAX","title":"DMAX  <code>instance-attribute</code>","text":"<pre><code>DMAX = DMAX\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.ID","title":"ID  <code>instance-attribute</code>","text":"<pre><code>ID = ID\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.calculator","title":"calculator  <code>instance-attribute</code>","text":"<pre><code>calculator = calculator\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.conv_Ediff","title":"conv_Ediff  <code>instance-attribute</code>","text":"<pre><code>conv_Ediff = conv_Ediff\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.conv_gmax","title":"conv_gmax  <code>instance-attribute</code>","text":"<pre><code>conv_gmax = conv_gmax\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.coordinate_type","title":"coordinate_type  <code>instance-attribute</code>","text":"<pre><code>coordinate_type = coordinate_type\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.fixed_product","title":"fixed_product  <code>instance-attribute</code>","text":"<pre><code>fixed_product = fixed_product\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.fixed_reactant","title":"fixed_reactant  <code>instance-attribute</code>","text":"<pre><code>fixed_reactant = fixed_reactant\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.line_search","title":"line_search  <code>instance-attribute</code>","text":"<pre><code>line_search = line_search\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.max_gsm_iterations","title":"max_gsm_iterations  <code>instance-attribute</code>","text":"<pre><code>max_gsm_iterations = max_gsm_iterations\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.max_opt_steps","title":"max_opt_steps  <code>instance-attribute</code>","text":"<pre><code>max_opt_steps = max_opt_steps\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.multiplicity","title":"multiplicity  <code>instance-attribute</code>","text":"<pre><code>multiplicity = multiplicity\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.num_of_nodes","title":"num_of_nodes  <code>instance-attribute</code>","text":"<pre><code>num_of_nodes = num_of_nodes\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.optimizer_method","title":"optimizer_method  <code>instance-attribute</code>","text":"<pre><code>optimizer_method = optimizer_method\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.product","title":"product  <code>instance-attribute</code>","text":"<pre><code>product = product\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.r_type","title":"r_type  <code>instance-attribute</code>","text":"<pre><code>r_type = r_type\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.reactant","title":"reactant  <code>instance-attribute</code>","text":"<pre><code>reactant = reactant\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.check_atoms","title":"check_atoms","text":"<pre><code>check_atoms(values)\n</code></pre> Source code in <code>himatcal/recipes/gsm/DE_GSM.py</code> <pre><code>@field_validator(\"reactant\", \"product\")\ndef check_atoms(cls, values):\n    reactant, product = values\n    if isinstance(reactant, str):\n        values[\"reactant\"] = read(reactant)\n    if isinstance(product, str):\n        values[\"product\"] = read(product)\n    return values\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.run","title":"run","text":"<pre><code>run()\n</code></pre> Source code in <code>himatcal/recipes/gsm/DE_GSM.py</code> <pre><code>def run(self):\n    # * 0. convert atoms to geom\n    self.reactant_gemos = atoms2geom(self.reactant)\n    self.product_gemos = atoms2geom(self.product)\n\n    # * 1. build the LoT\n    logging.info(\"Building the LoT\")\n    self.lot = ASELoT.from_options(self.calculator, geom=self.reactant_gemos[2])\n\n    # * 2. build the PES\n    logging.info(\"Building the PES\")\n    self.pes = PES.from_options(\n        lot=self.lot, ad_idx=0, multiplicity=self.multiplicity\n    )\n\n    # * 3. build the topology\n    logging.info(\"Building the topologies\")\n    self.reactant_topo = Topology.build_topology(\n        xyz=self.reactant_gemos[1], atoms=self.reactant_gemos[0]\n    )\n    self.product_topo = Topology.build_topology(\n        xyz=self.product_gemos[1], atoms=self.product_gemos[0]\n    )\n    self.union_bonds()\n\n    # * 4. build the primitice internal coordinates\n    logging.info(\"Building Primitive Internal Coordinates\")\n    self.reactant_prim = PrimitiveInternalCoordinates.from_options(\n        xyz=self.reactant_gemos[1],\n        atoms=self.reactant_gemos[0],\n        topology=self.reactant_topo,\n        connect=self.coordinate_type == \"DLC\",\n        addtr=self.coordinate_type == \"TRIC\",\n        addcart=self.coordinate_type == \"HDLC\",\n    )\n    self.product_prim = PrimitiveInternalCoordinates.from_options(\n        xyz=self.product_gemos[1],\n        atoms=self.product_gemos[0],\n        topology=self.product_topo,\n        connect=self.coordinate_type == \"DLC\",\n        addtr=self.coordinate_type == \"TRIC\",\n        addcart=self.coordinate_type == \"HDLC\",\n    )\n    # * 4.1. add product coords to reactant coords\n    self.reactant_prim.add_union_primitives(self.product_prim)\n\n    # * 5. build the delocalized internal coordinates\n    logging.info(\"Building Delocalized Internal Coordinates\")\n    self.deloc_coords_reactant = DelocalizedInternalCoordinates.from_options(\n        xyz=self.reactant_gemos[1],\n        atoms=self.reactant_gemos[0],\n        connect=self.coordinate_type == \"DLC\",\n        addtr=self.coordinate_type == \"TRIC\",\n        addcart=self.coordinate_type == \"HDLC\",\n        primitives=self.reactant_prim,\n    )\n\n    # * 6. build the molecule\n    logging.info(\"Building Molecule\")\n    self.molecule_reactant = Molecule.from_options(\n        geom=self.reactant_gemos[2],\n        PES=self.pes,\n        coord_obj=self.deloc_coords_reactant,\n        Form_Hessian=self.optimizer_method == \"eigenvector_follow\",\n    )\n    self.molecule_product = Molecule.copy_from_options(\n        self.molecule_reactant,\n        xyz=self.product_gemos[1],\n        new_node_id=self.num_of_nodes - 1,\n        copy_wavefunction=False,\n    )\n\n    # * 7. create the optimizer\n    logging.info(\"Creating optimizer\")\n    opt_options = {\n        \"print_level\": 1,\n        \"Linesearch\": self.line_search,\n        \"update_hess_in_bg\": False,\n        \"conv_Ediff\": self.conv_Ediff,\n        \"conv_gmax\": self.conv_gmax,\n        \"DMAX\": self.DMAX,\n        \"opt_climb\": self.r_type in [1, 2],\n    }\n    if self.optimizer_method == \"eigenvector_follow\":\n        self.optimizer = eigenvector_follow.from_options(**opt_options)\n    elif self.optimizer_method == \"lbfgs\":\n        self.optimizer = lbfgs.from_options(**opt_options)\n    else:\n        raise NotImplementedError\n\n    # * 7.1 optimize reactant and product if needed\n    if not self.fixed_reactant:\n        path = str(Path.cwd() / \"scratch\" / f\"{self.ID:03}\" / \"0\")\n        self.optimizer.optimize(\n            molecule=self.molecule_reactant,\n            refE=self.molecule_reactant.energy,\n            opt_steps=100,\n            path=path,\n        )\n    if not self.fixed_product:\n        path = str(\n            Path.cwd() / \"scratch\" / f\"{self.ID:03}\" / str(self.num_of_nodes - 1)\n        )\n        self.optimizer.optimize(\n            molecule=self.molecule_product,\n            refE=self.molecule_product.energy,\n            opt_steps=100,\n            path=path,\n        )\n\n    # * 8. build the GSM\n    logging.info(\"Building the GSM object\")\n    self.gsm = DE_GSM.from_options(\n        reactant=self.molecule_reactant,\n        product=self.molecule_product,\n        nnodes=self.num_of_nodes,\n        CONV_TOL=0.0005,\n        CONV_gmax=self.conv_gmax,\n        CONV_Ediff=self.conv_Ediff,\n        ADD_NODE_TOL=0.1,\n        growth_direction=0,\n        optimizer=self.optimizer,\n        ID=self.ID,\n        print_level=1,\n        mp_cores=1,\n        interp_method=\"DLC\",\n        xyz_writer=XYZ_WRITERS[\"multixyz\"]\n    )\n\n    # * 9. run the GSM\n    logging.info(\"Main GSM Calculation\")\n    self.gsm.go_gsm(\n        max_iters=self.max_gsm_iterations,\n        opt_steps=self.max_opt_steps,\n        rtype=self.r_type,\n    )\n\n    # * 10. write the results into an extended xyz file\n    string_ase, ts_ase = gsm2atoms(self.gsm)\n    write(f\"opt_converged_{self.gsm.ID:03d}_ase.xyz\", string_ase)\n    write(f\"TSnode_{self.gsm.ID}.xyz\", ts_ase)\n\n    # * 11. post processing\n    logging.info(\"Post processing\")\n    post_processing(self.gsm, have_TS=True)\n\n    # * 12. cleanup\n    logging.info(\"Cleaning up\")\n    cleanup_scratch(self.gsm.ID)\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/DE_GSM.html#himatcal.recipes.gsm.DE_GSM.ASE_DE_GSM.union_bonds","title":"union_bonds","text":"<pre><code>union_bonds()\n</code></pre> Source code in <code>himatcal/recipes/gsm/DE_GSM.py</code> <pre><code>def union_bonds(self):\n    for bond in self.product_topo.edges():\n        if (\n            bond in self.reactant_topo.edges()\n            or (bond[1], bond[0]) in self.reactant_topo.edges()\n        ):\n            continue\n        logging.info(f\" Adding bond {bond} to reactant topology\")\n        if bond[0] &gt; bond[1]:\n            self.reactant_topo.add_edge(bond[0], bond[1])\n        else:\n            self.reactant_topo.add_edge(bond[1], bond[0])\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html","title":"SE_GSM","text":""},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM","title":"ASE_SE_GSM","text":"<pre><code>ASE_SE_GSM(atoms, driving_coords, multiplicity=1, calculator=None, cleanup_scratch=False)\n</code></pre> <p>This constructor sets up the parameters necessary for the class, including the atom to be used, the driving coordinates for simulations, and an optional calculator for performing calculations. It also allows for the option to clean up temporary files created during the process.</p> <p>Args:     atom: The atom to be used in the calculations.     driving_coords: A list of driving coordinates, formatted as [[\"BREAK\", 2, 3]].     calculator: An optional calculator instance; if not provided, a default XTB calculator is used.     cleanup_scratch: A boolean indicating whether to clean up scratch files after computations.</p> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def __init__(\n    self,\n    atoms,\n    driving_coords,\n    multiplicity=1,\n    calculator=None,\n    cleanup_scratch=False,\n):\n    \"\"\"\n    Initializes the class with the specified atom and driving coordinates.\n\n    This constructor sets up the parameters necessary for the class, including the atom to be used, the driving coordinates for simulations, and an optional calculator for performing calculations. It also allows for the option to clean up temporary files created during the process.\n\n    Args:\n        atom: The atom to be used in the calculations.\n        driving_coords: A list of driving coordinates, formatted as [[\"BREAK\", 2, 3]].\n        calculator: An optional calculator instance; if not provided, a default XTB calculator is used.\n        cleanup_scratch: A boolean indicating whether to clean up scratch files after computations.\n\n    \"\"\"\n\n    self.atoms = atoms\n    self.driving_coords = driving_coords  # List: driving_coords = [[\"BREAK\", 2, 3]]\n    self.multiplicity = multiplicity\n    if calculator is None:\n        from xtb_ase import XTB\n\n        calculator = XTB()\n    self.calculator = calculator\n    self.cleanup_scratch = cleanup_scratch\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.atoms","title":"atoms  <code>instance-attribute</code>","text":"<pre><code>atoms = atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.calculator","title":"calculator  <code>instance-attribute</code>","text":"<pre><code>calculator = calculator\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.cleanup_scratch","title":"cleanup_scratch  <code>instance-attribute</code>","text":"<pre><code>cleanup_scratch = cleanup_scratch\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.driving_coords","title":"driving_coords  <code>instance-attribute</code>","text":"<pre><code>driving_coords = driving_coords\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.multiplicity","title":"multiplicity  <code>instance-attribute</code>","text":"<pre><code>multiplicity = multiplicity\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_delocalized_coords","title":"build_delocalized_coords","text":"<pre><code>build_delocalized_coords()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_delocalized_coords(self):\n    nifty.printcool(\"Building Delocalized Internal Coordinates\")\n    self.coord_obj1 = DelocalizedInternalCoordinates.from_options(\n        xyz=self.xyz,\n        atoms=self.atom,\n        addtr=True,  # Add TRIC\n        primitives=self.p1,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_lot","title":"build_lot","text":"<pre><code>build_lot()\n</code></pre> <p>build ase lot from calculator</p> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_lot(self):\n    \"\"\"\n    build ase lot from calculator\n    \"\"\"\n    nifty.printcool(\" Building the LOT\")\n    self.lot = ASELoT.from_options(self.calculator, geom=self.geom)\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_molecule","title":"build_molecule","text":"<pre><code>build_molecule()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_molecule(self):\n    nifty.printcool(\"Building Molecule\")\n    self.reactant = Molecule.from_options(\n        geom=self.geom,\n        PES=self.pes,\n        coord_obj=self.coord_obj1,\n        Form_Hessian=True,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_pes","title":"build_pes","text":"<pre><code>build_pes()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_pes(self):\n    nifty.printcool(\" Building the PES\")\n    self.pes = PES.from_options(\n        lot=self.lot,\n        ad_idx=0,  # Adiabatic index (default: 0)\n        multiplicity=self.multiplicity,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_primitives","title":"build_primitives","text":"<pre><code>build_primitives()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_primitives(self):\n    nifty.printcool(\"Building Primitive Internal Coordinates\")\n    self.p1 = PrimitiveInternalCoordinates.from_options(\n        xyz=self.xyz,\n        atoms=self.atom,\n        addtr=True,  # Add TRIC\n        topology=self.top,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.build_topology","title":"build_topology","text":"<pre><code>build_topology()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def build_topology(self):\n    # * build the topology\n    self.top = Topology.build_topology(\n        self.xyz,\n        self.atom,\n    )\n    # * add the driving coordinates to the topology\n    driving_coord_prims = []\n    for dc in self.driving_coords:\n        prim = get_driving_coord_prim(dc)\n        if prim is not None:\n            driving_coord_prims.append(prim)\n\n    for prim in driving_coord_prims:\n        if type(prim) is Distance:\n            bond = (prim.atoms[0], prim.atoms[1])\n            if (\n                bond not in self.top.edges\n                and (bond[1], bond[0]) not in self.top.edges()\n            ):\n                logging.info(f\" Adding bond {bond} to top1\")\n                self.top.add_edge(bond[0], bond[1])\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.clean_scratch","title":"clean_scratch","text":"<pre><code>clean_scratch()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def clean_scratch(self):\n    if self.cleanup_scratch:\n        cmd = f\"rm scratch/growth_iters_{self.gsm.ID:03d}_*.xyz\"\n        os.system(cmd)\n        cmd = f\"rm scratch/opt_iters_{self.gsm.ID:03d}_*.xyz\"\n        os.system(cmd)\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.create_optimizer","title":"create_optimizer","text":"<pre><code>create_optimizer()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def create_optimizer(self):\n    nifty.printcool(\"Creating optimizer\")\n    self.optimizer = eigenvector_follow.from_options(\n        Linesearch=\"backtrack\",\n        OPTTHRESH=0.0005,\n        DMAX=0.5,\n        abs_max_step=0.5,\n        conv_Ediff=0.1,\n        opt_climb=True,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.optimize_reactant","title":"optimize_reactant","text":"<pre><code>optimize_reactant()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def optimize_reactant(self):\n    nifty.printcool(f\"initial energy is {self.reactant.energy:5.4f} kcal/mol\")\n    nifty.printcool(\"REACTANT GEOMETRY NOT FIXED!!! OPTIMIZING\")\n    self.optimizer.optimize(\n        molecule=self.reactant,\n        refE=self.reactant.energy,\n        opt_steps=50,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.run","title":"run","text":"<pre><code>run()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def run(self):\n    self.atom, self.xyz, self.geom = atoms2geom(self.atoms)\n    self.build_lot()\n    self.build_pes()\n    self.build_topology()\n    self.build_primitives()\n    self.build_delocalized_coords()\n    self.build_molecule()\n    self.create_optimizer()\n    self.optimize_reactant()\n    self.run_gsm()\n    post_processing(self.gsm, analyze_ICs=False, have_TS=True)\n\n    # * 10. write the results into an extended xyz file\n    string_ase, ts_ase = gsm2atoms(self.gsm)\n    write(f\"opt_converged_{self.gsm.ID:03d}_ase.xyz\", string_ase)\n    write(f\"TSnode_{self.gsm.ID}.xyz\", ts_ase)\n\n    self.clean_scratch()\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/SE_GSM.html#himatcal.recipes.gsm.SE_GSM.ASE_SE_GSM.run_gsm","title":"run_gsm","text":"<pre><code>run_gsm()\n</code></pre> Source code in <code>himatcal/recipes/gsm/SE_GSM.py</code> <pre><code>def run_gsm(self):\n    self.gsm = SE_GSM.from_options(\n        reactant=self.reactant,\n        nnodes=30,\n        optimizer=self.optimizer,\n        xyz_writer=manage_xyz.write_std_multixyz,\n        driving_coords=self.driving_coords,\n        DQMAG_MAX=1.5,  # * default value is 0.8, Maximum step size in single-ended mode\n        DQMAG_MIN=0.2,  # * default value is 0.8, Maximum step size in single-ended mode\n        ADD_NODE_TOL=0.1,  # * default value is 0.1, for GSM, Convergence tolerance for adding new node\n        CONV_TOL=0.0005,  # * Convergence tolerance for optimizing nodes\n    )\n    self.gsm.go_gsm(max_iters=50, opt_steps=10, rtype=2)\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/core.html","title":"core","text":"<p>core functions for GSM</p>"},{"location":"reference/himatcal/recipes/gsm/core.html#himatcal.recipes.gsm.core.atoms2geom","title":"atoms2geom","text":"<pre><code>atoms2geom(atoms: Atoms)\n</code></pre> <p>Converts an Atoms object into a geometric representation suitable for further processing. This function extracts atomic symbols and positions, returning them in a structured format.</p> <p>The function takes an Atoms object as input and retrieves the atomic positions and symbols. It then constructs a list of atomic data and a geometric representation, which includes the symbols and their corresponding coordinates.</p> <p>Args:     atoms (Atoms): The Atoms object containing atomic positions and symbols.</p> <p>Returns:     tuple: A tuple containing:         - List of atom objects corresponding to the atomic symbols.         - Numpy array of atomic positions.         - List of geometric representations combining symbols and positions.</p> <p>Examples:     To convert an Atoms object to its geometric representation, call:     &gt;&gt;&gt; atom_list, positions, geometry = atoms2geom(atoms)</p> Source code in <code>himatcal/recipes/gsm/core.py</code> <pre><code>def atoms2geom(atoms: Atoms):\n    \"\"\"\n    Converts an Atoms object into a geometric representation suitable for further processing. This function extracts atomic symbols and positions, returning them in a structured format.\n\n    The function takes an Atoms object as input and retrieves the atomic positions and symbols. It then constructs a list of atomic data and a geometric representation, which includes the symbols and their corresponding coordinates.\n\n    Args:\n        atoms (Atoms): The Atoms object containing atomic positions and symbols.\n\n    Returns:\n        tuple: A tuple containing:\n            - List of atom objects corresponding to the atomic symbols.\n            - Numpy array of atomic positions.\n            - List of geometric representations combining symbols and positions.\n\n    Examples:\n        To convert an Atoms object to its geometric representation, call:\n        &gt;&gt;&gt; atom_list, positions, geometry = atoms2geom(atoms)\n    \"\"\"\n\n    xyz = atoms.positions\n    geom = np.column_stack([atoms.symbols, xyz]).tolist()\n    ELEMENT_TABLE = elements.ElementData()\n    atom = [ELEMENT_TABLE.from_symbol(atom) for atom in atoms.symbols]\n    return atom, xyz, geom\n</code></pre>"},{"location":"reference/himatcal/recipes/gsm/core.html#himatcal.recipes.gsm.core.gsm2atoms","title":"gsm2atoms","text":"<pre><code>gsm2atoms(gsm)\n</code></pre> <p>convert GSM DE_GSM object to ASE Atoms objects</p> Source code in <code>himatcal/recipes/gsm/core.py</code> <pre><code>def gsm2atoms(gsm):\n    \"\"\"\n    convert GSM DE_GSM object to ASE Atoms objects\n    \"\"\"\n    # string\n    frames = []\n    for energy, geom in zip(gsm.energies, gsm.geometries):\n        at = Atoms(symbols=[x[0] for x in geom], positions=[x[1:4] for x in geom])\n        at.info[\"energy\"] = energy\n        frames.append(at)\n\n    # TS\n    ts_geom = gsm.nodes[gsm.TSnode].geometry\n    ts_atoms = Atoms(symbols=[x[0] for x in ts_geom], positions=[x[1:4] for x in ts_geom])\n\n    return frames, ts_atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/materials/core.html#himatcal.recipes.materials.core.ase_to_pymatgen","title":"ase_to_pymatgen  <code>staticmethod</code>","text":"<pre><code>ase_to_pymatgen(atoms)\n</code></pre> <p>Converts an ASE Atoms object to a pymatgen Structure.</p> <p>Args:     atoms: ASE Atoms object to convert.</p> <p>Returns:     pymatgen Structure object representing the same atomic configuration.</p> Source code in <code>himatcal/recipes/materials/core.py</code> <pre><code>@staticmethod\ndef ase_to_pymatgen(atoms):\n    \"\"\"\n    Converts an ASE Atoms object to a pymatgen Structure.\n\n    Args:\n        atoms: ASE Atoms object to convert.\n\n    Returns:\n        pymatgen Structure object representing the same atomic configuration.\n    \"\"\"\n\n    return Structure(\n        coords_are_cartesian=True,\n        coords=atoms.positions,\n        species=atoms.symbols,\n        lattice=atoms.cell,\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/core.html#himatcal.recipes.materials.core.pymatgen_to_ase","title":"pymatgen_to_ase  <code>staticmethod</code>","text":"<pre><code>pymatgen_to_ase(structure)\n</code></pre> Source code in <code>himatcal/recipes/materials/core.py</code> <pre><code>@staticmethod\ndef pymatgen_to_ase(structure):\n    lattice = structure.lattice\n    \"\"\"\n    Converts a pymatgen Structure to an ASE Atoms object.\n\n    Args:\n        structure: pymatgen Structure object to convert.\n\n    Returns:\n        ASE Atoms object representing the same structure.\n    \"\"\"\n\n    return Atoms(\n        scaled_positions=structure.frac_coords,\n        numbers=structure.atomic_numbers,\n        pbc=True,\n        cell=Cell.fromcellpar(\n            [\n                lattice.a,\n                lattice.b,\n                lattice.c,\n                lattice.alpha,\n                lattice.beta,\n                lattice.gamma,\n            ]\n        ),\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html","title":"diffubarrier","text":""},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.Logger","title":"Logger  <code>module-attribute</code>","text":"<pre><code>Logger = getLogger(__name__)\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal","title":"DiffusionBarrierCal","text":"<pre><code>DiffusionBarrierCal(atoms: Atoms, label: str, ion_type: str = 'Li', neb_point_number: int = 5, nebor_cutoff: float = 4, parallel: int = 4)\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def __init__(\n    self,\n    atoms: Atoms,\n    label: str,\n    ion_type: str = \"Li\",\n    neb_point_number: int = 5,\n    nebor_cutoff: float = 4,\n    parallel: int = 4,\n):\n    self.label = label\n    self.atoms = atoms\n    self.ion_type = ion_type\n    self.neb_point_number = neb_point_number\n    self.nebor_cutoff = nebor_cutoff\n    self.parallel = parallel\n    self._CWD = Path.cwd()\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.atoms","title":"atoms  <code>instance-attribute</code>","text":"<pre><code>atoms = atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.ion_type","title":"ion_type  <code>instance-attribute</code>","text":"<pre><code>ion_type = ion_type\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.label","title":"label  <code>instance-attribute</code>","text":"<pre><code>label = label\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.neb_point_number","title":"neb_point_number  <code>instance-attribute</code>","text":"<pre><code>neb_point_number = neb_point_number\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.nebor_cutoff","title":"nebor_cutoff  <code>instance-attribute</code>","text":"<pre><code>nebor_cutoff = nebor_cutoff\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.parallel","title":"parallel  <code>instance-attribute</code>","text":"<pre><code>parallel = parallel\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.cal_diffusion_barrier","title":"cal_diffusion_barrier","text":"<pre><code>cal_diffusion_barrier(neb_path_floder: Path)\n</code></pre> <p>Calculate the diffusion barrier in the neb path floder</p> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def cal_diffusion_barrier(self, neb_path_floder: Path):\n    \"\"\"\n    Calculate the diffusion barrier in the neb path floder\n    \"\"\"\n    # * if Ea.txt is in cal_dir, pass\n    if Path(f\"{neb_path_floder}/Ea.txt\").exists():\n        logging.info(f\"{neb_path_floder}/Ea.txt exists.\")\n        return\n\n    # * read neb path data from the folder\n    neb_data = []\n    for i in range(self.neb_point_number + 2):\n        tmp_data = read(f\"{neb_path_floder}/0{i}.vasp\")\n        neb_data.append(tmp_data)\n    neb_data[0] = self.relax(atoms=neb_data[0])\n    neb_data[-1] = self.relax(atoms=neb_data[-1])\n\n    # * neb calculation\n    ## * 1. assign calculator to neb data\n    images = []\n    pot = matgl.load_model(\"M3GNet-MP-2021.2.8-PES\")\n    calc = M3GNetCalculator(potential=pot, stress_weight=1 / 160.21766208)\n\n    for i in neb_data:\n        i.calc = calc\n        images.append(i)\n\n    ## * 2. run neb calculation\n    neb = NEB(images, climb=True, allow_shared_calculator=True)\n    qn = FIRE(neb, trajectory=f\"{neb_path_floder}/neb.traj\")\n    try:\n        logging.info(f\"calculating image {neb_path_floder}\")\n        qn.run(fmax=0.15)\n    except Exception:\n        logging.error(f\"Error: neb calculation of image {neb_path_floder} failed.\")\n\n    ## * 3. get the neb barrier\n    traj = read(f\"{neb_path_floder}/neb.traj@-{self.neb_point_number+2}:\")\n    result = []\n    for j in traj:\n        j.calc = calc\n        result.append(j)\n    logging.info(f\"image {neb_path_floder} calculated.\")\n\n    nebtools = NEBTools(result)\n    Ef, dE = nebtools.get_barrier()\n\n    ## * 4. write the Ea to Ea.txt\n    Path.open(Path(f\"{neb_path_floder}/Ea.txt\"), \"w\").write(f\"{Ef-dE}\")\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.extract_results","title":"extract_results","text":"<pre><code>extract_results(neb_path_floders: list)\n</code></pre> <p>extract the Ea from the Ea.txt in the neb path floders</p> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def extract_results(self, neb_path_floders: list):\n    \"\"\"\n    extract the Ea from the Ea.txt in the neb path floders\n    \"\"\"\n    with Path.open(Path(f\"{self._CWD}/Ea_result.txt\"), \"w\") as f:\n        E_sum = []\n        for i in neb_path_floders:\n            try:\n                logging.info(f\"Extracting 'Ea' from {i}\")\n                tmp_Ea = float(\n                    Path.open(Path(f\"{i}/Ea.txt\"), \"r\")\n                    .readlines()[0]\n                    .rstrip()\n                    .split()[0]\n                )\n                logging.info(f\"{i} Ea: {tmp_Ea}\")\n                f.write(f\"{i}: {tmp_Ea}\\n\")\n                E_sum.append(tmp_Ea)\n            except FileNotFoundError:\n                f.write(f\"{i}: Error: File not found\\n\")\n            except ValueError:\n                f.write(f\"{i}: Error: Invalid value\\n\")\n        Ea = sum(E_sum) / len(E_sum)\n        f.write(f\"Ea: {Ea:.3f}\")\n    return Ea\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.generate_neb_path","title":"generate_neb_path","text":"<pre><code>generate_neb_path()\n</code></pre> <p>Generate the neb path using the OgStrucure and return the path of the neb path floders.</p> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def generate_neb_path(self):\n    \"\"\"\n    Generate the neb path using the OgStrucure and return the path of the neb path floders.\n    \"\"\"\n    self.structure = self.relax(atoms=self.atoms, relax_cell=True)\n    write(\"relaxed_atoms.vasp\", self.structure)\n    OgStructure(structure=self.structure).generate_neb(\n        moving_atom_species=self.ion_type,\n        num_images=self.neb_point_number,\n        r=self.nebor_cutoff,\n    )\n    return [item for item in self._CWD.iterdir() if item.is_dir()]\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.get_diffusion_barrier","title":"get_diffusion_barrier","text":"<pre><code>get_diffusion_barrier()\n</code></pre> <p>Get the diffusion barrier of the atoms.</p> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def get_diffusion_barrier(self):\n    \"\"\"\n    Get the diffusion barrier of the atoms.\n    \"\"\"\n    # * 1. generate neb path\n    neb_path_floders = self.generate_neb_path()\n    logging.info(f\"neb_path_floders: {neb_path_floders}\")\n\n    # * 2. calculate diffusion barrier\n    # for folder in neb_path_floders:\n    #     logging.info(f\"cal_diffusion_barrier {folder}\")\n    #     try:\n    #         self.cal_diffusion_barrier(folder)\n    #     except Exception:\n    #         logging.error(f\"Error: cal_diffusion_barrier {folder} failed.\")\n    pool = Pool(nodes=min(self.parallel, len(neb_path_floders)))\n    pool.map(self.cal_diffusion_barrier, neb_path_floders)\n    logging.info(\"cal_diffusion_barrier done\")\n\n    # * 3. extract results Ea\n    return self.extract_results(neb_path_floders)\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.DiffusionBarrierCal.relax","title":"relax","text":"<pre><code>relax(atoms, relax_cell=False)\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def relax(self, atoms, relax_cell=False):\n    pot = matgl.load_model(\"M3GNet-MP-2021.2.8-PES\")\n    relaxer = Relaxer(potential=pot, relax_cell=relax_cell)\n    relax_results = relaxer.relax(atoms, verbose=True, fmax=0.1)\n    return pymatgen_to_ase(relax_results[\"final_structure\"])\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure","title":"OgStructure","text":"<pre><code>OgStructure(structure: Atoms | Structure | str = None)\n</code></pre> <p>model from OgStructure, using to generate the NEB Path in the Crystal.</p> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def __init__(\n    self,\n    structure: Atoms | Structure | str = None,\n) -&gt; None:\n    if structure is None:\n        return\n\n    if isinstance(structure, str):\n        parser = CifParser.from_str(structure)\n        structure = parser.get_structures()[0]\n    elif isinstance(structure, Atoms):\n        self.structure = ase_to_pymatgen(structure)\n    elif isinstance(structure, Structure):\n        self.structure = structure\n\n    self.structure.sort()\n    self.pot = matgl.load_model(\"M3GNet-MP-2021.2.8-PES\")\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.pot","title":"pot  <code>instance-attribute</code>","text":"<pre><code>pot = load_model('M3GNet-MP-2021.2.8-PES')\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.structure","title":"structure  <code>instance-attribute</code>","text":"<pre><code>structure = ase_to_pymatgen(structure)\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.center","title":"center","text":"<pre><code>center(about_atom=None, about_point=None)\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def center(self, about_atom=None, about_point=None):\n    if about_atom is not None:\n        about_point = self.structure.frac_coords[about_atom]\n    elif about_point is None:\n        about_point = [0, 0, 0]\n    sys = pymatgen_to_ase(self.structure)\n    sys.center(about=about_point)\n    self.structure = ase_to_pymatgen(sys)\n    return self\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.epsilon","title":"epsilon","text":"<pre><code>epsilon(a, b)\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def epsilon(self, a, b):\n    return abs(a - b) &lt; 1e-6\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.equivalent_sites","title":"equivalent_sites","text":"<pre><code>equivalent_sites(i, site)\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def equivalent_sites(self, i, site):\n    return bool(\n        self.epsilon(self.structure.frac_coords[i][0] % 1, site.frac_coords[0] % 1)\n        and self.epsilon(\n            self.structure.frac_coords[i][1] % 1, site.frac_coords[1] % 1\n        )\n        and self.epsilon(\n            self.structure.frac_coords[i][2] % 1, site.frac_coords[2] % 1\n        )\n    )\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.generate_neb","title":"generate_neb","text":"<pre><code>generate_neb(moving_atom_species, num_images=5, r=4) -&gt; None\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def generate_neb(\n    self,\n    moving_atom_species,\n    num_images=5,\n    r=4,\n) -&gt; None:\n    structure = self.structure\n    self.neb_paths = []\n\n    def get_moving_atom_neighbors(site):\n        return [\n            neighbor\n            for neighbor in structure.get_neighbors(site=site, r=r)\n            if neighbor.specie.symbol == moving_atom_species\n        ]\n\n    def modify_structure(new_structure, i_site, i_neighbor_site):\n        ogs = OgStructure(new_structure)\n        new_structure = ogs.center(i_site, [0.5, 0.5, 0.5]).structure\n\n        initial_structure = new_structure.copy()\n        final_structure = new_structure.copy()\n        initial_structure.remove_sites([i_site, i_neighbor_site])\n        initial_structure.append(\n            species=new_structure[i_site].species,\n            coords=new_structure[i_site].frac_coords,\n        )\n        initial = pymatgen_to_ase(initial_structure)\n        final_structure.remove_sites([i_site, i_neighbor_site])\n        final_structure.append(\n            species=new_structure[i_neighbor_site].species,\n            coords=new_structure[i_neighbor_site].frac_coords,\n        )\n        final = pymatgen_to_ase(final_structure)\n        return initial, final\n\n    def handle_neb_path(i_site, i_neighbor_site):\n        new_structure = structure.copy()\n        self.neb_paths.append([i_site, i_neighbor_site])\n        neb_folder = f\"neb_path_{i_neighbor_site}_{i_site}\"\n\n        initial, final = modify_structure(new_structure, i_site, i_neighbor_site)\n\n        self.images = (\n            [initial] + [initial.copy() for _ in range(num_images)] + [final]\n        )\n        self.neb = NEB(self.images)\n        Path(neb_folder).mkdir(exist_ok=True)\n        self.neb.interpolate(mic=True)\n        for i, img in enumerate(self.images):\n            image = OgStructure(img).relax()\n            image_str = image.structure.to(fmt=\"poscar\")\n            with Path.open(Path(f\"{neb_folder}/{str(i).zfill(2)}.vasp\"), \"w\") as f:\n                f.write(image_str)\n\n    for i_site in range(len(structure)):\n        if structure[i_site].specie.symbol == moving_atom_species:\n            neighbors = get_moving_atom_neighbors(structure[i_site])\n            logging.info(f\"og:Full neighbors: {neighbors}\")\n            logging.info(\n                f\"og:Checking site, {i_site} Surrounded by {len(neighbors)}\"\n            )\n            for neighbor in neighbors:\n                i_neighbor_site = self._get_site_for_neighbor_site(neighbor)\n                logging.info(f\"og:Checking neighbor site {i_neighbor_site}\")\n                if i_neighbor_site is None:\n                    logging.error(\"og:Really? Wrong site in neighbor list!\")\n                if [i_site, i_neighbor_site] in self.neb_paths or [\n                    i_neighbor_site,\n                    i_site,\n                ] in self.neb_paths:\n                    continue\n                handle_neb_path(i_site, i_neighbor_site)\n</code></pre>"},{"location":"reference/himatcal/recipes/materials/diffubarrier.html#himatcal.recipes.materials.diffubarrier.OgStructure.relax","title":"relax","text":"<pre><code>relax()\n</code></pre> Source code in <code>himatcal/recipes/materials/diffubarrier.py</code> <pre><code>def relax(self):\n    relaxer = Relaxer(potential=self.pot, relax_cell=False)\n    relax_results = relaxer.relax(self.structure, verbose=True, fmax=0.1)\n    self.structure = relax_results[\"final_structure\"]\n    self.total_energy = relax_results[\"trajectory\"].energies[-1]\n    return self\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner","title":"MCD_runner","text":"<pre><code>MCD_runner(atoms: Atoms, chg: int = 0, mult: int = 1, driving_coords: list | None = None, qcsoft: str = 'gaussian', command: str = 'g16', calc_kwargs: str = '#N B3LYP/6-311+g* em=GD3BJ scf(xqc) scrf(iefpcm, solvent=acetone)', num_relaxation: int = 5, step_size: float = 0.05, working_directory='', output_directory='', use_hessian: bool = False, hessian_update: str = 'exact', unit: str = 'Hartree')\n</code></pre> Source code in <code>himatcal/recipes/mcd/core.py</code> <pre><code>def __init__(\n    self,\n    atoms: Atoms,\n    chg: int = 0,\n    mult: int = 1,\n    driving_coords: list | None = None,  # atoms' index, target bondlength, step, [[1, 8, 2.1, 5]]\n    qcsoft: str = \"gaussian\",\n    command: str = \"g16\",\n    calc_kwargs: str = \"#N B3LYP/6-311+g* em=GD3BJ scf(xqc) scrf(iefpcm, solvent=acetone)\",\n    num_relaxation: int = 5,\n    step_size: float = 0.05,\n    working_directory=\"\",\n    output_directory=\"\",\n    use_hessian: bool = False,\n    hessian_update: str = \"exact\",\n    unit: str = \"Hartree\",\n):\n    self.atoms = atoms\n    self.chg = chg\n    self.mult = mult\n    self.driving_coords = driving_coords\n    self.qcsoft = qcsoft\n    self.command = command\n    self.calc_kwargs = calc_kwargs\n    self.num_relaxation = num_relaxation\n    self.use_hessian = use_hessian\n    self.hessian_update = hessian_update\n    self.step_size = step_size\n    if output_directory == \"\":\n        output_directory = str(Path.cwd())\n    if working_directory == \"\":\n        working_directory = output_directory\n    self.working_directory = working_directory\n    self.output_directory = output_directory\n    self.unit = unit\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.atoms","title":"atoms  <code>instance-attribute</code>","text":"<pre><code>atoms = atoms\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.calc_kwargs","title":"calc_kwargs  <code>instance-attribute</code>","text":"<pre><code>calc_kwargs = calc_kwargs\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.chg","title":"chg  <code>instance-attribute</code>","text":"<pre><code>chg = chg\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.command","title":"command  <code>instance-attribute</code>","text":"<pre><code>command = command\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.driving_coords","title":"driving_coords  <code>instance-attribute</code>","text":"<pre><code>driving_coords = driving_coords\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.hessian_update","title":"hessian_update  <code>instance-attribute</code>","text":"<pre><code>hessian_update = hessian_update\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.mult","title":"mult  <code>instance-attribute</code>","text":"<pre><code>mult = mult\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.num_relaxation","title":"num_relaxation  <code>instance-attribute</code>","text":"<pre><code>num_relaxation = num_relaxation\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.output_directory","title":"output_directory  <code>instance-attribute</code>","text":"<pre><code>output_directory = output_directory\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.qcsoft","title":"qcsoft  <code>instance-attribute</code>","text":"<pre><code>qcsoft = qcsoft\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.step_size","title":"step_size  <code>instance-attribute</code>","text":"<pre><code>step_size = step_size\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.unit","title":"unit  <code>instance-attribute</code>","text":"<pre><code>unit = unit\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.use_hessian","title":"use_hessian  <code>instance-attribute</code>","text":"<pre><code>use_hessian = use_hessian\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.working_directory","title":"working_directory  <code>instance-attribute</code>","text":"<pre><code>working_directory = working_directory\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.dirving_constraints","title":"dirving_constraints","text":"<pre><code>dirving_constraints()\n</code></pre> Source code in <code>himatcal/recipes/mcd/core.py</code> <pre><code>def dirving_constraints(self):\n    constraints = {}\n    num_steps = {}\n    for DC in self.driving_coords:\n        constraint = (DC[0] - 1, DC[1] - 1)\n        constraints[constraint] = DC[2]\n        num_steps[constraint] = DC[3]\n    return constraints, num_steps\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.get_calculator","title":"get_calculator","text":"<pre><code>get_calculator()\n</code></pre> Source code in <code>himatcal/recipes/mcd/core.py</code> <pre><code>def get_calculator(self):\n    if self.qcsoft == \"gaussian\":\n        from himatcal.calculator.gaussian_mcd import Gaussian\n\n        calculator = Gaussian(self.command)\n    elif self.qcsoft == \"orca\":\n        from himatcal.calculator.orca_mcd import Orca\n\n        calculator = Orca(self.command)\n    else:\n        print(\n            f\"Wrong calculator (={self.qcsoft}) is given! Check the option file !!!\"\n        )\n        calculator = None\n        return calculator\n    calculator.content = self.calc_kwargs\n    # basis_file = os.path.join(args.input_directory,'basis') # For Effective Core Potential\n    # if os.path.exists(basis_file):\n    #     calculator.load_basis(basis_file)\n    return calculator\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.read_reactant","title":"read_reactant","text":"<pre><code>read_reactant()\n</code></pre> Source code in <code>himatcal/recipes/mcd/core.py</code> <pre><code>def read_reactant(self):\n    atom_list = []\n    for a in self.atoms:\n        atom = chem.Atom(a.symbol)\n        atom.x = a.x\n        atom.y = a.y\n        atom.z = a.z\n        atom_list.append(atom)\n    reactant = chem.Molecule()\n    reactant.atom_list = atom_list\n    reactant.chg = self.chg\n    reactant.multiplicity = self.mult\n    return reactant\n</code></pre>"},{"location":"reference/himatcal/recipes/mcd/core.html#himatcal.recipes.mcd.core.MCD_runner.run_MCD","title":"run_MCD","text":"<pre><code>run_MCD()\n</code></pre> Source code in <code>himatcal/recipes/mcd/core.py</code> <pre><code>def run_MCD(self):\n    reactant = self.read_reactant()\n    calculator = self.get_calculator()\n    constraints, num_steps = self.dirving_constraints()\n    scanner = mcd.MCD(num_relaxation=self.num_relaxation, calculator=calculator)\n    scanner.use_hessian = self.use_hessian\n    scanner.hessian_update = self.hessian_update\n    scanner.step_size = self.step_size\n    scanner.log_directory = self.output_directory\n    scanner.change_working_directory(self.working_directory)\n    pathway = scanner.scan(\n        reactant,\n        constraints,\n        num_steps,\n        chg=self.chg,\n        multiplicity=self.mult,\n    )\n    return pathway\n</code></pre>"},{"location":"reference/himatcal/recipes/mol/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/mol/core.html#himatcal.recipes.mol.core.cas2xyz","title":"cas2xyz","text":"<pre><code>cas2xyz(CAS_ID, relax_atoms=True)\n</code></pre> <p>Converts a CAS ID into an XYZ file format representation of the corresponding molecule.</p> <p>This function retrieves molecular data from the Common Chemistry API using the provided CAS ID, constructs a molecular structure, and optionally relaxes the atomic positions before saving the structure to an XYZ file.</p> <p>Args:     CAS_ID (str): The Chemical Abstracts Service identifier for the desired molecule.     relax_atoms (bool): A flag indicating whether to relax the atomic positions before saving. Defaults to True.</p> <p>Returns:     None</p> <p>Raises:     ValueError: If the CAS ID is invalid or if the API call fails.</p> <p>Examples:     cas2xyz(\"50-00-0\")  # Converts the CAS ID for formaldehyde to an XYZ file.</p> Source code in <code>himatcal/recipes/mol/core.py</code> <pre><code>def cas2xyz(CAS_ID, relax_atoms=True):\n    \"\"\"\n    Converts a CAS ID into an XYZ file format representation of the corresponding molecule.\n\n    This function retrieves molecular data from the Common Chemistry API using the provided CAS ID, constructs a molecular structure, and optionally relaxes the atomic positions before saving the structure to an XYZ file.\n\n    Args:\n        CAS_ID (str): The Chemical Abstracts Service identifier for the desired molecule.\n        relax_atoms (bool): A flag indicating whether to relax the atomic positions before saving. Defaults to True.\n\n    Returns:\n        None\n\n    Raises:\n        ValueError: If the CAS ID is invalid or if the API call fails.\n\n    Examples:\n        cas2xyz(\"50-00-0\")  # Converts the CAS ID for formaldehyde to an XYZ file.\n    \"\"\"\n    sources = [\n        f\"https://commonchemistry.cas.org/api/detail?cas_rn={CAS_ID}\",\n        f\"https://www.chemicalbook.com/CAS/mol/{CAS_ID}.mol\",\n        f\"https://www.chemicalbook.com/CAS/20210305/MOL/{CAS_ID}.mol\",\n        f\"https://www.chemicalbook.com/CAS/20210111/MOL/{CAS_ID}.mol\",\n        f\"https://www.chemicalbook.com/CAS/20180601/MOL/{CAS_ID}.mol\",\n        f\"https://www.chemicalbook.com/CAS/20150408/MOL/{CAS_ID}.mol\",\n        f\"https://www.chemicalbook.com/CAS/20200515/MOL/{CAS_ID}.mol\"\n    ]\n\n    mol = None\n    for source in sources:\n        try:\n            if \"commonchemistry\" in source:\n                result_dict = json.loads(consumeApi(source))\n                mol = Chem.MolFromInchi(result_dict[\"inchi\"])\n            else:\n                request = urllib.request.Request(\n                    source, headers={\"User-Agent\": \"Mozilla/5.0\"}\n                )\n                response = urllib.request.urlopen(request)\n                if response.status == 200:\n                    mol_file_content = response.read().decode(\"utf-8\")\n                    mol = Chem.MolFromMolBlock(mol_file_content, removeHs=False)\n            if mol:\n                break\n        except Exception:\n            # print(f\"Failed to retrieve data from {source}: {e}\")\n            continue\n\n    if not mol:\n        try:\n            mol = get_molecular_structure(CAS_ID)\n        except Exception as e:\n            raise ValueError(\n                f\"Could not retrieve molecular data for CAS ID {CAS_ID}\"\n            ) from e\n\n    mol = Chem.AddHs(mol, addCoords=True)\n    AllChem.EmbedMultipleConfs(mol, numConfs=10)\n    if relax_atoms:\n        atoms = rdkit2ase(mol)\n        atoms_relaxed = relax(atoms)\n        write(f\"{CAS_ID}.xyz\", atoms_relaxed)\n    else:\n        Chem.MolToXYZFile(mol, f\"{CAS_ID}.xyz\")\n    with Path.open(Path(f\"{CAS_ID}.xyz\")) as file:\n        return file.read()\n</code></pre>"},{"location":"reference/himatcal/recipes/mol/core.html#himatcal.recipes.mol.core.consumeApi","title":"consumeApi","text":"<pre><code>consumeApi(urlPath)\n</code></pre> Source code in <code>himatcal/recipes/mol/core.py</code> <pre><code>def consumeApi(urlPath):\n    dataResponse = requests.get(urlPath)\n    return None if (dataResponse.status_code != 200) else dataResponse.text\n</code></pre>"},{"location":"reference/himatcal/recipes/mol/core.html#himatcal.recipes.mol.core.get_molecular_structure","title":"get_molecular_structure","text":"<pre><code>get_molecular_structure(molecular_cas: str, write_mol: bool = True, chemspider_api: str = CHEMSPIDER_API_KEY)\n</code></pre> <p>Get molecular structure from CAS number, using chemspipy from RSC ChemSpider.</p> <p>This function retrieves the molecular structure corresponding to the provided CAS number from ChemSpider, processes it, and optionally writes it to a file in XYZ format.</p> <p>Args:     molecular_cas (str): The CAS number of the molecule.     write_mol (str | None): The file name to write the molecular structure to in XYZ format. Defaults to None.     chemspider_api (str): The ChemSpider API key. Defaults to the value in SETTINGS.CHEMSPIDER_API_KEY.</p> <p>Returns:     None</p> Source code in <code>himatcal/recipes/mol/core.py</code> <pre><code>def get_molecular_structure(\n    molecular_cas: str,\n    write_mol: bool = True,\n    chemspider_api: str = SETTINGS.CHEMSPIDER_API_KEY,\n):\n    \"\"\"\n    Get molecular structure from CAS number, using chemspipy from RSC ChemSpider.\n\n    This function retrieves the molecular structure corresponding to the provided CAS number from ChemSpider, processes it, and optionally writes it to a file in XYZ format.\n\n    Args:\n        molecular_cas (str): The CAS number of the molecule.\n        write_mol (str | None): The file name to write the molecular structure to in XYZ format. Defaults to None.\n        chemspider_api (str): The ChemSpider API key. Defaults to the value in SETTINGS.CHEMSPIDER_API_KEY.\n\n    Returns:\n        None\n    \"\"\"\n\n    cs = ChemSpider(chemspider_api)\n    c1 = cs.search(molecular_cas)[0]\n    try:\n        mol_file = StringIO(c1.mol_3d)\n        mol = Chem.MolFromMolBlock(mol_file.getvalue(), removeHs=False)\n        mol = Chem.AddHs(mol, addCoords=True)\n        if write_mol:\n            Chem.MolToXYZFile(mol, f\"{molecular_cas}.xyz\")\n        return mol\n    except Exception as e:\n        return f\"Unexpected error: {e}\"\n</code></pre>"},{"location":"reference/himatcal/recipes/quacc/core.html","title":"core","text":""},{"location":"reference/himatcal/recipes/quacc/core.html#himatcal.recipes.quacc.core.relax_job","title":"relax_job","text":"<pre><code>relax_job(atoms: Atoms, calc, relax_cell: bool = False, opt_params: OptParams | None = None, additional_fields: dict[str, Any] | None = None) -&gt; OptSchema\n</code></pre> Source code in <code>himatcal/recipes/quacc/core.py</code> <pre><code>@job\ndef relax_job(\n    atoms: Atoms,\n    calc,\n    relax_cell: bool = False,\n    opt_params: OptParams | None = None,\n    additional_fields: dict[str, Any] | None = None,\n) -&gt; OptSchema:\n    opt_defaults = {\"fmax\": 0.05, \"max_steps\": 1000}\n    opt_flags = recursive_dict_merge(opt_defaults, opt_params)\n\n    dyn = Runner(atoms, calc).run_opt(relax_cell=relax_cell, **opt_flags)\n\n    return Summarize(\n        additional_fields={\"name\": \"MLP Relax\"} | (additional_fields or {})\n    ).opt(dyn)\n</code></pre>"},{"location":"reference/himatcal/tools/db.html","title":"db","text":""},{"location":"reference/himatcal/tools/db.html#himatcal.tools.db.load_from_db","title":"load_from_db","text":"<pre><code>load_from_db(label, database='himat', collection_name='job')\n</code></pre> <p>Load a document from the database.</p> Source code in <code>himatcal/tools/db.py</code> <pre><code>def load_from_db(label, database=\"himat\", collection_name=\"job\"):\n    \"\"\"\n    Load a document from the database.\n    \"\"\"\n    store = MongoURIStore(\n        uri=SETTINGS.MONGODB_URI,\n        database=database,\n        collection_name=collection_name,\n    )\n\n    with store:\n        documents = store.query(criteria={\"label\": label})\n    if len(documents) == 0:\n        logging.debug(f\"{label} not found in the database!\")\n        return None\n    else:\n        logging.debug(f\"{label} has been loaded from the database!\")\n        return documents\n</code></pre>"},{"location":"reference/himatcal/tools/db.html#himatcal.tools.db.save_to_db","title":"save_to_db","text":"<pre><code>save_to_db(label, info=None, database='himat', collection_name='job')\n</code></pre> <p>Save a document to the database.</p> Source code in <code>himatcal/tools/db.py</code> <pre><code>def save_to_db(label, info=None, database=\"himat\", collection_name=\"job\"):\n    \"\"\"\n    Save a document to the database.\n    \"\"\"\n    if info is None:\n        info = {}\n    store = MongoURIStore(\n        uri=SETTINGS.MONGODB_URI,\n        database=database,\n        collection_name=collection_name,\n    )\n\n    base_info = {\n        \"label\": label,\n        \"time\": jsanitize(datetime.now(timezone.utc).strftime(\"%Y-%m-%d %H:%M:%S\")),\n    }\n\n    document = {**base_info, **info}\n    with store:\n        store.update([document])\n    logging.debug(f\"{label} has been saved to the database!\")\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html","title":"mpdownload","text":""},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.data","title":"data  <code>module-attribute</code>","text":"<pre><code>data = get_mp_chemsys(input_content)\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.extract_data","title":"extract_data  <code>module-attribute</code>","text":"<pre><code>extract_data = extract_mp_prop(data)\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.input_content","title":"input_content  <code>module-attribute</code>","text":"<pre><code>input_content = argv[2]\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.input_type","title":"input_type  <code>module-attribute</code>","text":"<pre><code>input_type = argv[1]\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.mpr","title":"mpr  <code>module-attribute</code>","text":"<pre><code>mpr = MPRester(api_key=MAPI_KEY)\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.path","title":"path  <code>module-attribute</code>","text":"<pre><code>path = argv[3]\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.extract_mp_data","title":"extract_mp_data","text":"<pre><code>extract_mp_data(material_id, path)\n</code></pre> Source code in <code>himatcal/tools/mpdownload.py</code> <pre><code>def extract_mp_data(material_id, path):\n    stru = mpr.materials.summary.search(material_ids=[material_id])\n    stru = stru[0].structure.to(fmt=\"poscar\", filename=f\"{path}/{material_id}.vasp\")\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.extract_mp_prop","title":"extract_mp_prop","text":"<pre><code>extract_mp_prop(MPdoc)\n</code></pre> Source code in <code>himatcal/tools/mpdownload.py</code> <pre><code>def extract_mp_prop(MPdoc):\n    data = {\n        \"MPID\": [],\n        \"formula\": [],\n        \"CrystalSystem\": [],\n        \"SpaceGroup\": [],\n        \"nsites\": [],\n        \"EHull\": [],\n        \"BandGap\": [],\n    }\n    for i in range(len(MPdoc)):\n        data[\"MPID\"].append(\"mp-\" + str(MPdoc[i].material_id.split(\"-\")[1]))\n        data[\"formula\"].append(MPdoc[i].formula_pretty)\n        data[\"CrystalSystem\"].append(str(MPdoc[i].symmetry.crystal_system))\n        data[\"SpaceGroup\"].append(str(MPdoc[i].symmetry.symbol))\n        data[\"nsites\"].append(MPdoc[i].nsites)\n        data[\"EHull\"].append(MPdoc[i].energy_above_hull)\n        data[\"BandGap\"].append(MPdoc[i].band_gap)\n    return data\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.get_mp_chemsys","title":"get_mp_chemsys","text":"<pre><code>get_mp_chemsys(chemsys)\n</code></pre> Source code in <code>himatcal/tools/mpdownload.py</code> <pre><code>def get_mp_chemsys(chemsys):\n    # chemsys = 'Li-Fe-O'\n    elements = chemsys.split(\"-\")\n    structure = mpr.materials.summary.search(\n        elements=elements,\n        fields=[\n            \"material_id\",\n            \"formula_pretty\",\n            \"nsites\",\n            \"symmetry\",\n            \"energy_above_hull\",\n            \"band_gap\",\n        ],\n    )\n    return structure\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.get_mp_formula","title":"get_mp_formula","text":"<pre><code>get_mp_formula(formula)\n</code></pre> Source code in <code>himatcal/tools/mpdownload.py</code> <pre><code>def get_mp_formula(formula):\n    structure = mpr.materials.summary.search(\n        formula=formula,\n        fields=[\n            \"material_id\",\n            \"formula_pretty\",\n            \"nsites\",\n            \"symmetry\",\n            \"energy_above_hull\",\n            \"band_gap\",\n        ],\n    )\n    return structure\n</code></pre>"},{"location":"reference/himatcal/tools/mpdownload.html#himatcal.tools.mpdownload.get_mp_id","title":"get_mp_id","text":"<pre><code>get_mp_id(material_id)\n</code></pre> Source code in <code>himatcal/tools/mpdownload.py</code> <pre><code>def get_mp_id(material_id):\n    structure = mpr.materials.summary.search(\n        material_ids=[material_id],\n        fields=[\n            \"material_id\",\n            \"formula_pretty\",\n            \"nsites\",\n            \"symmetry\",\n            \"energy_above_hull\",\n            \"band_gap\",\n        ],\n    )\n    return structure\n</code></pre>"},{"location":"reference/himatcal/utils/ase.html","title":"ase","text":""},{"location":"reference/himatcal/utils/ase.html#himatcal.utils.ase.constraints_indices_add","title":"constraints_indices_add","text":"<pre><code>constraints_indices_add(indices_list, num_add) -&gt; list\n</code></pre> <p>Add a specified number to each index in the given list of indices.</p> <p>Args:     indices_list (list of int): A list of indices to be incremented.     num_add (int): The number to add to each index in the list.</p> <p>Returns     list of int: A new list with each index incremented by the specified number.</p> Source code in <code>himatcal/utils/ase.py</code> <pre><code>def constraints_indices_add(indices_list, num_add) -&gt; list:\n    \"\"\"\n    Add a specified number to each index in the given list of indices.\n\n    Args:\n        indices_list (list of int): A list of indices to be incremented.\n        num_add (int): The number to add to each index in the list.\n\n    Returns\n        list of int: A new list with each index incremented by the specified number.\n    \"\"\"\n    return [x + num_add for x in indices_list]\n</code></pre>"},{"location":"reference/himatcal/utils/ct.html","title":"ct","text":"<p>utils for covalent</p>"},{"location":"reference/himatcal/utils/ct.html#himatcal.utils.ct.extract_gaussian_result","title":"extract_gaussian_result","text":"<pre><code>extract_gaussian_result(results, id)\n</code></pre> Source code in <code>himatcal/utils/ct.py</code> <pre><code>def extract_gaussian_result(results, id):\n    final_scf_energy = results.result['attributes']['final_scf_energy']/27.211385 # convert the uint from a.u. to eV\n    parameters = results.result['parameters']\n    input_atoms = results.result['trajectory'][0]\n    final_atoms = results.result['atoms']\n    write('input.xyz',input_atoms)\n    write('final.xyz',final_atoms)\n    with open('log.yaml','w') as f:\n        f.write(f'dispatch_id: {id}\\n')\n        f.write(f'status: \\'{str(results.status.__str__)}\\'\\n')\n        f.write(f'final_scf_energy (a.u.): {final_scf_energy}\\n')\n        f.write(f'parameters: {parameters}\\n')\n    return final_atoms\n</code></pre>"},{"location":"reference/himatcal/utils/ct.html#himatcal.utils.ct.extract_result","title":"extract_result","text":"<pre><code>extract_result(dispatch_id, return_atoms=True)\n</code></pre> <p>extract the result of a covalent job after Gaussian calculation</p> Source code in <code>himatcal/utils/ct.py</code> <pre><code>def extract_result(dispatch_id, return_atoms=True):    # sourcery skip: avoid-builtin-shadow\n    \"\"\"\n    extract the result of a covalent job after Gaussian calculation\n    \"\"\"\n    import os\n    import pickle as pkl\n\n    from monty.os import cd\n    results = ct.get_result(dispatch_id)\n    dispatch_id = results.dispatch_id\n    # create a folder with the dispatch_id\n    os.makedirs(dispatch_id, exist_ok=True)\n    with cd(dispatch_id):\n        with open(f'{dispatch_id}.pkl','wb') as f:\n            pkl.dump(results,f)\n        try:\n            if return_atoms:\n                return extract_gaussian_result(results, dispatch_id)\n            else:\n                extract_gaussian_result(results, dispatch_id)\n                return results # return covalent results\n        except Exception:\n            if results.status.__eq__(_Status__value='RUNNING'):\n                print('Job is still running')\n            with open('log.yaml','w') as f:\n                f.write(f'dispatch_id: {dispatch_id}\\n')\n                f.write(f'job_status: {str(results.status.__str__)}\\n')\n</code></pre>"},{"location":"reference/himatcal/utils/ct.html#himatcal.utils.ct.get_result","title":"get_result","text":"<pre><code>get_result(dispatch_id, job_dir, wait=False)\n</code></pre> <p>extract result in the job_dir</p> Source code in <code>himatcal/utils/ct.py</code> <pre><code>def get_result(dispatch_id, job_dir, wait=False):\n    \"\"\"\n    extract result in the job_dir\n    \"\"\"\n    from monty.os import cd\n    results = ct.get_result(\n        dispatch_id,\n        wait=wait\n    )\n    if results.status.__eq__(\"COMPLETED\") is True:\n        with cd(job_dir):\n            extract_result(dispatch_id)\n            final_scf_energy = (\n                results.result[\"attributes\"][\"final_scf_energy\"] / 27.211385\n            )  # convert to a.u.\n            atoms = results.result[\"atoms\"]\n            write(\"final.xyz\", atoms)\n            print(f\"final_scf_energy (a.u.): {final_scf_energy}\\n\")\n        return atoms\n    else:\n        print(\"The calculation is not completed.\")\n        return None\n</code></pre>"},{"location":"reference/himatcal/utils/os.html","title":"os","text":"<p>os utilities for himatcal</p>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.cclib_result","title":"cclib_result","text":"<pre><code>cclib_result(log_path: Path)\n</code></pre> <p>Extracts and reads computational chemistry log files.</p> <p>This function checks for compressed log files in the specified directory, decompresses the first found file, and reads the contents using the cclib library. It returns the parsed data from the log file.</p> <p>Args:     log_path (Path): The directory path where log files are located.</p> <p>Returns:     object: The parsed data from the log file.</p> <p>Raises:     FileNotFoundError: If no log files are found and the directory is empty.</p> <p>Examples:     result = cclib_result(Path(\"/path/to/logs\"))</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def cclib_result(log_path:Path):\n    \"\"\"Extracts and reads computational chemistry log files.\n\n    This function checks for compressed log files in the specified directory, decompresses the first found file, and reads the contents using the cclib library. It returns the parsed data from the log file.\n\n    Args:\n        log_path (Path): The directory path where log files are located.\n\n    Returns:\n        object: The parsed data from the log file.\n\n    Raises:\n        FileNotFoundError: If no log files are found and the directory is empty.\n\n    Examples:\n        result = cclib_result(Path(\"/path/to/logs\"))\n    \"\"\"\n\n    import contextlib\n    import gzip\n\n    import cclib\n\n    with contextlib.suppress(FileNotFoundError):\n        if gzip_log := list(log_path.glob(\"*.log.gz\")):\n            unzip_file = gzip.decompress(Path.open(gzip_log[0], \"rb\").read())\n            logfile = gzip_log[0].with_suffix(\"\")\n            with Path.open(logfile, \"w\") as f:\n                f.write(unzip_file.decode())\n        log_files = list(log_path.glob(\"*.log\"))\n        return cclib.io.ccread(log_path / log_files[0])\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.extract_fchk","title":"extract_fchk","text":"<pre><code>extract_fchk(label, dzip=False)\n</code></pre> <p>Extracts the formatted checkpoint file (.fchk) from a Gaussian checkpoint file (.chk).</p> <p>Args:     label (str): The label to use for the extracted .fchk file.     dzip (bool, optional): Whether to decompress the Gaussian checkpoint file if it is gzipped.</p> <p>Returns:     None</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def extract_fchk(label, dzip=False):\n    \"\"\"\n    Extracts the formatted checkpoint file (.fchk) from a Gaussian checkpoint file (.chk).\n\n    Args:\n        label (str): The label to use for the extracted .fchk file.\n        dzip (bool, optional): Whether to decompress the Gaussian checkpoint file if it is gzipped.\n\n    Returns:\n        None\n    \"\"\"\n    if dzip:\n        os.system(\"gzip -d Gaussian.chk.gz\")\n    chk_file = Path(\"Gaussian.chk\")\n    if not Path.exists(chk_file):\n        logging.info(f\"{chk_file} not found\")\n        return\n    os.system(f\"formchk {chk_file}\")\n    os.system(f\"mv Gaussian.fchk {label}.fchk\")\n    logging.info(f\"fchk file extracted for {label}\")\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.get_chg_mult","title":"get_chg_mult","text":"<pre><code>get_chg_mult(molname)\n</code></pre> <p>Get the label, charge, and multiplicity from the name of a molecule.</p> <p>Args:     molname (str): The name of the molecule in the format {label}-c{charge}s{multiplicity}.</p> <p>Returns:     tuple: A tuple containing the label (str), charge (int), and multiplicity (int) of the molecule.            If the name does not match the expected format, returns (None, None, None).</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def get_chg_mult(molname):\n    \"\"\"\n    Get the label, charge, and multiplicity from the name of a molecule.\n\n    Args:\n        molname (str): The name of the molecule in the format {label}-c{charge}s{multiplicity}.\n\n    Returns:\n        tuple: A tuple containing the label (str), charge (int), and multiplicity (int) of the molecule.\n               If the name does not match the expected format, returns (None, None, None).\n    \"\"\"\n    import re\n\n    pattern = r\"(.*?)-c(n?\\d)s(\\d+)\"\n    if not (match := re.match(pattern, molname)):\n        return None, None, None\n    label, chg, mult = match.groups()\n    chg = f\"-{chg[1:]}\" if chg.startswith(\"n\") else chg\n    return label, int(chg), int(mult)\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.get_homo_lumo","title":"get_homo_lumo","text":"<pre><code>get_homo_lumo(log_path)\n</code></pre> <p>Extracts HOMO, LUMO, and related energies and gaps from a computational chemistry log file.</p> <p>Args:     logfile (str): Path to the computational chemistry log file.</p> <p>Returns:     dict: A dictionary containing HOMO and LUMO orbitals, energies, gaps, and the minimum HOMO-LUMO gap.</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def get_homo_lumo(log_path):\n    \"\"\"\n    Extracts HOMO, LUMO, and related energies and gaps from a computational chemistry log file.\n\n    Args:\n        logfile (str): Path to the computational chemistry log file.\n\n    Returns:\n        dict: A dictionary containing HOMO and LUMO orbitals, energies, gaps, and the minimum HOMO-LUMO gap.\n    \"\"\"\n\n    data = cclib_result(Path(log_path))\n    HOMO = data.homos + 1\n    LUMO = data.homos + 2\n    homo_energies, lumo_energies, gaps = get_homos_lumos(data.moenergies, data.homos)\n    min_gap = min(gaps)\n    return {\n        \"homo_orbital\": HOMO,\n        \"lumo_orbital\": LUMO,\n        \"homo_energies\": homo_energies,\n        \"lumo_energies\": lumo_energies,\n        \"homo_lumo_gaps\": gaps,\n        \"min_homo_lumo_gap\": min_gap,\n    }\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.get_homos_lumos","title":"get_homos_lumos","text":"<pre><code>get_homos_lumos(moenergies: list[list[float]], homo_indices: list[int]) -&gt; tuple[list[float], list[float], list[float]] | tuple[list[float], None, None]\n</code></pre> <p>Calculate the HOMO, LUMO, and HOMO-LUMO gap energies in eV.</p> <p>Parameters:</p> <ul> <li> <code>moenergies</code>               (<code>list[list[float]]</code>)           \u2013            <p>List of MO energies. For restricted calculations, List[List[float]] is length one. For unrestricted, it is length two.</p> </li> <li> <code>homo_indices</code>               (<code>list[int]</code>)           \u2013            <p>Indices of the HOMOs.</p> </li> </ul> <p>Returns:</p> <ul> <li> <code>homo_energies</code>           \u2013            <p>The HOMO energies (eV), split by alpha and beta</p> </li> <li> <code>lumo_energies</code>           \u2013            <p>The LUMO energies (eV), split by alpha and beta</p> </li> <li> <code>homo_lumo_gaps</code>           \u2013            <p>The HOMO-LUMO gaps (eV), calculated as LUMO_alpha-HOMO_alpha and LUMO_beta-HOMO_beta</p> </li> </ul> Source code in <code>himatcal/utils/os.py</code> <pre><code>def get_homos_lumos(\n    moenergies: list[list[float]], homo_indices: list[int]\n) -&gt; tuple[list[float], list[float], list[float]] | tuple[list[float], None, None]:\n    \"\"\"\n    Calculate the HOMO, LUMO, and HOMO-LUMO gap energies in eV.\n\n    Parameters\n    ----------\n    moenergies\n        List of MO energies. For restricted calculations, List[List[float]] is\n        length one. For unrestricted, it is length two.\n    homo_indices\n        Indices of the HOMOs.\n\n    Returns\n    -------\n    homo_energies\n        The HOMO energies (eV), split by alpha and beta\n    lumo_energies\n        The LUMO energies (eV), split by alpha and beta\n    homo_lumo_gaps\n        The HOMO-LUMO gaps (eV), calculated as LUMO_alpha-HOMO_alpha and\n        LUMO_beta-HOMO_beta\n    \"\"\"\n    homo_energies = [moenergies[i][h] for i, h in enumerate(homo_indices)]\n    # Make sure that the HOMO+1 (i.e. LUMO) is in moenergies (sometimes virtual\n    # orbitals aren't printed in the output)\n    for i, h in enumerate(homo_indices):\n        if len(moenergies[i]) &lt; h + 2:\n            return homo_energies, None, None\n    lumo_energies = [moenergies[i][h + 1] for i, h in enumerate(homo_indices)]\n    homo_lumo_gaps = [\n        lumo_energies[i] - homo_energies[i] for i in range(len(homo_energies))\n    ]\n    return homo_energies, lumo_energies, homo_lumo_gaps\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.labeled_dir","title":"labeled_dir","text":"<pre><code>labeled_dir(main_workdir: Path, label: str)\n</code></pre> <p>Create a new folder in the main working directory with the provided label.</p> <p>Args:     main_workdir (Path): The main working directory.     label (str): The label of the folder.</p> <p>Returns:     Path: The path of the new folder.</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def labeled_dir(main_workdir: Path, label: str):\n    \"\"\"\n    Create a new folder in the main working directory with the provided label.\n\n    Args:\n        main_workdir (Path): The main working directory.\n        label (str): The label of the folder.\n\n    Returns:\n        Path: The path of the new folder.\n    \"\"\"\n    folder_names = [p.name for p in main_workdir.iterdir() if p.is_dir()]\n    numbers = (\n        int(re.search(r\"\\d+\", name).group())\n        for name in folder_names\n        if re.search(r\"\\d+\", name)\n    )\n    new_number = max(numbers, default=0) + 1\n    # Create new folder\n    folder_name = f\"{new_number:02d}.{label}\"\n    folder_path = main_workdir / folder_name\n    Path.mkdir(folder_path, parents=True, exist_ok=True)\n    return folder_path\n</code></pre>"},{"location":"reference/himatcal/utils/os.html#himatcal.utils.os.write_chg_mult_label","title":"write_chg_mult_label","text":"<pre><code>write_chg_mult_label(label, chg, mult)\n</code></pre> <p>Write the label, chg and mult to a string, format: {label}-c{charge}s{mult}</p> Source code in <code>himatcal/utils/os.py</code> <pre><code>def write_chg_mult_label(label, chg, mult):\n    \"\"\"Write the label, chg and mult to a string, format: {label}-c{charge}s{mult}\"\"\"\n    if chg &lt; 0:\n        chg = f\"n{abs(chg)}\"\n    return f\"{label}-c{chg}s{mult}\"\n</code></pre>"},{"location":"reference/himatcal/utils/visualization.html","title":"visualization","text":"<p>functions using for visualization</p>"},{"location":"reference/himatcal/utils/visualization.html#himatcal.utils.visualization.init_style","title":"init_style","text":"<pre><code>init_style()\n</code></pre> <p>Use the science style for matplotlib plots.</p> <p>This function sets the style and font family for matplotlib plots to a predefined science style.</p> <p>Args:     None</p> <p>Returns:     None</p> Source code in <code>himatcal/utils/visualization.py</code> <pre><code>def init_style():\n    \"\"\"\n    Use the science style for matplotlib plots.\n\n    This function sets the style and font family for matplotlib plots to a predefined science style.\n\n    Args:\n        None\n\n    Returns:\n        None\n    \"\"\"\n\n    import matplotlib.pyplot as plt\n    import pkg_resources\n\n    plt.style.use(\n        pkg_resources.resource_filename(\"himatcal\", \"tools/science-1.mplstyle\")\n    )\n    plt.rcParams[\"font.family\"] = \"Calibri, Microsoft YaHei\"\n</code></pre>"},{"location":"reference/himatcal/utils/visualization.html#himatcal.utils.visualization.mpl_view_atoms","title":"mpl_view_atoms","text":"<pre><code>mpl_view_atoms(atoms)\n</code></pre> <p>view atoms using matplotlib at top and side view</p> Source code in <code>himatcal/utils/visualization.py</code> <pre><code>def mpl_view_atoms(atoms):\n    \"\"\"\n    view atoms using matplotlib at top and side view\n    \"\"\"\n    import matplotlib.pyplot as plt\n    from ase.visualize.plot import plot_atoms\n\n    fig, axs = plt.subplots(1, 2, figsize=(5, 5))\n    plot_atoms(atoms, axs[0])\n    plot_atoms(atoms, axs[1], rotation=(\"-90x\"))\n</code></pre>"},{"location":"reference/himatcal/utils/visualization.html#himatcal.utils.visualization.show_xyz_mol","title":"show_xyz_mol","text":"<pre><code>show_xyz_mol(xyz_file: Path)\n</code></pre> <p>Visualize a stk molecule using py3Dmol.</p> Source code in <code>himatcal/utils/visualization.py</code> <pre><code>def show_xyz_mol(xyz_file: Path):\n    \"\"\"\n    Visualize a stk molecule using py3Dmol.\n    \"\"\"\n    import py3Dmol\n\n    mol = Path.open(xyz_file).read()\n    p = py3Dmol.view(\n        data=mol,\n        style={\"stick\": {\"colorscheme\": \"Jmol\"}},\n        width=400,\n        height=400,\n    )\n    p.setBackgroundColor(\"white\")\n    p.zoomTo()\n    p.show()\n</code></pre>"},{"location":"reference/himatcal/utils/visualization.html#himatcal.utils.visualization.view_atoms","title":"view_atoms","text":"<pre><code>view_atoms(atoms: Atoms, fmt='xyz')\n</code></pre> <p>View atoms using a 3D molecular viewer.</p> <p>Args:     atoms: The molecular structure to visualize.     fmt: The format in which to save the molecular structure (default is \"xyz\").</p> <p>Returns:     A 3D molecular viewer displaying the atoms.</p> <p>Raises:     FileNotFoundError: If the temporary file \"tmp_atoms\" is not found.</p> Source code in <code>himatcal/utils/visualization.py</code> <pre><code>def view_atoms(atoms: Atoms, fmt=\"xyz\"):\n    \"\"\"\n    View atoms using a 3D molecular viewer.\n\n    Args:\n        atoms: The molecular structure to visualize.\n        fmt: The format in which to save the molecular structure (default is \"xyz\").\n\n    Returns:\n        A 3D molecular viewer displaying the atoms.\n\n    Raises:\n        FileNotFoundError: If the temporary file \"tmp_atoms\" is not found.\n    \"\"\"\n\n    import py3Dmol\n    from ase.io import write\n\n    Path(\".cache\").mkdir(exist_ok=True)\n    tmp_path = Path(\".cache/tmp_atoms\")\n    write(tmp_path, atoms, format=fmt)\n    atoms_data = Path.open(tmp_path).read()\n    view = py3Dmol.view(width=800, height=400)\n    view.addModel(atoms_data, format)\n    view.setStyle({\"stick\": {}})\n    view.zoomTo()\n    return view\n</code></pre>"},{"location":"reference/himatcal/utils/visualization.html#himatcal.utils.visualization.xyz_to_mol","title":"xyz_to_mol","text":"<pre><code>xyz_to_mol(xyz_file: Path, write_mol=True)\n</code></pre> <p>Convert a xyz file to a mol file and block.</p> Source code in <code>himatcal/utils/visualization.py</code> <pre><code>def xyz_to_mol(xyz_file: Path, write_mol=True):\n    \"\"\"\n    Convert a xyz file to a mol file and block.\n    \"\"\"\n    from openbabel import pybel as pb\n\n    # ! openbabel is a conda package, try other packages if openbabel is not available.\n    mol = next(pb.readfile(\"xyz\", xyz_file))\n    if write_mol:\n        mol.write(\"mol\", f\"{xyz_file}.mol\", overwrite=True)\n        return Path.open(f\"{xyz_file}.mol\").read()\n    return None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html","title":"chem","text":"<p>--chem.py-- Declaring classes. (Intermediates, molecules, atoms, ...) Some parts can be replaced by ASE formats, but now we are using these settings for convenient customization.</p>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom","title":"Atom","text":"<pre><code>Atom(data=None)\n</code></pre> <p>:class Atom:     class Atom mainly contains atomic_number, element, and x,     Other attributes are not widely used     molecule_index shows on which molecule that this atom is contained in. For example, if we consider Intermediate C.C,     molecule_index can have either 0 or 1, and every atom within atom_list of Intermediate can be assigned by checking     which molecule does the atom belong to.</p> <p>:param data(str or integer):     Data is either symbol that represents element or atomic number</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def __init__(self, data=None):\n    self.atomic_number = None\n    self.element = None\n    self.x = 0.00\n    self.y = 0.00\n    self.z = 0.00\n    self.molecule_index = 0\n    self.is_divalent_hydrogen = False\n    if data is not None:\n        if type(data) is str:\n            self.element = data\n        else:\n            self.atomic_number = data\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.atomic_number","title":"atomic_number  <code>instance-attribute</code>","text":"<pre><code>atomic_number = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.element","title":"element  <code>instance-attribute</code>","text":"<pre><code>element = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.is_divalent_hydrogen","title":"is_divalent_hydrogen  <code>instance-attribute</code>","text":"<pre><code>is_divalent_hydrogen = False\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.molecule_index","title":"molecule_index  <code>instance-attribute</code>","text":"<pre><code>molecule_index = 0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.periodic_table","title":"periodic_table  <code>class-attribute</code>","text":"<pre><code>periodic_table: list[str] = ['H', 'He', 'Li', 'Be', 'B', 'C', 'N', 'O', 'F', 'Ne', 'Na', 'Mg', 'Al', 'Si', 'P', 'S', 'Cl', 'Ar', 'K', 'Ca', 'Sc', 'Ti', 'V', 'Cr', 'Mn', 'Fe', 'Co', 'Ni', 'Cu', 'Zn', 'Ga', 'Ge', 'As', 'Se', 'Br', 'Kr', 'Rb', 'Sr', 'Y', 'Zr', 'Nb', 'Mo', 'Tc', 'Ru', 'Rh', 'Pd', 'Ag', 'Cd', 'In', 'Sn', 'Sb', 'Te', 'I', 'Xe', 'Cs', 'Ba', 'La', 'Ce', 'Pr', 'Nd', 'Pm', 'Sm', 'Eu', 'Gd', 'Tb', 'Dy', 'Ho', 'Er', 'Tm', 'Yb', 'Lu', 'Hf', 'Ta', 'W', 'Re', 'Os', 'Ir', 'Pt', 'Au', 'Hg', 'Tl', 'Pb', 'Bi', 'Po', 'At', 'Rn']\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.x","title":"x  <code>instance-attribute</code>","text":"<pre><code>x = 0.0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.y","title":"y  <code>instance-attribute</code>","text":"<pre><code>y = 0.0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.z","title":"z  <code>instance-attribute</code>","text":"<pre><code>z = 0.0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.__eq__","title":"__eq__","text":"<pre><code>__eq__(atom)\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def __eq__(self, atom):\n    return self.is_same_atom(atom)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.copy","title":"copy","text":"<pre><code>copy()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def copy(self):\n    new_atom = Atom()\n    # Copy all attributes\n    new_atom.atomic_number = self.atomic_number\n    new_atom.element = self.element\n    new_atom.x = self.x\n    new_atom.y = self.y\n    new_atom.z = self.z\n    return new_atom\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_atomic_number","title":"get_atomic_number","text":"<pre><code>get_atomic_number()\n</code></pre> <p>Returns the atomic number (number of protons) of a given atom.</p> <p>:param:</p> <p>:return integer:     Directly the atomic number of a given atom is returned</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_atomic_number(self):\n    \"\"\"\n    Returns the atomic number (number of protons) of a given atom.\n\n    :param:\n\n    :return integer:\n        Directly the atomic number of a given atom is returned\n    \"\"\"\n    if self.atomic_number == None:\n        element = self.element\n        if element == None:\n            print(\"atom is not specified!\")\n        if len(element) &gt; 1:\n            end_part = element[1:]\n            end_part = str.lower(end_part)\n            element = element[0] + end_part\n            self.element = element\n        if element in periodic_table:\n            index = periodic_table.index(element)\n            self.atomic_number = index + 1\n        else:\n            print(\"element\", element)\n            print(\"modify periodic table!!!\")\n    return self.atomic_number\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_content","title":"get_content","text":"<pre><code>get_content(option='element', criteria=0.0001)\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_content(self, option=\"element\", criteria=1e-4):\n    x = self.x\n    y = self.y\n    z = self.z\n    if abs(x) &lt; criteria:\n        x = 0.00\n    if abs(y) &lt; criteria:\n        y = 0.00\n    if abs(z) &lt; criteria:\n        z = 0.00\n    content = \" \" + str(x) + \" \" + str(y) + \" \" + str(z) + \"\\n\"\n    if option == \"element\":\n        content = self.get_element() + content\n    else:\n        content = str(self.get_atomic_number()) + content\n    return content\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_coordinate","title":"get_coordinate","text":"<pre><code>get_coordinate()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_coordinate(self):\n    return np.array([self.x, self.y, self.z])\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_element","title":"get_element","text":"<pre><code>get_element()\n</code></pre> <p>Returns symbol of a given atom.</p> <p>:param:</p> <p>:return str:     Directly the symbol of a given atom is returned</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_element(self):\n    \"\"\"\n    Returns symbol of a given atom.\n\n    :param:\n\n    :return str:\n        Directly the symbol of a given atom is returned\n    \"\"\"\n    if self.element == None:\n        atomic_number = self.atomic_number\n        if atomic_number == None:\n            print(\"atom is not specified!\")\n        z = int(self.atomic_number) - 1\n        self.element = periodic_table[z]\n    return self.element\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_mass","title":"get_mass","text":"<pre><code>get_mass()\n</code></pre> <p>Returns the exact value (float) of an atomic mass of a given atom.</p> <p>:param:</p> <p>:return float:     Directly the atomic mass of a given atom is returned</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_mass(self):\n    \"\"\"\n    Returns the exact value (float) of an atomic mass of a given atom.\n\n    :param:\n\n    :return float:\n        Directly the atomic mass of a given atom is returned\n    \"\"\"\n    element = self.get_element()\n    a = str.lower(element)\n    if a == \"h\":\n        return 1.008\n    elif a == \"he\":\n        return 4.003\n    elif a == \"li\":\n        return 6.941\n    elif a == \"be\":\n        return 9.012\n    elif a == \"b\":\n        return 10.81\n    elif a == \"c\":\n        return 12.01\n    elif a == \"n\":\n        return 14.01\n    elif a == \"o\":\n        return 16.00\n    elif a == \"f\":\n        return 19.00\n    elif a == \"ne\":\n        return 20.18\n    elif a == \"na\":\n        return 22.99\n    elif a == \"mg\":\n        return 24.31\n    elif a == \"al\":\n        return 26.98\n    elif a == \"si\":\n        return 28.09\n    elif a == \"p\":\n        return 30.97\n    elif a == \"s\":\n        return 32.07\n    elif a == \"cl\":\n        return 35.45\n    elif a == \"ar\":\n        return 39.95\n    elif a == \"k\":\n        return 39.10\n    elif a == \"ca\":\n        return 40.08\n    elif a == \"au\":\n        return 196.97\n    elif a == \"co\":\n        return 58.9332\n    elif a == \"ni\":\n        return 58.6934\n    elif a == \"ti\":\n        return 47.8671\n    elif a == \"fe\":\n        return 55.845\n    elif a == \"br\":\n        return 79.904\n    elif a == \"rh\":\n        return 102.90550\n    elif a == \"pd\":\n        return 106.42\n    elif a == \"hf\":\n        return 178.49\n    elif a == \"i\":\n        return 126.90447\n    else:\n        return 0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_period_group","title":"get_period_group","text":"<pre><code>get_period_group()\n</code></pre> <p>Returns a period,group information from a given atom. It finds period, group by identifying electron configuration (orbital configuration)</p> <p>:param:</p> <p>:return period,group(int,int):     Note that these values are actual period and group. If C atomm is given, it returns 2,4</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_period_group(self):\n    \"\"\"\n    Returns a period,group information from a given atom. It finds period, group by identifying\n    electron configuration (orbital configuration)\n\n    :param:\n\n    :return period,group(int,int):\n        Note that these values are actual period and group. If C atomm is given, it returns 2,4\n\n    \"\"\"\n    atomic_number = self.get_atomic_number()\n    num_of_electrons = atomic_number\n    # Orbital: [n,l,num_of_electrons]\n    sum_of_n_and_l = 1\n    orbital_configuration = []\n    while num_of_electrons &gt; 0:\n        # Generate orbitals within sum_of_n_and_l=k\n        # New orbitals are introduced for (k+1)/2\n        maximal_l = int((sum_of_n_and_l - 1) / 2)\n        for l in range(maximal_l, -1, -1):\n            # Start with lowest l\n            if num_of_electrons &gt; 4 * l + 2:\n                num_of_electrons -= 4 * l + 2\n                orbital_configuration.append([sum_of_n_and_l - l, l, 4 * l + 2])\n            else:\n                orbital_configuration.append(\n                    [sum_of_n_and_l - l, l, num_of_electrons]\n                )\n                num_of_electrons = 0\n                break\n        sum_of_n_and_l += 1\n    # Get maximal n and l\n    period = 0\n    for orbital in orbital_configuration:\n        if orbital[0] &gt; period:\n            period = orbital[0]\n    # If transition metal, we add 9, Sc has group 9 for else, we do not consider ...\n    last_orbital = orbital_configuration[-1]\n    if last_orbital[1] &lt; 2:\n        group = 2 * last_orbital[1] ** 2 + last_orbital[2]\n    else:\n        group = 8 + last_orbital[2]\n    return period, group\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.get_radius","title":"get_radius","text":"<pre><code>get_radius()\n</code></pre> <p>Returns a radius information of a given atom. Reference is given here: Dalton Trans., 2008, 2832-2838</p> <p>:param:</p> <p>:return float:     It directly returns the reference values</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_radius(self):\n    \"\"\"\n    Returns a radius information of a given atom. Reference is given here: Dalton Trans., 2008, 2832-2838\n\n    :param:\n\n    :return float:\n        It directly returns the reference values\n    \"\"\"\n    element = self.get_element()\n    a = str.lower(element)\n    # reference : Dalton Trans., 2008, 2832-2838\n    if a == \"h\":\n        return 0.31\n    elif a == \"li\":\n        return 1.28\n    elif a == \"be\":\n        return 0.96\n    elif a == \"b\":\n        return 0.84\n    elif a == \"c\":\n        return 0.76\n    elif a == \"n\":\n        return 0.71\n    elif a == \"o\":\n        return 0.66\n    elif a == \"f\":\n        return 0.57\n    elif a == \"na\":\n        return 1.66\n    elif a == \"mg\":\n        return 1.41\n    elif a == \"al\":\n        return 1.21\n    elif a == \"si\":\n        return 1.11\n    elif a == \"p\":\n        return 1.07\n    elif a == \"s\":\n        return 1.05\n    elif a == \"cl\":\n        return 1.02\n    elif a == \"ar\":\n        return 0.76\n    elif a == \"k\":\n        return 2.03\n    elif a == \"ca\":\n        return 1.76\n    elif a == \"co\":\n        return 1.38  # 1/2*(lowspin+highspin)\n    # elif a=='co': return 1.26 #lowspin\n    # elif a=='co': return 1.50 #highspin\n    elif a == \"fe\":\n        return 1.42  # 1/2*(lowspin+highspin)\n    elif a == \"ni\":\n        return 1.24\n    # elif a=='cr': return 1.39\n    elif a == \"ti\":\n        return 1.60\n    elif a == \"br\":\n        return 1.20\n    elif a == \"rh\":\n        return 1.42\n    elif a == \"pd\" or a == \"i\":\n        return 1.39\n    elif a == \"hf\":\n        return 1.75\n    else:\n        return 0\n\n    # reference : J. Chem. Phys. 41, 3199 (1964)\n    \"\"\"\n    if a=='h': return 0.25\n    elif a=='li': return 1.45\n    elif a=='be': return 1.05\n    elif a=='b': return 0.85\n    elif a=='c': return 0.70\n    elif a=='n': return 0.65\n    elif a=='o': return 0.60\n    elif a=='f': return 0.50\n    elif a=='na': return 1.80\n    elif a=='mg': return 1.50\n    elif a=='al': return 1.25\n    elif a=='si': return 1.10\n    elif a=='p': return 1.00\n    elif a=='s': return 1.00\n    elif a=='cl': return 1.00\n    elif a=='ar': return 0.71\n    elif a=='k': return 2.20\n    elif a=='ca': return 1.80\n    elif a=='co': return 1.35\n    else: return 0\n    \"\"\"\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.is_same_atom","title":"is_same_atom","text":"<pre><code>is_same_atom(atom)\n</code></pre> <p>Returns whether the two atoms have same type by comparing atomic number</p> <p>:param atom(pyclass 'Atom'):     Our defined class 'Atom'</p> <p>:return:     True: Two atoms are same type     False: Two atoms are different type</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def is_same_atom(self, atom):\n    \"\"\"\n    Returns whether the two atoms have same type by comparing atomic number\n\n    :param atom(pyclass 'Atom'):\n        Our defined class 'Atom'\n\n    :return:\n        True: Two atoms are same type\n        False: Two atoms are different type\n    \"\"\"\n    atomic_number = self.get_atomic_number()\n    atomic_number_prime = atom.get_atomic_number()\n    return atomic_number == atomic_number_prime\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.set_atomic_number","title":"set_atomic_number","text":"<pre><code>set_atomic_number(atomic_number)\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def set_atomic_number(self, atomic_number):\n    self.atomic_number = atomic_number\n    self.element = periodic_table[atomic_number - 1]\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.set_coordinate","title":"set_coordinate","text":"<pre><code>set_coordinate(position)\n</code></pre> <p>Set Cartesian coordinates of an atom</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def set_coordinate(self, position):\n    \"\"\"Set Cartesian coordinates of an atom\"\"\"\n    dim = len(position)\n    if dim == 2:\n        x = position[0]\n        y = position[1]\n        z = 0\n    elif dim == 3:\n        x = position[0]\n        y = position[1]\n        z = position[2]\n    self.x = x\n    self.y = y\n    self.z = z\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Atom.set_element","title":"set_element","text":"<pre><code>set_element(element)\n</code></pre> <p>Type of an atom. e.g. 'C', 'H', 'O', and so on.</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def set_element(self, element):\n    \"\"\"Type of an atom. e.g. 'C', 'H', 'O', and so on.\"\"\"\n    self.element = element\n    self.atomic_number = periodic_table.index(element) + 1\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule","title":"Molecule","text":"<pre><code>Molecule(data=None)\n</code></pre> <p>:class Molecule:     class Molecule mainly contains atom_list, atom_feature, chg, bo_matrix, adj_matrix, energy, smiles, c_eig_list     atom_list is a list of atom (pyclass 'Atom')     atom_feature is a dict, where features of atom such as formal charge, number of pi bonds, etc, are stored.     Those information can be freely added by giving new dict     c_eig_list can be used to identify whether the given two molecules are the same. This c_eig_list is invariant     to the permutation of atom indexing, identification between any two generated molecules can be easily checked.</p> <p>:param data(str or xyz file or None):     data should be feeded as either smiles(str), xyz file(file) or None     * If smiles is used, rd_mol is generated using the given smiles and converted into ace_mol (pyclass 'Molecule)     * If xyz file is used, directly the 3d geometry of the given molecule is generated. If you want to generate adj_matrix,     bo_matrix, chg_list, etc, refer following method contained in pyclass 'Molecule' (charge of molecule should be given!!!)     i. Generate adj_matrix by using 'get_adj_matrix_from_distance' stored in class 'Molecule'     ii. Generate bo_matrix by using 'get_adj_matrix_from_adj_matrix' stored in class 'Molecule'     iii. Then, using those bo_matrix, get chg_list by using 'get_chg_list_from_bo_matrix' stored n class 'Molecule'     * If None is used, only blank virtual molecule is generated</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def __init__(self, data=None):\n    self.atom_list = []\n    self.atom_feature = dict()\n    self.adj_matrix = None\n    self.bo_matrix = None\n    self.chg = None\n    self.energy = None\n    self.smiles = None\n    self.multiplicity = None\n\n    if data == None:\n        pass\n\n    elif (type(data) == str) and (data[-4:] == \".xyz\"):\n        # data is already opened file\n        f = open(data)\n        atom_list = []\n        try:\n            atom_num = int(f.readline())\n        except:\n            print(\"Wrong format! Should start with number of atoms!\")\n        try:\n            energy = float(f.readline())\n            self.energy = energy\n        except:\n            self.energy = None\n        for i in range(atom_num):\n            try:\n                content = f.readline().strip()\n                atom_line = content.split()\n                # atomic_number = int(atom_line[0])\n                element_symbol = atom_line[0]\n                x = float(atom_line[1])\n                y = float(atom_line[2])\n                z = float(atom_line[3])\n                new_atom = Atom(element_symbol)\n                new_atom.x = x\n                new_atom.y = y\n                new_atom.z = z\n                atom_list.append(new_atom)\n            except:\n                print(\"Error found in:\", content)\n                print(\"Check the file again:\", data)\n        self.atom_list = atom_list\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.adj_matrix","title":"adj_matrix  <code>instance-attribute</code>","text":"<pre><code>adj_matrix = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.atom_feature","title":"atom_feature  <code>instance-attribute</code>","text":"<pre><code>atom_feature = dict()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.atom_list","title":"atom_list  <code>instance-attribute</code>","text":"<pre><code>atom_list = []\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.bo_matrix","title":"bo_matrix  <code>instance-attribute</code>","text":"<pre><code>bo_matrix = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.chg","title":"chg  <code>instance-attribute</code>","text":"<pre><code>chg = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.energy","title":"energy  <code>instance-attribute</code>","text":"<pre><code>energy = energy\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.multiplicity","title":"multiplicity  <code>instance-attribute</code>","text":"<pre><code>multiplicity = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.smiles","title":"smiles  <code>instance-attribute</code>","text":"<pre><code>smiles = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.copy","title":"copy","text":"<pre><code>copy()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def copy(self):\n    new_molecule = Molecule()\n    atom_list = self.atom_list\n    # First copy atoms\n    new_atom_list = []\n    for atom in atom_list:\n        new_atom_list.append(atom.copy())\n    new_molecule.atom_list = new_atom_list\n    # Copy connectivity information\n    bo_matrix = self.get_bo_matrix()\n    if bo_matrix is not None:\n        new_molecule.bo_matrix = np.copy(bo_matrix)\n    else:\n        adj_matrix = self.get_adj_matrix()\n        if adj_matrix is not None:\n            new_molecule.adj_matrix = np.copy(adj_matrix)\n        else:\n            print(\n                \"Warning: Connectivity information is not included in the molecule!!!\"\n            )\n    return new_molecule\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_adj_matrix","title":"get_adj_matrix","text":"<pre><code>get_adj_matrix()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_adj_matrix(self):\n    if self.adj_matrix is not None:\n        return self.adj_matrix\n    if self.bo_matrix is not None:\n        adj_matrix = np.where(self.bo_matrix &gt; 0, 1, 0)\n        return adj_matrix\n    return None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_angle_between_atoms","title":"get_angle_between_atoms","text":"<pre><code>get_angle_between_atoms(idx1, idx2, idx3, unit='rad')\n</code></pre> <p>Returns the distance between chosen two atoms</p> <p>:param idx1,idx2(int):     indices of chosen two atoms.</p> <p>:return distance(float):     Distance between selected two atoms</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_angle_between_atoms(self, idx1, idx2, idx3, unit=\"rad\"):\n    \"\"\"\n    Returns the distance between chosen two atoms\n\n    :param idx1,idx2(int):\n        indices of chosen two atoms.\n\n    :return distance(float):\n        Distance between selected two atoms\n\n    \"\"\"\n    coordinate_list = self.get_coordinate_list()\n    angle = ic.get_angle(coordinate_list, idx1, idx2, idx3)\n    if unit == \"degree\":\n        angle *= 180 / np.pi\n    return angle\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_bo_matrix","title":"get_bo_matrix","text":"<pre><code>get_bo_matrix()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_bo_matrix(self):\n    return self.bo_matrix\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_bond_list","title":"get_bond_list","text":"<pre><code>get_bond_list(contain_bond_order=True)\n</code></pre> <p>Returns the total bond list as list of tuples For example, if CH4 is given with atom order [C,H,H,H,H], if contain_bond_order = False, the output is given as [(0,1),(0,2),(0,3),(0,4)] if contain_bond_order = True, the output is given as [(0,1,1),(0,2,1),(0,3,1),(0,4,1)]</p> <p>:param contain_bond_order(boolean):     If contain_bond_order is False, it only returns bonds represented as (i,j) between atoms within the given intermediate.     If contain_bond_order is True, it returns bonds with bond order included (i,j,bond_order), where bond_order can only have 1,2,3.     Therefore, a given molecule(self) should be kekulized.</p> <p>:return bond_list(either list of tuple with size 2 or 3):     bond_list</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_bond_list(self, contain_bond_order=True):\n    \"\"\"\n    Returns the total bond list as list of tuples\n    For example, if CH4 is given with atom order [C,H,H,H,H], if contain_bond_order = False, the output is given as\n    [(0,1),(0,2),(0,3),(0,4)]\n    if contain_bond_order = True, the output is given as\n    [(0,1,1),(0,2,1),(0,3,1),(0,4,1)]\n\n    :param contain_bond_order(boolean):\n        If contain_bond_order is False, it only returns bonds represented as (i,j) between atoms within the given intermediate.\n        If contain_bond_order is True, it returns bonds with bond order included (i,j,bond_order), where bond_order can only have 1,2,3.\n        Therefore, a given molecule(self) should be kekulized.\n\n    :return bond_list(either list of tuple with size 2 or 3):\n        bond_list\n    \"\"\"\n    atom_list = self.atom_list\n    n = len(atom_list)\n    check_matrix = self.bo_matrix\n    total_bond_list = []\n    if contain_bond_order:\n        check_matrix = self.get_bo_matrix()\n        if check_matrix is None:\n            print(\"we cannot give bond order!!!\")\n            print(\"We will automatically give only bond list!\")\n            contain_bond_order = False\n            check_matrix = self.get_adj_matrix()\n            if check_matrix is None:\n                print(\"matrix\", self.atom_list)\n                print(\"hahahahahaha\", check_matrix)\n                print(\"Give connectivity! We cannot find the bond!\")\n                return None\n    if contain_bond_order:\n        bond_type = [1, 2, 3]\n        check_matrix = self.get_bo_matrix()\n    else:\n        bond_type = [1]\n        check_matrix = self.get_adj_matrix()\n    # check_matrix = self.adj_matrix\n    for bond_order in bond_type:\n        bond_list = np.where(check_matrix == bond_order)\n        bond_list = np.stack(bond_list, axis=1)\n        for array in bond_list:\n            if array[0] &lt; array[1]:\n                if contain_bond_order:\n                    bond_tuple = (int(array[0]), int(array[1]), int(bond_order))\n                else:\n                    bond_tuple = (int(array[0]), int(array[1]))\n                total_bond_list.append(bond_tuple)\n    return total_bond_list\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_chg","title":"get_chg","text":"<pre><code>get_chg()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_chg(self):\n    if self.chg is None:\n        chg_list = self.get_chg_list()\n        if chg_list is None:\n            return None\n        else:\n            return np.sum(chg_list)\n    else:\n        return self.chg\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_chg_list","title":"get_chg_list","text":"<pre><code>get_chg_list()\n</code></pre> <p>Returns chg list of a given molecule</p> <p>:param:</p> <p>:return chg_list(pyclass 'numpy.ndarray'):     list of formal charge</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_chg_list(self):\n    \"\"\"\n    Returns chg list of a given molecule\n\n    :param:\n\n    :return chg_list(pyclass 'numpy.ndarray'):\n        list of formal charge\n    \"\"\"\n    atom_feature = self.atom_feature\n    try:\n        return atom_feature[\"chg\"]\n    except:\n        print(\"charge lists are not prepared!!!\")\n        return None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_coordinate_list","title":"get_coordinate_list","text":"<pre><code>get_coordinate_list()\n</code></pre> <p>Returns 3d coordinate of a given molecule</p> <p>:param:</p> <p>:return coordinate_list(list(size n) of tuple of float(size 3)):</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_coordinate_list(self):\n    \"\"\"\n    Returns 3d coordinate of a given molecule\n\n    :param:\n\n    :return coordinate_list(list(size n) of tuple of float(size 3)):\n\n    \"\"\"\n    atom_list = self.atom_list\n    if \"coords\" in self.atom_feature:\n        return self.atom_feature[\"coords\"]\n    coordinate_list = [[atom.x, atom.y, atom.z] for atom in atom_list]\n    return np.array(coordinate_list)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_dihedral_angle_between_atoms","title":"get_dihedral_angle_between_atoms","text":"<pre><code>get_dihedral_angle_between_atoms(idx1, idx2, idx3, idx4, unit='rad')\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_dihedral_angle_between_atoms(self, idx1, idx2, idx3, idx4, unit=\"rad\"):\n    coordinate_list = self.get_coordinate_list()\n    angle = ic.get_dihedral_angle(coordinate_list, idx1, idx2, idx3, idx4)\n    if unit == \"degree\":\n        angle *= 180 / np.pi\n    return angle\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_distance_between_atoms","title":"get_distance_between_atoms","text":"<pre><code>get_distance_between_atoms(idx1, idx2)\n</code></pre> <p>Returns the distance between chosen two atoms</p> <p>:param idx1,idx2(int):     indices of chosen two atoms.</p> <p>:return distance(float):     Distance between selected two atoms</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_distance_between_atoms(self, idx1, idx2):\n    \"\"\"\n    Returns the distance between chosen two atoms\n\n    :param idx1,idx2(int):\n        indices of chosen two atoms.\n\n    :return distance(float):\n        Distance between selected two atoms\n\n    \"\"\"\n    coordinate_list = self.get_coordinate_list()\n    return ic.get_distance(coordinate_list, idx1, idx2)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_element_list","title":"get_element_list","text":"<pre><code>get_element_list()\n</code></pre> <p>Returns element list of a given molecule</p> <p>:param:</p> <p>:return element_list(list of string):     list of element written as capital letters</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_element_list(self):\n    \"\"\"\n    Returns element list of a given molecule\n\n    :param:\n\n    :return element_list(list of string):\n        list of element written as capital letters\n    \"\"\"\n    atom_feature = self.atom_feature\n    if atom_feature is not None and \"element\" in atom_feature:\n        return atom_feature[\"element\"]\n    else:\n        element_list = list(map(lambda x: x.get_element(), self.atom_list))\n        return element_list\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_internal_coordinate","title":"get_internal_coordinate","text":"<pre><code>get_internal_coordinate(indices, unit='degree')\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_internal_coordinate(self, indices, unit=\"degree\"):\n    if len(indices) == 2:\n        idx1, idx2 = indices\n        return self.get_distance_between_atoms(idx1, idx2)\n    elif len(indices) == 3:\n        idx1, idx2, idx3 = indices\n        return self.get_angle_between_atoms(idx1, idx2, idx3, unit)\n    elif len(indices) == 4:\n        idx1, idx2, idx3, idx4 = indices\n        return self.get_dihedral_angle_between_atoms(idx1, idx2, idx3, idx4, unit)\n    else:\n        print(f\"Wrong coordinate (={indices}) given!\")\n        return None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_minimal_data","title":"get_minimal_data","text":"<pre><code>get_minimal_data()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_minimal_data(self):\n    data = dict()\n    data[\"z\"] = self.get_z_list()\n    data[\"adj\"] = self.get_adj_matrix()\n    data[\"bo\"] = self.get_bo_matrix()\n    data[\"chg\"] = self.get_chg()\n    data[\"atom chg\"] = self.get_chg_list()\n    data[\"coords\"] = self.get_coordinate_list()\n    return data\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_multiplicity","title":"get_multiplicity","text":"<pre><code>get_multiplicity()\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_multiplicity(self):\n    try:\n        e_list = self.get_num_of_lone_pair_list()\n        num_of_unpaired_e = len(np.where((2 * e_list) % 2 == 1)[0])\n        multiplicity = num_of_unpaired_e + 1\n        return multiplicity\n    except:\n        return None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_normal_vector","title":"get_normal_vector","text":"<pre><code>get_normal_vector(idx1, idx2, idx3)\n</code></pre> <p>For given three atom indices, it returns normal vector that is perpendicular to the plane generated by three indices</p> <p>:param idx1,idx2,idx3(int):     Indices for selected three atoms</p> <p>:return normal_vector(pyclass 'numpy.ndarray' with length 3)     normal vector</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_normal_vector(self, idx1, idx2, idx3):\n    \"\"\"\n    For given three atom indices, it returns normal vector that is perpendicular to\n    the plane generated by three indices\n\n    :param idx1,idx2,idx3(int):\n        Indices for selected three atoms\n\n    :return normal_vector(pyclass 'numpy.ndarray' with length 3)\n        normal vector\n    \"\"\"\n    vector1 = self.get_vector_between_atoms(idx3, idx1)\n    vector2 = self.get_vector_between_atoms(idx3, idx2)\n    cross_vector = np.cross(vector1, vector2)\n    norm = np.linalg.norm(cross_vector)\n    if norm == 0:\n        return cross_vector\n    else:\n        return cross_vector / norm\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_radius_list","title":"get_radius_list","text":"<pre><code>get_radius_list()\n</code></pre> <p>Returns radius list of a given molecule Ex. For CH4 with atom order [C,H,H,H,H], then radius_list is given as [0.8,0.5,0.5,0.5,0.5], if radius of C and H are given as 0.8 and 0.5 (unit is Angstrom)</p> <p>:param:</p> <p>:return radius_list(list of float):     list of radius of each atom</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_radius_list(self):\n    \"\"\"\n    Returns radius list of a given molecule\n    Ex. For CH4 with atom order [C,H,H,H,H], then radius_list is given as\n    [0.8,0.5,0.5,0.5,0.5], if radius of C and H are given as 0.8 and 0.5 (unit is Angstrom)\n\n    :param:\n\n    :return radius_list(list of float):\n        list of radius of each atom\n    \"\"\"\n    atom_list = self.atom_list\n    atom_feature = self.atom_feature\n    if \"radius\" in atom_feature:\n        return atom_feature[\"radius\"]\n    radius_list = []\n    for atom in atom_list:\n        radius_list.append(atom.get_radius())\n    return radius_list\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_vector_between_atoms","title":"get_vector_between_atoms","text":"<pre><code>get_vector_between_atoms(idx1, idx2, normalize=True)\n</code></pre> <p>For given two atom indices, it returns difference vector between two atoms. This function can be used to move or rotate a given molecule</p> <p>:param idx1,idx2(int):     Indices for selected two atoms</p> <p>:return difference_vector(pyclass 'numpy.ndarray' with length 3)</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_vector_between_atoms(self, idx1, idx2, normalize=True):\n    \"\"\"\n    For given two atom indices, it returns difference vector between two atoms. This function can be used to\n    move or rotate a given molecule\n\n    :param idx1,idx2(int):\n        Indices for selected two atoms\n\n    :return difference_vector(pyclass 'numpy.ndarray' with length 3)\n\n    \"\"\"\n    atom_list = self.atom_list\n    atom_coord1 = atom_list[idx1].get_coordinate()\n    atom_coord2 = atom_list[idx2].get_coordinate()\n    vector = atom_coord2 - atom_coord1\n    if normalize:\n        norm = np.linalg.norm(vector)\n        if norm &lt; 0.0001:\n            print(\"zero vector is found ...\")\n            return vector\n        else:\n            # print ('finalvector',vector,vector/norm)\n            return vector / norm\n    return vector\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.get_z_list","title":"get_z_list","text":"<pre><code>get_z_list()\n</code></pre> <p>Returns atomic number list of a given molecule</p> <p>:param:</p> <p>:return z_list(pyclass 'numpy.ndarray'):     list of atomic number</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def get_z_list(self):\n    \"\"\"\n    Returns atomic number list of a given molecule\n\n    :param:\n\n    :return z_list(pyclass 'numpy.ndarray'):\n        list of atomic number\n    \"\"\"\n    atom_feature = self.atom_feature\n    if atom_feature is not None and \"atomic number\" in atom_feature:\n        return atom_feature[\"atomic number\"]\n    else:\n        z_list = list(map(lambda x: x.get_atomic_number(), self.atom_list))\n        return np.array(z_list)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.print_coordinate_list","title":"print_coordinate_list","text":"<pre><code>print_coordinate_list(option='element')\n</code></pre> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def print_coordinate_list(self, option=\"element\"):\n    coordinate_list = self.get_coordinate_list()\n    atom_list = self.atom_list\n    n = len(atom_list)\n    for i in range(n):\n        coordinate = coordinate_list[i]\n        element = atom_list[i].get_element()\n        if option == \"number\":\n            element = atom_list[i].get_atomic_number()\n        print_x = coordinate[0]\n        print_y = coordinate[1]\n        print_z = coordinate[2]\n        if abs(print_x) &lt; 0.0001:\n            print_x = 0.00\n        if abs(print_y) &lt; 0.0001:\n            print_y = 0.00\n        if abs(print_z) &lt; 0.0001:\n            print_z = 0.00\n        print(element, print_x, print_y, print_z)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/chem.html#himatcal.utils.mcd.chem.Molecule.write_geometry","title":"write_geometry","text":"<pre><code>write_geometry(file_directory, option='element', criteria=0.0001)\n</code></pre> <p>Writes xyz file that contains the 3d molecular geometry</p> <p>:param file_directory(str):     Directory for saving 3d geometry xyz file</p> <p>:return:</p> Source code in <code>himatcal/utils/mcd/chem.py</code> <pre><code>def write_geometry(self, file_directory, option=\"element\", criteria=1e-4):\n    \"\"\"\n    Writes xyz file that contains the 3d molecular geometry\n\n    :param file_directory(str):\n        Directory for saving 3d geometry xyz file\n\n    :return:\n\n    \"\"\"\n    atom_list = self.atom_list\n    n = len(atom_list)\n    with open(file_directory, \"w\") as f:\n        content = str(n) + \"\\n\"\n        if self.energy is not None:\n            content = content + str(self.energy) + \"\\n\"\n        else:\n            content = content + \"\\n\"\n        f.write(content)\n        for atom in atom_list:\n            f.write(atom.get_content(option, criteria))\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html","title":"ic","text":""},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.coordinate_list","title":"coordinate_list  <code>module-attribute</code>","text":"<pre><code>coordinate_list = get_coordinate_list()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.delta_qs","title":"delta_qs  <code>module-attribute</code>","text":"<pre><code>delta_qs = dict()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.internal_coordinate","title":"internal_coordinate  <code>module-attribute</code>","text":"<pre><code>internal_coordinate = (0, 1, 2)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.internal_coordinates","title":"internal_coordinates  <code>module-attribute</code>","text":"<pre><code>internal_coordinates = list(keys())\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.matrix","title":"matrix  <code>module-attribute</code>","text":"<pre><code>matrix = get_wilsonB_derivative_matrix(coordinate_list, internal_coordinates)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.molecule","title":"molecule  <code>module-attribute</code>","text":"<pre><code>molecule = Molecule('R.xyz')\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.arccos","title":"arccos","text":"<pre><code>arccos(x)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def arccos(x):\n    return np.arccos(x)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.cos","title":"cos","text":"<pre><code>cos(x)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def cos(x):\n    return np.cos(x)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_angle","title":"get_angle","text":"<pre><code>get_angle(xyz_coordinates, idx1, idx2, idx3)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_angle(xyz_coordinates, idx1, idx2, idx3):\n    # Formula: theta = cos-1(u.v/|u||v|)\n    v_21 = get_vector(xyz_coordinates, idx2, idx1, True)\n    v_23 = get_vector(xyz_coordinates, idx2, idx3, True)\n    return get_vector_angle(v_21, v_23)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_cross_vector","title":"get_cross_vector","text":"<pre><code>get_cross_vector(v1, v2, normalize=False)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_cross_vector(v1, v2, normalize=False):\n    v = np.cross(v1, v2)\n    if normalize:\n        d = np.linalg.norm(v)\n        v /= d\n    return v\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_dihedral_angle","title":"get_dihedral_angle","text":"<pre><code>get_dihedral_angle(xyz_coordinates, idx1, idx2, idx3, idx4)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_dihedral_angle(xyz_coordinates, idx1, idx2, idx3, idx4):\n    # Formula: theta = cos-1((uxw)_n.(vxw)_n], (uxw)_n: normalized cross vector\n    v_12 = get_vector(xyz_coordinates, idx1, idx2, True)  # u\n    v_23 = get_vector(xyz_coordinates, idx2, idx3, True)  # w\n    v_34 = get_vector(xyz_coordinates, idx3, idx4, True)  # v\n    w1 = get_cross_vector(v_12, v_23, True)\n    w2 = get_cross_vector(v_23, v_34, True)\n    return get_vector_angle(w1, w2)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_distance","title":"get_distance","text":"<pre><code>get_distance(xyz_coordinates, idx1, idx2)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_distance(xyz_coordinates, idx1, idx2):\n    v = get_vector(xyz_coordinates, idx1, idx2)\n    return np.linalg.norm(v)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_gradient_q","title":"get_gradient_q","text":"<pre><code>get_gradient_q(g_x, xyz_coordinates, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_gradient_q(g_x, xyz_coordinates, internal_coordinates):\n    B = get_wilsonB_matrix(xyz_coordinates, internal_coordinates)  # M x 3N, B.T: 3N x M\n    BT_inverse = np.linalg.pinv(B.T)\n    return BT_inverse @ g_x  # M x 1\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_hessian_q","title":"get_hessian_q","text":"<pre><code>get_hessian_q(g_x, h_x, xyz_coordinates, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_hessian_q(g_x, h_x, xyz_coordinates, internal_coordinates):\n    # print ('bf',internal_coordinates)\n    B = get_wilsonB_matrix(xyz_coordinates, internal_coordinates)  # M x 3N\n    # print ('af',internal_coordinates)\n    B_prime = get_wilsonB_derivative_matrix(\n        xyz_coordinates, internal_coordinates\n    )  # M x 3N x 3N\n    BT_inverse = np.linalg.pinv(B.T)\n    B_inverse = np.linalg.pinv(B)\n    g_q = BT_inverse @ g_x  # M x 1\n    # print (g_q.shape,B_prime.shape)\n    K = np.squeeze(\n        np.einsum(\"il,ijk-&gt;ljk\", g_q, B_prime), axis=0\n    )  # M x 1, M x 3N x 3N -&gt; 1 x 3N x 3N (einsum) -&gt; 3N x 3N (squeeze)\n    # print (K.shape)\n    # print (h_x.shape)\n    # print ('K',np.sum(np.abs(K)))\n    h_q = BT_inverse @ (h_x - K) @ B_inverse\n    # print (h_q.shape)\n    return h_q\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_internal_coordinate_info","title":"get_internal_coordinate_info","text":"<pre><code>get_internal_coordinate_info(coordinate_list, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_internal_coordinate_info(coordinate_list, internal_coordinates):\n    infos = dict()\n    q = get_q(coordinate_list, internal_coordinates)\n    for idx, internal_coordinate in enumerate(internal_coordinates):\n        infos[internal_coordinate] = q[idx]\n    return infos\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_q","title":"get_q","text":"<pre><code>get_q(xyz_coordinates, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_q(xyz_coordinates, internal_coordinates):\n    q = []\n    for internal_coordinate in internal_coordinates:\n        q.append(get_single_q_element(xyz_coordinates, internal_coordinate))\n    return np.array(q).T\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_single_q_element","title":"get_single_q_element","text":"<pre><code>get_single_q_element(xyz_coordinates, internal_coordinate)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_single_q_element(xyz_coordinates, internal_coordinate):\n    if len(internal_coordinate) == 2:\n        idx1, idx2 = internal_coordinate\n        return get_distance(xyz_coordinates, idx2, idx1)\n    elif len(internal_coordinate) == 3:\n        idx1, idx2, idx3 = internal_coordinate\n        return get_angle(xyz_coordinates, idx1, idx2, idx3)\n    else:\n        idx1, idx2, idx3, idx4 = internal_coordinate\n        return get_dihedral_angle(xyz_coordinates, idx1, idx2, idx3, idx4)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_vector","title":"get_vector","text":"<pre><code>get_vector(xyz_coordinates, idx1, idx2, normalize=False)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_vector(xyz_coordinates, idx1, idx2, normalize=False):\n    start = xyz_coordinates[idx1]\n    end = xyz_coordinates[idx2]\n    v = start - end\n    if normalize:\n        d = np.linalg.norm(v)\n        v /= d\n    return v\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_vector_angle","title":"get_vector_angle","text":"<pre><code>get_vector_angle(v1, v2)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_vector_angle(v1, v2):\n    return np.arccos(np.dot(v1, v2))\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_wilsonB_derivative_matrix","title":"get_wilsonB_derivative_matrix","text":"<pre><code>get_wilsonB_derivative_matrix(xyz_coordinates, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_wilsonB_derivative_matrix(xyz_coordinates, internal_coordinates):\n    n = len(xyz_coordinates)\n    m = len(internal_coordinates)\n    B_derivative_matrix = np.zeros((m, 3 * n, 3 * n))\n    for row_idx, internal_coordinate in enumerate(internal_coordinates):\n        tensor, scanning_indices = get_wilsonB_derivative_sub_matrix(\n            xyz_coordinates, internal_coordinate\n        )  # tensor: m x m x 3 x 3\n        for indices in scanning_indices:\n            x, y = indices\n            a = internal_coordinate[x]\n            b = internal_coordinate[y]\n            B_derivative_matrix[row_idx, 3 * a : 3 * a + 3, 3 * b : 3 * b + 3] = tensor[\n                x, y, :, :\n            ]\n    return B_derivative_matrix\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_wilsonB_derivative_sub_matrix","title":"get_wilsonB_derivative_sub_matrix","text":"<pre><code>get_wilsonB_derivative_sub_matrix(xyz_coordinates, internal_coordinate)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_wilsonB_derivative_sub_matrix(xyz_coordinates, internal_coordinate):\n    m = len(internal_coordinate)\n    indices = list(range(m))\n    scanning_indices = list(itertools.product(indices, indices))\n    tensor = np.zeros((m, m, 3, 3))\n    if m == 2:\n        a, b = internal_coordinate\n        u = get_vector(xyz_coordinates, a, b, False)\n        l_u = np.linalg.norm(u)\n        u /= l_u  # Normalized u\n        # m: a, n: b\n        for indices in list(scanning_indices):\n            x, y = indices\n            idx1 = internal_coordinate[x]\n            idx2 = internal_coordinate[y]\n            # a: idx1, b: idx2\n            for i in range(3):\n                for j in range(3):\n                    u_i = u[i]\n                    u_j = u[j]\n                    tensor[x][y][i][j] = (\n                        (-1) ** kronecker_delta(idx1, idx2)\n                        * (u_i * u_j - kronecker_delta(i, j))\n                        / l_u\n                    )\n    if m == 3:\n        a, b, c = internal_coordinate\n        u = get_vector(xyz_coordinates, a, b, False)\n        l_u = np.linalg.norm(u)\n        u /= l_u  # Normalized u\n        v = get_vector(xyz_coordinates, c, b, False)\n        l_v = np.linalg.norm(v)\n        v /= l_v  # Normalized v\n        cos_q = np.sum(u * v)\n        sin_q = np.sqrt(1 - cos_q**2)\n        vector_dict = get_wilsonB_vector(xyz_coordinates, internal_coordinate)\n        # m: a, o: b, n: c\n        for indices in scanning_indices:\n            x, y = indices\n            idx1 = internal_coordinate[x]\n            idx2 = internal_coordinate[y]\n            # a: idx1, b: idx2\n            for i in range(3):\n                for j in range(3):\n                    u_i = u[i]\n                    u_j = u[j]\n                    v_i = v[j]\n                    v_j = u[j]\n                    first_term = (\n                        u_i * v_j\n                        + u_j * v_i\n                        - 3 * u_i * u_j * cos_q\n                        + kronecker_delta(i, j) * cos_q\n                    ) / (l_u**2 * sin_q)\n                    first_term *= sign_factor(idx1, a, b) * sign_factor(idx2, a, b)\n                    second_term = (\n                        v_i * u_j\n                        + v_j * u_i\n                        - 3 * v_i * v_j * cos_q\n                        + kronecker_delta(i, j) * cos_q\n                    ) / (l_v**2 * sin_q)\n                    second_term *= sign_factor(idx1, c, b) * sign_factor(idx2, c, b)\n                    third_term = (\n                        u_i * u_j\n                        + v_j * v_i\n                        - u_i * v_j * cos_q\n                        - kronecker_delta(i, j)\n                    ) / (l_u * l_v * sin_q)\n                    third_term *= sign_factor(idx1, a, b) * sign_factor(idx2, c, b)\n                    fourth_term = (\n                        v_i * v_j\n                        + u_j * u_i\n                        - v_i * u_j * cos_q\n                        - kronecker_delta(i, j)\n                    ) / (l_u * l_v * sin_q)\n                    fourth_term *= sign_factor(idx1, c, b) * sign_factor(idx2, a, b)\n                    fifth_term = (\n                        cos_q / sin_q * vector_dict[idx1][i] * vector_dict[idx2][j]\n                    )\n                    tensor[x][y][i][j] = (\n                        first_term + second_term + third_term + fourth_term - fifth_term\n                    )\n\n    elif m == 4:\n        a, b, c, d = internal_coordinate\n        u = get_vector(xyz_coordinates, a, b, False)\n        l_u = np.linalg.norm(u)\n        u /= l_u  # Normalized u\n        v = get_vector(xyz_coordinates, d, c, False)\n        l_v = np.linalg.norm(v)\n        v /= l_v  # Normalized v\n        w = get_vector(xyz_coordinates, c, b, False)\n        l_w = np.linalg.norm(w)\n        w /= l_w  # Normalized w\n        uw = get_cross_vector(u, w, False)\n        vw = get_cross_vector(v, w, False)\n        cos_phi_u = np.sum(u * w)\n        sin_phi_u = np.sqrt(1 - cos_phi_u**2)\n        cos_phi_v = np.sum(v * w)\n        sin_phi_v = np.sqrt(1 - cos_phi_v**2)\n        cos_q = np.sum(uw * vw) / (sin_phi_u * sin_phi_v)\n        # m: a, o: b, p: c, n: d\n        for indices in scanning_indices:\n            x, y = indices\n            idx1 = internal_coordinate[x]\n            idx2 = internal_coordinate[y]\n            # a: idx1, b: idx2\n            for i in range(3):\n                for j in range(3):\n                    u_i = u[i]\n                    u_j = u[j]\n                    v_i = v[j]\n                    v_j = u[j]\n                    w_i = w[i]\n                    w_j = w[j]\n                    first_term = (uw[i] * (cos_phi_u * w_j - u_j)) / (\n                        l_u**2 * sin_phi_u**4\n                    )\n                    first_term *= sign_factor(idx1, a, b) * sign_factor(idx2, a, b)\n                    second_term = (uw[j] * (cos_phi_u * w_i - u_i)) / (\n                        l_u**2 * sin_phi_u**4\n                    )\n                    second_term *= sign_factor(idx1, a, b) * sign_factor(idx2, a, b)\n                    third_term = (vw[i] * (w_j * cos_phi_v - v_j)) / (\n                        l_v**2 * sin_phi_v**4\n                    )\n                    third_term *= sign_factor(idx1, d, c) * sign_factor(idx2, d, c)\n                    fourth_term = (vw[j] * (w_i * cos_phi_v - v_i)) / (\n                        l_v**2 * sin_phi_v**4\n                    )\n                    fourth_term *= sign_factor(idx1, d, c) * sign_factor(idx2, d, c)\n                    fifth_term = (\n                        uw[i] * (w_j - 2 * u_j * cos_phi_u + w_j * cos_phi_u**2)\n                    ) / (2 * l_u * l_w * sin_phi_u**4)\n                    fifth_term *= sign_factor(idx1, a, b) * sign_factor(\n                        idx2, b, c\n                    ) + sign_factor(idx1, c, b) * sign_factor(idx2, b, a)\n                    sixth_term = (\n                        uw[j] * (w_i - 2 * u_i * cos_phi_u + w_i * cos_phi_u**2)\n                    ) / (2 * l_u * l_w * sin_phi_u**4)\n                    sixth_term *= sign_factor(idx1, a, b) * sign_factor(\n                        idx2, b, c\n                    ) + sign_factor(idx1, c, b) * sign_factor(idx2, b, a)\n                    seventh_term = (\n                        vw[i] * (w_j + 2 * u_j * cos_phi_v + w_j * cos_phi_v**2)\n                    ) / (2 * l_v * l_w * sin_phi_v**4)\n                    seventh_term *= sign_factor(idx1, d, c) * sign_factor(\n                        idx2, c, b\n                    ) + sign_factor(idx1, c, b) * sign_factor(idx2, d, c)\n                    eighth_term = (\n                        vw[j] * (w_i + 2 * u_i * cos_phi_v + w_i * cos_phi_v**2)\n                    ) / (2 * l_v * l_w * sin_phi_v**4)\n                    eighth_term *= sign_factor(idx1, d, c) * sign_factor(\n                        idx2, c, b\n                    ) + sign_factor(idx1, c, b) * sign_factor(idx2, d, c)\n                    ninth_term = (\n                        uw[i]\n                        * (\n                            u_j\n                            + u_j * cos_phi_u**2\n                            - 3 * w_j * cos_phi_u\n                            + w_j * cos_phi_u**3\n                        )\n                    ) / (2 * l_w**2 * sin_phi_u**4)\n                    ninth_term *= sign_factor(idx1, b, c) * sign_factor(idx2, c, b)\n                    tenth_term = (\n                        uw[j]\n                        * (\n                            u_i\n                            + u_i * cos_phi_u**2\n                            - 3 * w_i * cos_phi_u\n                            + w_i * cos_phi_u**3\n                        )\n                    ) / (2 * l_w**2 * sin_phi_u**4)\n                    tenth_term *= sign_factor(idx1, b, c) * sign_factor(idx2, c, b)\n                    eleventh_term = (\n                        vw[i]\n                        * (\n                            v_j\n                            + v_j * cos_phi_v**2\n                            + 3 * w_j * cos_phi_v\n                            - w_j * cos_phi_v**3\n                        )\n                    ) / (2 * l_w**2 * sin_phi_v**4)\n                    eleventh_term *= sign_factor(idx1, b, c) * sign_factor(idx2, b, c)\n                    twelvth_term = (\n                        vw[j]\n                        * (\n                            v_i\n                            + v_i * cos_phi_v**2\n                            + 3 * w_i * cos_phi_v\n                            - w_i * cos_phi_v**3\n                        )\n                    ) / (2 * l_w**2 * sin_phi_v**4)\n                    twelvth_term *= sign_factor(idx1, b, c) * sign_factor(idx2, b, c)\n                    if i != j:\n                        k = list(set([0, 1, 2]) - set([i, j]))[0]\n                        w_k = w[k]\n                        u_k = u[k]\n                        v_k = v[k]\n                        thirteenth_term = (\n                            (j - i)\n                            * (-1 / 2) ** (abs(i - j))\n                            * (w_k * cos_phi_u - u_k)\n                            / (l_u * l_w * sin_phi_u)\n                        )\n                        thirteenth_term *= (1 - kronecker_delta(idx1, idx2)) * (\n                            sign_factor(idx1, a, b) * sign_factor(idx2, b, c)\n                            + sign_factor(idx1, c, b) * sign_factor(idx2, b, a)\n                        )\n                        fourteenth_term = (\n                            (j - i)\n                            * (-1 / 2) ** (abs(i - j))\n                            * (w_k * cos_phi_v - v_k)\n                            / (l_v * -l_w * sin_phi_v)\n                        )\n                        fourteenth_term *= (1 - kronecker_delta(idx1, idx2)) * (\n                            sign_factor(idx1, d, b) * sign_factor(idx2, b, c)\n                            + sign_factor(idx1, c, b) * sign_factor(idx2, b, a)\n                        )\n                    else:\n                        thirteenth_term = 0\n                        fourteenth_term = 0\n                    tensor[x][y][i][j] = (\n                        first_term\n                        + second_term\n                        + third_term\n                        + fourth_term\n                        + fifth_term\n                        + sixth_term\n                        + seventh_term\n                        + eighth_term\n                        + ninth_term\n                        + tenth_term\n                        + eleventh_term\n                        + twelvth_term\n                        + thirteenth_term\n                        + fourteenth_term\n                    )\n\n    return tensor, scanning_indices\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_wilsonB_matrix","title":"get_wilsonB_matrix","text":"<pre><code>get_wilsonB_matrix(xyz_coordinates, internal_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_wilsonB_matrix(xyz_coordinates, internal_coordinates):\n    # Reshape xyzs\n    n = len(xyz_coordinates)\n    m = len(internal_coordinates)\n    B_matrix = np.zeros((m, 3 * n))\n    for row_idx, internal_coordinate in enumerate(internal_coordinates):\n        vectors = get_wilsonB_vector(xyz_coordinates, internal_coordinate)\n        for index in vectors:\n            B_matrix[row_idx, 3 * index : 3 * index + 3] = vectors[index]\n    return B_matrix\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_wilsonB_vector","title":"get_wilsonB_vector","text":"<pre><code>get_wilsonB_vector(xyz_coordinates, internal_coordinate)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_wilsonB_vector(xyz_coordinates, internal_coordinate):\n    vector_dict = dict()\n    if len(internal_coordinate) == 2:\n        idx1, idx2 = internal_coordinate\n        u = get_vector(xyz_coordinates, idx1, idx2, True)\n        # a: idx1, m: idx1, n: idx2\n        vector_dict[idx2] = sign_factor(idx2, idx1, idx2) * u\n        vector_dict[idx1] = sign_factor(idx1, idx1, idx2) * u\n    elif len(internal_coordinate) == 3:\n        idx1, idx2, idx3 = internal_coordinate\n        u = get_vector(xyz_coordinates, idx1, idx2, False)\n        l_u = np.linalg.norm(u)\n        u /= l_u  # Normalized u\n        v = get_vector(xyz_coordinates, idx3, idx2, False)\n        l_v = np.linalg.norm(v)  # Normalized v\n        v /= l_v\n        w = get_cross_vector(u, v, True)  # Normalized w\n        uw = get_cross_vector(u, w, False)\n        wv = get_cross_vector(w, v, False)\n        # m: idx1, o: idx2, n: idx3\n        for idx in [idx1, idx2, idx3]:\n            vector_dict[idx] = (\n                sign_factor(idx, idx1, idx2) * uw / l_u\n                + sign_factor(idx, idx3, idx2) * wv / l_v\n            )\n    else:\n        idx1, idx2, idx3, idx4 = internal_coordinate\n        # m:idx1, o:idx2, p:idx3, n: idx4\n        u = get_vector(xyz_coordinates, idx1, idx2, False)\n        l_u = np.linalg.norm(u)\n        u /= l_u  # Normalized u\n        v = get_vector(xyz_coordinates, idx4, idx3, False)\n        l_v = np.linalg.norm(v)\n        v /= l_v  # Normalized v\n        w = get_vector(xyz_coordinates, idx3, idx2, False)\n        l_w = np.linalg.norm(w)\n        w /= l_w  # Normalized w\n        uw = get_cross_vector(u, w, False)\n        vw = get_cross_vector(v, w, False)\n        cos_phi_u = np.sum(u * w)\n        sin_phi_u = np.sqrt(1 - cos_phi_u**2)\n        cos_phi_v = np.sum(v * w)\n        sin_phi_v = np.sqrt(1 - cos_phi_v**2)\n        cos_q = np.sum(uw * vw) / (sin_phi_u * sin_phi_v)\n        for idx in [idx1, idx2, idx3, idx4]:\n            first_term = sign_factor(idx, idx1, idx2) * uw / (l_u * sin_phi_u**2)\n            second_term = sign_factor(idx, idx3, idx4) * vw / (l_v * sin_phi_v**2)\n            third_term = cos_phi_u * uw / (l_w * sin_phi_u**2) - cos_phi_v * vw / (\n                l_w * sin_phi_v**2\n            )\n            third_term *= sign_factor(idx, idx2, idx3)\n            vector_dict[idx] = first_term + second_term + third_term\n\n    return vector_dict\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.get_xyz_updates","title":"get_xyz_updates","text":"<pre><code>get_xyz_updates(xyz_coordinates, internal_coordinates, delta_q)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def get_xyz_updates(\n    xyz_coordinates, internal_coordinates, delta_q\n):  # Note that here, delta_qs[internal_coordinate] = delta_q\n    B = get_wilsonB_matrix(xyz_coordinates, internal_coordinates)\n    delta_x = solve_equation(B, delta_q)  # 3N x 1 -&gt; N x 3\n    n = len(xyz_coordinates)\n    delta_x = np.reshape(delta_x, (n, 3))\n    return delta_x\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.kronecker_delta","title":"kronecker_delta","text":"<pre><code>kronecker_delta(a, b)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def kronecker_delta(a, b):\n    if a == b:\n        return 1\n    else:\n        return 0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.sign_factor","title":"sign_factor","text":"<pre><code>sign_factor(a, b, c)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def sign_factor(a, b, c):\n    return kronecker_delta(a, b) - kronecker_delta(a, c)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.sin","title":"sin","text":"<pre><code>sin(x)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def sin(x):\n    return np.sin(x)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.solve_equation","title":"solve_equation","text":"<pre><code>solve_equation(B, delta_q)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def solve_equation(B, delta_q):\n    B_inverse = np.linalg.pinv(B)  # N x M\n    delta_x = B_inverse @ delta_q\n    return delta_x\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/ic.html#himatcal.utils.mcd.ic.update_geometry","title":"update_geometry","text":"<pre><code>update_geometry(xyz_coordinates, q_updates, criteria=1e-06, max_iteration=25)\n</code></pre> Source code in <code>himatcal/utils/mcd/ic.py</code> <pre><code>def update_geometry(xyz_coordinates, q_updates, criteria=1e-6, max_iteration=25):\n    internal_coordinates = list(q_updates.keys())\n    delta_q = np.array(list(q_updates.values())).T  # M x 1\n    q = get_q(xyz_coordinates, internal_coordinates)  # q_n or q_0\n    # print ('q: ',q)\n    # print ('internals: ',internal_coordinates)\n    target_q = q + delta_q  # q\n    original_coordinates = np.copy(xyz_coordinates)\n    for i in range(max_iteration):\n        delta_x = get_xyz_updates(xyz_coordinates, internal_coordinates, delta_q)\n        xyz_coordinates += delta_x\n        q = get_q(xyz_coordinates, internal_coordinates)\n        delta_q = target_q - q  # dq = q - q_n\n        x_norm = np.linalg.norm(delta_x)\n        if x_norm &lt; criteria:\n            # print (delta_q,q_updates,q)\n            break\n        elif i == max_iteration - 1:\n            print(\n                f\"Iteration did not converged! The final updated vector has norm: {x_norm}\"\n            )\n            for xyz in original_coordinates:\n                print(xyz)\n            print(\"update: \", q_updates)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html","title":"mcd","text":""},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD","title":"MCD","text":"<pre><code>MCD(num_relaxation=3, calculator=None)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def __init__(self, num_relaxation=3, calculator=None):\n    self.num_relaxation = num_relaxation\n    self.calculator = calculator\n    self.log_directory = \"\"\n    self.energy_unit = \"Hartree\"\n    self.num_force_calls = 0\n    self.num_hessian_calls = 0\n    self.step_size = 0.0\n    self.use_hessian = False\n    self.hessian_update = \"Bofill\"\n    self.num_filter_iteration = 10\n    self.previous_gradient = None\n    self.previous_hessian = None\n    self.previous_geometry = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.calculator","title":"calculator  <code>instance-attribute</code>","text":"<pre><code>calculator = calculator\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.energy_unit","title":"energy_unit  <code>instance-attribute</code>","text":"<pre><code>energy_unit = 'Hartree'\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.hessian_update","title":"hessian_update  <code>instance-attribute</code>","text":"<pre><code>hessian_update = 'Bofill'\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.log_directory","title":"log_directory  <code>instance-attribute</code>","text":"<pre><code>log_directory = ''\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.num_filter_iteration","title":"num_filter_iteration  <code>instance-attribute</code>","text":"<pre><code>num_filter_iteration = 10\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.num_force_calls","title":"num_force_calls  <code>instance-attribute</code>","text":"<pre><code>num_force_calls = 0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.num_hessian_calls","title":"num_hessian_calls  <code>instance-attribute</code>","text":"<pre><code>num_hessian_calls = 0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.num_relaxation","title":"num_relaxation  <code>instance-attribute</code>","text":"<pre><code>num_relaxation = num_relaxation\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.previous_geometry","title":"previous_geometry  <code>instance-attribute</code>","text":"<pre><code>previous_geometry = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.previous_gradient","title":"previous_gradient  <code>instance-attribute</code>","text":"<pre><code>previous_gradient = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.previous_hessian","title":"previous_hessian  <code>instance-attribute</code>","text":"<pre><code>previous_hessian = None\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.step_size","title":"step_size  <code>instance-attribute</code>","text":"<pre><code>step_size = 0.0\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.use_hessian","title":"use_hessian  <code>instance-attribute</code>","text":"<pre><code>use_hessian = False\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.__str__","title":"__str__","text":"<pre><code>__str__()\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def __str__(self):\n    content = \"\"\n    content = content + f\"num relaxation: {self.num_relaxation}\\n\"\n    content = content + f\"step size: {self.step_size}\\n\"\n    # content = content + f'working_directory: {self.working_directory}\\n'\n    # content = content + f'qc inputs\\n\\n{self.content}\\n'\n    return content\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.change_energy_unit","title":"change_energy_unit","text":"<pre><code>change_energy_unit(energy_unit)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def change_energy_unit(self, energy_unit):\n    self.energy_unit = energy_unit\n    if self.calculator is not None:\n        self.calculator.energy_unit = energy_unit\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.change_working_directory","title":"change_working_directory","text":"<pre><code>change_working_directory(working_directory)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def change_working_directory(self, working_directory):\n    if self.calculator is not None:\n        self.calculator.change_working_directory(working_directory)\n    else:\n        print(\"Calculator does not exist!!! Define a calcualtor first!\")\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.find_solution","title":"find_solution","text":"<pre><code>find_solution(grad, hessian, update_size, delta_q, scanning_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def find_solution(self, grad, hessian, update_size, delta_q, scanning_coordinates):\n    # grad: n x 1, hessian: n x n\n    # Make constraints\n    x0 = []  # Initial guess\n    lower_bounds = []\n    upper_bounds = []\n    jac = []\n    b = np.squeeze(grad)  # M x 1 -&gt; M\n    H = hessian\n    n = len(scanning_coordinates)\n    constant = 0\n    # Ao -&gt; Bohr\n    for constraint in scanning_coordinates:\n        delta = delta_q[constraint]\n        if delta &gt; 0:\n            # Upper bound\n            upper_bound = min(update_size, delta)\n            lower_bounds.append(0)\n            upper_bounds.append(upper_bound)\n            value = np.random.rand(1)[0]\n            constant += value\n            x0.append(value)\n            jac.append(1.0)\n        else:\n            # Lower bound\n            lower_bound = max(-update_size, delta)\n            lower_bounds.append(lower_bound)\n            upper_bounds.append(0)\n            value = np.random.rand(1)[0]\n            constant += value\n            x0.append(-value)\n            jac.append(-1.0)\n    jac = np.array(jac)\n    x0 = np.array(x0)\n    # print ('cons',constant)\n    x0 /= constant\n    x0 *= update_size\n    # print ('x0',x0)\n    constraints = [\n        {\n            \"type\": \"eq\",\n            \"fun\": lambda x: np.sum(x * jac) - update_size,\n            \"jac\": lambda x: jac,\n        }\n    ]\n    bounds = Bounds(lower_bounds, upper_bounds)\n    energy_function = lambda x: 1 / 2 * x.T @ H @ x + np.sum(x * b)\n    jac_energy_function = lambda x: x @ H + b\n    # hessian_energy_function = lambda x: H\n    res = minimize(\n        energy_function,\n        x0,\n        method=\"SLSQP\",\n        jac=jac_energy_function,\n        constraints=constraints,\n        bounds=bounds,\n    )\n    solution = dict()\n    # print ('energy increase: ',energy_function(res.x))\n    print(H, b, res.x)\n    print(\"Expected energy change:\", energy_function(res.x))\n\n    for i, constraint in enumerate(scanning_coordinates):\n        solution[constraint] = res.x[i]\n    return solution\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.get_corrected_indices","title":"get_corrected_indices","text":"<pre><code>get_corrected_indices(constraint)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def get_corrected_indices(\n    self, constraint\n):  # In general, we use index = 1 as starting point!\n    new_constraint = []\n    for idx in constraint:\n        new_constraint.append(idx + 1)\n    new_constraint = tuple(new_constraint)\n    return new_constraint\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.get_delta_q","title":"get_delta_q","text":"<pre><code>get_delta_q(coordinate_list, constraints)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def get_delta_q(self, coordinate_list, constraints):\n    delta_q = dict()\n    update_q = dict()\n    internal_coordinates = list(constraints.keys())\n    # May consider better reaction coordinate representation later!\n    for constraint in constraints:\n        delta_q[constraint] = constraints[constraint] - ic.get_single_q_element(\n            coordinate_list, constraint\n        )\n        update_q[constraint] = 0\n    return delta_q, update_q\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.get_gradient","title":"get_gradient","text":"<pre><code>get_gradient(molecule, chg=None, multiplicity=None)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def get_gradient(self, molecule, chg=None, multiplicity=None):\n    n = len(molecule.atom_list)\n    force = self.calculator.get_force(molecule, chg, multiplicity)\n    dV_dx = -np.reshape(force, (3 * n, 1))\n    self.num_force_calls += 1\n    return dV_dx\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.get_hessian","title":"get_hessian","text":"<pre><code>get_hessian(molecule, chg=None, multiplicity=None)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def get_hessian(self, molecule, chg=None, multiplicity=None):\n    n = len(molecule.atom_list)\n    if self.previous_hessian is None:\n        force, hessian = self.calculator.get_hessian(molecule, chg, multiplicity)\n        dV_dx = -np.reshape(force, (3 * n, 1))\n        self.num_hessian_calls += 1\n        return dV_dx, hessian\n    else:\n        hessian_update = str.lower(self.hessian_update)\n        if hessian_update == \"bofill\":\n            dV_dx = self.get_gradient(molecule, chg, multiplicity)\n            G_i = self.previous_hessian\n            dg_i = dV_dx - self.previous_gradient\n            x_i = np.reshape(molecule.get_coordinate_list(), (3 * n, 1))\n            x_i_1 = np.reshape(self.previous_geometry, (3 * n, 1))\n            dx_i = x_i - x_i_1\n            # print (np.linalg.norm(dx_i))\n            E_i = dg_i - G_i @ dx_i\n            hessian_MS = G_i + (E_i @ E_i.T) / (E_i.T @ dx_i)\n            hessian_PSB = (\n                G_i\n                + (E_i @ dx_i.T + dx_i @ E_i.T) / (dx_i.T @ dx_i)\n                - (dx_i.T @ E_i) * (dx_i @ dx_i.T) / (dx_i.T @ dx_i) ** 2\n            )\n            gamma = 1 - (dx_i.T @ E_i) ** 2 / ((dx_i.T @ dx_i) * (E_i.T @ E_i))\n            hessian = (1 - gamma) * hessian_MS + gamma * hessian_PSB\n            return dV_dx, hessian\n        elif hessian_update == \"exact\":\n            force, hessian = self.calculator.get_hessian(\n                molecule, chg, multiplicity\n            )\n            dV_dx = -np.reshape(force, (3 * n, 1))\n            self.num_hessian_calls += 1\n            return dV_dx, hessian\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.make_restart_file","title":"make_restart_file","text":"<pre><code>make_restart_file(molecule, constraints, num_scan)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def make_restart_file(self, molecule, constraints, num_scan):\n    save_directory = self.log_directory\n    if save_directory == \"\":\n        print(\"No log directory!!! We do not save the pathway!!!\")\n    else:\n        # Save xyz file\n        with open(os.path.join(save_directory, \"new_R.com\"), \"w\") as f:\n            f.write(\"{molecule.get_chg()} {molecule.get_multiplicity()}\\n\")\n            for atom in molecule.atom_list:\n                f.write(atom.get_content())\n            f.write(\"\\n\")\n            f.flush()\n\n        with open(os.path.join(save_directory, \"new_coordinates\"), \"w\") as f:\n            for i, constraint in enumerate(constraints):\n                value = constraints[constraint]\n                new_constraint = [str(index + 1) for index in constraint]\n                content = \" \".join(new_constraint)\n                if i == len(constraints) - 1:\n                    num_step = num_scan\n                else:\n                    num_step = 0\n                f.write(f\"{content} {value} {num_step}\\n\")\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.print_status","title":"print_status","text":"<pre><code>print_status(molecule, constraints, unit='degree')\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def print_status(self, molecule, constraints, unit=\"degree\"):\n    print(\"########## Current geometry info ############\")\n    print(\"\\t Target \\t Current\")\n    coordinate_list = molecule.get_coordinate_list()\n    for constraint in constraints:\n        new_constraint = self.get_corrected_indices(constraint)\n        target_value = constraints[constraint]\n        current_value = molecule.get_internal_coordinate(constraint, unit)\n        current_value = float(format(current_value, \".4f\"))\n        if len(constraint) &gt; 2:\n            if unit == \"degree\":\n                target_value *= 180 / np.pi\n        print(f\"{new_constraint}   {target_value}  {current_value}\")\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.save_figure","title":"save_figure","text":"<pre><code>save_figure(data, unit='kcal')\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def save_figure(self, data, unit=\"kcal\"):\n    try:\n        import matplotlib.pyplot as plt\n\n        from himatcal.tools import mplstyle_file\n\n        plt.style.use(mplstyle_file)\n    except:\n        return None\n    x = list(range(len(data)))\n    plt.plot(x, np.array(data), \"s-\")\n    plt.xlabel(\"Step\")\n    plt.ylabel(f\"Energy ({unit}/mol)\")\n    plt.savefig(os.path.join(self.log_directory, \"profile.png\"))\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.scan","title":"scan","text":"<pre><code>scan(molecule, constraints, num_steps, chg=None, multiplicity=None, restart=False, reoptimize=True)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def scan(\n    self,\n    molecule,\n    constraints,\n    num_steps,\n    chg=None,\n    multiplicity=None,\n    restart=False,\n    reoptimize=True,\n):  # constraints: given as bond: target_distance\n    if type(num_steps) is int:\n        new_num_steps = dict()\n        for constraint in constraints:\n            new_num_steps[constraint] = num_steps\n        num_steps = new_num_steps  # Make cubic scan coordinates\n    else:\n        num_steps = num_steps.copy()  # It should be dict\n    num_scan = sum(num_steps.values())\n\n    self.calculator.set_error_directory(self.log_directory)\n    constraints = constraints.copy()\n    coordinate_list = molecule.get_coordinate_list()\n    delta_q, update_q = self.get_delta_q(coordinate_list, constraints)\n    # Write reactant info\n    self.write_log(\"###### Reactant information ######\\n\", \"w\")\n    if chg is not None and multiplicity is not None:\n        self.write_log(f\"charge: {chg}    multiplicity: {multiplicity}\\n\")\n    else:\n        self.write_log(\"Default charge and multiplicity values are used !!!\\n\")\n    self.write_log(str(len(molecule.atom_list)) + \"\\n\")\n    for atom in molecule.atom_list:\n        self.write_log(atom.get_content())\n    self.write_log(\"\\n\")\n    self.write_log(\"######### Scanning coordinates #########\\n\")\n\n    # Make updates\n    updates = dict()\n    maximum_delta = -100\n    total_delta = 0\n    digit = 3\n    for coordinate in delta_q:\n        current_value = ic.get_single_q_element(coordinate_list, coordinate)\n        target_value = constraints[coordinate]\n        new_constraint = self.get_corrected_indices(coordinate)\n        if len(coordinate) &gt; 2:\n            current_value *= 180 / np.pi\n            target_value *= 180 / np.pi\n        current_value = float(format(current_value, \".4f\"))\n        target_value = float(format(target_value, \".4f\"))\n        delta = delta_q[coordinate]\n        total_delta += abs(delta)\n        delta /= num_steps[coordinate]\n        updates[coordinate] = delta\n        if abs(delta) &gt; maximum_delta:\n            maximum_delta = abs(delta)\n        self.write_log(f\"{coordinate}: \\t {current_value} -&gt; {target_value}\\n\")\n\n    # Reset updates when hessian is used ...\n    if self.use_hessian:\n        for constraint in constraints:\n            updates[constraint] = total_delta / num_scan\n\n    # Change step size\n\n    self.write_log(\n        \"\\n ################## Update Information ################### \\n\"\n    )\n    self.write_log(f\"Use hessian: {self.use_hessian}\\n\")\n    self.write_log(f\"Hessian update (if used): {self.hessian_update}\\n\")\n\n    original_step_size = self.step_size\n    # Set default step size: (Maximum delta x/num_relaxation * 3)\n    if self.step_size == 0:\n        if self.use_hessian:\n            self.step_size = total_delta / num_scan\n            self.step_size *= 3 / self.num_relaxation\n        else:\n            self.step_size = maximum_delta / self.num_relaxation * 3\n        self.write_log(\n            f\"Step size is set to {round(self.step_size,4)} as the default value!!!\\n\\n\"\n        )\n\n    # Set default step size: (Maximum delta x/num_relaxation * 3)\n    self.write_log(\n        \"########## Scanning information ##########\\n\" + str(self) + \"\\n\"\n    )\n    ###### Write basic informations #####\n    self.write_log(\n        \"##### Calculator information ######\\n\" + str(self.calculator)\n    )  # Calculator information\n    self.write_log(\n        f\"\\nAll electronic energies are written in {self.energy_unit}! \\n\"\n    )\n    self.write_log(\"All distances are written in angstrom! \\n\")\n    self.write_log(\"All angles are written in degree(o)! \\n\\n\")\n\n    st = datetime.datetime.now()\n    self.write_log(f\"Starting time: {st}\\n\")\n    print(\"scanning ...\")\n    list_of_constraints = list(constraints.keys())\n    self.write_log(\"Set up done!!!\\n\")\n    if reoptimize:\n        now = datetime.datetime.now()\n        now = str(now)[:-digit]\n        self.write_log(f\"[{now}] Reoptmizing current geometry ...\\n\")\n        # To start with the geometries of reactants that are near local minima ...\n        relaxing_path = self.calculator.relax_geometry(\n            molecule, constraints, chg, multiplicity, \"Reactant\", None, 1000\n        )\n        if len(relaxing_path) &lt; 1:\n            self.write_log(\n                f\"[{datetime.datetime.now()}] Calculation did not terminate properly !!!\\n\"\n            )\n            file_directory = os.path.join(\n                self.calculator.error_directory, f\"{self.calculator.name}.err\"\n            )\n            self.write_log(f\"Check file {file_directory} !!! \\n\")\n            self.write_log(\"Terminating pyMCD ... \\n\")\n            # self.make_restart_file(molecule,constraints,num_steps)\n            return []\n        try:\n            self.num_force_calls += len(relaxing_path)\n        except:\n            a = 1\n        now = datetime.datetime.now()\n        now = str(now)[:-digit]\n        self.write_log(f\"[{now}] Relaxation finished! Start scanning ....\\n\")\n    else:\n        self.write_log(\"Calculating the energy of current geometry ...\\n\")\n        energy = self.calculator.get_energy(molecule, chg, multiplicity)\n        if energy is None:\n            self.write_log(\n                f\"[{datetime.datetime.now()}] Calculation did not terminate properly !!!\\n\"\n            )\n            file_directory = os.path.join(\n                self.calculator.error_directory, f\"{self.calculator.name}.err\"\n            )\n            self.write_log(f\"Check file {file_directory} !!! \\n\")\n            self.write_log(\"Terminating pyMCD ... \\n\")\n            return []\n        molecule.energy = energy\n    copied_molecule = molecule.copy()\n    copied_molecule.energy = molecule.energy\n    trajectory = [copied_molecule]  # Trajectory is list of coordinates\n    # self.print_status(molecule,constraints)\n    energy_list = [molecule.energy]\n    if restart:\n        self.update_pathway(copied_molecule, \"a\")\n    else:\n        self.update_pathway(copied_molecule, \"w\")\n    for iteration in range(num_scan):\n        starttime = datetime.datetime.now()\n        # self.write_log(f'[{starttime}] Performing one step search ... ({len(trajectory)-1}/{total_num_scans}) completed ... \\n')\n        # Update/Relax geometry\n        self.print_status(molecule, constraints)\n        self.update_geometry(molecule, constraints, updates, chg, multiplicity)\n        tmp_st = str(datetime.datetime.now())[:-digit]\n        content = f\"[{tmp_st}] Progress ({iteration+1}/{num_scan}): \"\n        constraint_contents = []\n        for coordinate in constraints:\n            new_constraint = self.get_corrected_indices(coordinate)\n            constraint_contents.append(\n                f'{new_constraint}: {round(molecule.get_internal_coordinate(coordinate,\"degree\"),5)}'\n            )\n        content = content + \", \".join(constraint_contents)\n        self.write_log(content + \"\\n\")\n        relaxing_path = self.calculator.relax_geometry(\n            molecule,\n            list_of_constraints,\n            chg,\n            multiplicity,\n            \"test\",\n            self.num_relaxation,\n            self.step_size,\n        )\n        # scfenergies = calculated_data.scfenergies[]\n        # print ('relaxation energy: ',scfenergies[0] - molecule.energy)\n        if len(relaxing_path) &lt; 1:\n            self.write_log(\n                f\"[{datetime.datetime.now()}] Calculation did not terminate properly !!!\\n\"\n            )\n            self.write_log(f\"Check file {self.calculator.name}.err ...\\n\")\n            self.write_log(\"Terminating pyMCD ... \\n\")\n            self.make_restart_file(molecule, constraints, num_steps)\n            return []\n\n        try:\n            self.num_force_calls += len(relaxing_path)\n        except:\n            a = 1\n        endtime = datetime.datetime.now()\n        energy = molecule.energy\n        copied_molecule = molecule.copy()\n        copied_molecule.energy = energy\n        # Summary log for a single step\n        delta_e = energy - energy_list[-1]\n        delta_time = endtime - starttime\n        word = \"Increased\"\n        exponent = int(np.log10(np.abs(delta_e)))\n        x = delta_e * 10 ** (-exponent)\n        if x &lt; 0:\n            word = \"Decreased\"\n            x *= -1\n        x = format(x, \".4f\")\n        endtime = str(endtime)[:-digit]\n        delta_time = str(delta_time)[:-digit]\n        self.write_log(\n            f\"[{endtime}] {x}E{exponent} {self.energy_unit} has {word}. {delta_time} Taken ... Total {self.num_force_calls} force calls performed !!!\\n\"\n        )\n        energy_list.append(energy)\n        # Save/Copy new molecule\n        self.update_pathway(copied_molecule, \"a\")\n        trajectory.append(copied_molecule)\n        delta_energy = energy_list[-1] - energy_list[-2]\n        print(\"Energy increase: \", delta_energy)\n        print(\"Energy: \", energy_list)\n    self.write_log(f\"[{datetime.datetime.now()}] Scan completed ...\\n\")\n    self.write_log(\n        f\"Total {self.num_force_calls} force calculations performed ...\\n\"\n    )\n    self.write_log(\n        f\"Total {self.num_hessian_calls} hessian calculations performed ...\\n\"\n    )\n    self.write_profile(trajectory)\n    et = datetime.datetime.now()\n    self.write_log(f\"End time: {et}\\n\")\n    self.write_log(f\"Taken time: {et-st}\\n\")\n    self.calculator.error_directory = None\n    self.step_size = original_step_size\n    self.previous_gradient = None\n    self.previous_hessian = None\n    self.previous_geometry = None\n\n    return trajectory\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.select_coordinate","title":"select_coordinate","text":"<pre><code>select_coordinate(coordinate_list, dV_dx, delta_q, scanning_coordinates)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def select_coordinate(self, coordinate_list, dV_dx, delta_q, scanning_coordinates):\n    # Get inner products (coefficients)\n    constraints = list(delta_q.keys())\n    dV_dq = ic.get_gradient_q(dV_dx, coordinate_list, constraints)\n    minimum = 1000000\n    # print (dV_dq)\n    delta_es = dict()\n    for idx, internal_coordinate in enumerate(constraints):\n        if internal_coordinate not in scanning_coordinates:\n            continue\n        sign = 1\n        if delta_q[internal_coordinate] &lt; 0:\n            sign = -1\n        delta_e = dV_dq[idx][0] * sign\n        delta_es[internal_coordinate] = delta_e\n        if delta_e &lt; minimum:\n            minimum = delta_e\n            selected_coordinate = internal_coordinate\n    # print ('product: ',delta_es,selected_coordinate)\n    print(\"Expected energy change:\", minimum)\n    return selected_coordinate\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.update_geometry","title":"update_geometry","text":"<pre><code>update_geometry(molecule, constraints, updates, chg=None, multiplicity=None)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def update_geometry(\n    self, molecule, constraints, updates, chg=None, multiplicity=None\n):\n    num_relaxation = self.num_relaxation  # N\n    coordinate_list = molecule.get_coordinate_list()\n    delta_q, update_q = self.get_delta_q(\n        coordinate_list, constraints\n    )  # Only scanning coordinates are survived\n    # If you want to put additional redundnat coordinate, activate consider_redundant, and implement your own redundant coordinate (Default: If activated, interatomic distance between bonded atoms are added)\n    scanning_coordinates = []\n    atom_list = molecule.atom_list\n    n = len(atom_list)\n    for constraint in delta_q:\n        if abs(delta_q[constraint]) &gt; 0.001:\n            scanning_coordinates.append(constraint)\n    if len(scanning_coordinates) &gt; 1:\n        update_size = updates[scanning_coordinates[0]]\n        # Make update vector\n        if self.use_hessian:\n            dV_dx, hessian = self.get_hessian(molecule, chg, multiplicity)\n            dV_dq = ic.get_gradient_q(dV_dx, coordinate_list, constraints)\n            H_q = ic.get_hessian_q(dV_dx, hessian, coordinate_list, constraints)\n\n            # Make reduce function\n            reduced_indices = []\n            for idx, internal_coordinate in enumerate(constraints):\n                if internal_coordinate in scanning_coordinates:\n                    reduced_indices.append(idx)\n            reduce_function = np.ix_(reduced_indices, reduced_indices)\n            dV_dq = dV_dq[reduced_indices]\n            H_q = H_q[reduce_function]\n            # print (dV_dq)\n            # print (hessian,H_q)\n            # Make update vector\n            solution = self.find_solution(\n                dV_dq, H_q, update_size, delta_q, scanning_coordinates\n            )\n            for constraint in solution:\n                update_q[constraint] = solution[constraint]\n\n            # After using them, update previous ...\n            self.previous_gradient = dV_dx\n            self.previous_hessian = hessian\n            self.previous_geometry = molecule.get_coordinate_list()\n        else:\n            dV_dx = self.get_gradient(molecule, chg, multiplicity)\n            selected_coordinate = self.select_coordinate(\n                coordinate_list, dV_dx, delta_q, scanning_coordinates\n            )\n            # Update geometry using ic module\n            update_q[selected_coordinate] = updates[selected_coordinate]\n    else:\n        constraint = scanning_coordinates[0]\n        delta = delta_q[constraint]\n        if self.use_hessian:\n            update_size = updates[constraint]\n            if delta &gt; 0:\n                update_q[constraint] = min(delta, update_size)\n            else:\n                update_q[constraint] = max(delta, -update_size)\n        else:\n            update_q[constraint] = updates[constraint]\n        force = None\n    # molecule.print_coordinate_list()\n    ic.update_geometry(coordinate_list, update_q)\n    process.locate_molecule(molecule, coordinate_list)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.update_pathway","title":"update_pathway","text":"<pre><code>update_pathway(calculated_molecule, mode='a')\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def update_pathway(\n    self, calculated_molecule, mode=\"a\"\n):  # Calculated molecule that will be added to the current pathway\n    save_directory = self.log_directory\n    if save_directory == \"\":\n        print(\"No log directory!!! We do not save the pathway!!!\")\n    else:\n        # Save xyz file\n        with open(os.path.join(save_directory, \"pathway.xyz\"), mode) as f:\n            f.write(\n                str(len(calculated_molecule.atom_list))\n                + \"\\n\"\n                + str(calculated_molecule.energy)\n                + \"\\n\"\n            )\n            for atom in calculated_molecule.atom_list:\n                content = atom.get_content()\n                f.write(content)\n            f.flush()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.write_log","title":"write_log","text":"<pre><code>write_log(content, mode='a')\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def write_log(self, content, mode=\"a\"):\n    if self.log_directory == \"\":\n        print(\"No log directory!!! We write nothing!!!\")\n    else:\n        log_directory = os.path.join(self.log_directory, \"output.log\")\n        with open(log_directory, mode) as f:\n            f.write(content)\n            f.flush()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/mcd.html#himatcal.utils.mcd.mcd.MCD.write_profile","title":"write_profile","text":"<pre><code>write_profile(trajectory)\n</code></pre> Source code in <code>himatcal/utils/mcd/mcd.py</code> <pre><code>def write_profile(self, trajectory):\n    # Save trajectory with log file and trajectory files (xyz, pkl)\n    save_directory = self.log_directory\n    n = len(trajectory)\n    energy_list = []\n    for i in range(n):\n        molecule = trajectory[i]\n        energy_list.append(molecule.energy)\n    n = len(energy_list)\n    energy_log = open(os.path.join(save_directory, \"profile.log\"), \"w\")\n\n    # Always make it into kcal/mol\n    converter = 1\n    if self.energy_unit == \"Hartree\":\n        converter = 627.5094740631\n    elif self.energy_unit == \"eV\":\n        converter = 23.0605506577\n    energy_log.write(\n        f\"Original Energy ({self.energy_unit}/mol) \\t Relative Energy (kcal/mol)\\n\"\n    )\n    reference_energy = energy_list[0]\n    maximum_index = 0\n    maximum_energy = -100000000\n    relative_energy_list = []\n    for i in range(n):\n        relative_energy = energy_list[i] - reference_energy\n        relative_energy_list.append(relative_energy * converter)\n        energy = energy_list[i]\n        energy_log.write(f\"{energy} \\t {relative_energy*converter}\\n\")\n        if energy &gt; maximum_energy:\n            maximum_energy = energy\n            maximum_index = i\n    # Save figure\n    self.save_figure(relative_energy_list, \"kcal\")\n    # Write maxima point ...\n    trajectory[maximum_index].write_geometry(os.path.join(save_directory, \"ts.xyz\"))\n\n    # Search valley indices with using Golay Filter\n    for i in range(self.num_filter_iteration):\n        window_length = min(\n            9, len(energy_list)\n        )  # Ensure window_length is less than or equal to the size of energy_list\n        energy_list = savgol_filter(energy_list, window_length, 4)\n\n    left_min = None\n    max_index = None\n    ts_indices = []\n    right_min = None\n    max_energy_index = None\n    max_energy = -1000000\n\n    # Assume that curve is now well smoothed ...\n    for i in range(n - 1):\n        # print (left_min,max_index)\n        if left_min is None:\n            if energy_list[i] &lt; energy_list[i + 1]:  # Increasing\n                left_min = i\n        else:\n            if max_index is None:\n                if energy_list[i] &gt; energy_list[i + 1]:  # Decreasing\n                    max_index = i\n            else:\n                if energy_list[i] &lt; energy_list[i + 1]:  # If reincreasing ...\n                    right_min = i\n                    ts_indices.append(max_index)\n                    left_min = i\n                    max_index = None  # Search for the next local maximum\n                elif i == n - 2:\n                    right_min = i\n                    ts_indices.append(max_index)\n\n    # Write maxima points\n    if len(ts_indices) &gt; 0:\n        content = \", \".join([str(ts_index) for ts_index in ts_indices])\n        energy_log.write(\n            f\"\\nLocal maxima around {content}th point(s) are found !!!\\n\\n\"\n        )\n    else:\n        energy_log.write(\n            \"No local maxima points are found !!! May be barrierless reaction ???\\n\\n\"\n        )\n    energy_log.close()\n\n    if len(ts_indices) == 0:\n        self.write_log(\"Caution: Barrierless reaction is found !!!\\n\")\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/process.html","title":"process","text":"<p>---generate_molecule.py--- Generate 2D graph molecule in ACE-Reaction format from xyz files or SMILES</p>"},{"location":"reference/himatcal/utils/mcd/process.html#himatcal.utils.mcd.process.locate_atom","title":"locate_atom","text":"<pre><code>locate_atom(atom, coordinate)\n</code></pre> <p>Locates a single atom to input 'coordinate' Args:     |  atom (): class instance of Atom     |  coordinate (list of float): coordinate in form of [x,y,z] Returns:     |  No return, it directly locates the atom to the given coordinate Source code in <code>himatcal/utils/mcd/process.py</code> <pre><code>def locate_atom(atom, coordinate):\n    \"\"\"Locates a single atom to input 'coordinate'\n    Args:\n        |  atom (&lt;class 'Atom'&gt;): class instance of Atom\n        |  coordinate (list of float): coordinate in form of [x,y,z]\n    Returns:\n        |  No return, it directly locates the atom to the given coordinate\n    \"\"\"\n    atom.x = coordinate[0]\n    atom.y = coordinate[1]\n    atom.z = coordinate[2]\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/process.html#himatcal.utils.mcd.process.locate_molecule","title":"locate_molecule","text":"<pre><code>locate_molecule(ace_molecule, coordinate_list)\n</code></pre> <p>Locates atoms according to coordinate_list, be cautious on ordering of atoms Args:     |  ace_molecule (): class instance of Molecule     |  coordinate_list (list of list (x,y,z)): list of 3d coordinate, where each x,y,z are float type Returns:     |  No return, it direcly modifies the geometry of a given molecule Source code in <code>himatcal/utils/mcd/process.py</code> <pre><code>def locate_molecule(ace_molecule, coordinate_list):\n    \"\"\"Locates atoms according to coordinate_list, be cautious on ordering of atoms\n    Args:\n        |  ace_molecule (&lt;class 'Molecule'&gt;): class instance of Molecule\n        |  coordinate_list (list of list (x,y,z)): list of 3d coordinate, where each x,y,z are float type\n    Returns:\n        |  No return, it direcly modifies the geometry of a given molecule\n    \"\"\"\n    atom_list = ace_molecule.atom_list\n    for i in range(len(atom_list)):\n        atom = atom_list[i]\n        atom.set_coordinate(coordinate_list[i])\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/process.html#himatcal.utils.mcd.process.translate_atom","title":"translate_atom","text":"<pre><code>translate_atom(atom, vector)\n</code></pre> Source code in <code>himatcal/utils/mcd/process.py</code> <pre><code>def translate_atom(atom, vector):\n    atom.x += vector[0]\n    atom.y += vector[1]\n    atom.z += vector[2]\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/process.html#himatcal.utils.mcd.process.translate_molecule","title":"translate_molecule","text":"<pre><code>translate_molecule(ace_molecule, vector)\n</code></pre> Source code in <code>himatcal/utils/mcd/process.py</code> <pre><code>def translate_molecule(ace_molecule, vector):\n    atom_list = ace_molecule.atom_list\n    for atom in atom_list:\n        translate_atom(atom, vector)\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html","title":"run","text":""},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.pathway","title":"pathway  <code>module-attribute</code>","text":"<pre><code>pathway = generate_path()\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.change_option","title":"change_option","text":"<pre><code>change_option(args)\n</code></pre> Source code in <code>himatcal/utils/mcd/run.py</code> <pre><code>def change_option(args):\n    correct = True\n    try:\n        option_directory = os.path.join(args.input_directory, \"option\")\n    except:\n        print(\"Default option is used !!!\")\n        return\n    if os.path.exists(option_directory):\n        wrong_attributes = []\n        with open(option_directory) as f:\n            for line in f:\n                words = line.strip().split(\"=\")\n                attribute = words[0]\n                value = words[1]\n                if attribute == \"working_directory\":\n                    args.working_directory = value\n                elif attribute == \"num_relaxation\":\n                    try:\n                        value = int(value)\n                        if value &lt;= 0:\n                            print(\n                                f\"Wrong num_relaxation (={value}) is given! Check the option file !!!\"\n                            )\n                            print(\"The value must be positive integer !!!\\n\")\n                            correct = False\n                        else:\n                            args.num_relaxation = value\n                    except:\n                        print(\n                            f\"Wrong num_relaxation (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\"The value must be positive integer !!!\\n\")\n                        correct = False\n                elif attribute == \"step_size\":\n                    try:\n                        value = float(value)\n                        if value &lt;= 0.0:\n                            print(\n                                f\"Wrong step_size (={value}) is given! Check the option file !!!\"\n                            )\n                            print(\"The value must be positive !!!\\n\")\n                            correct = False\n                        else:\n                            args.step_size = value\n                    except:\n                        print(\n                            f\"Wrong step_size (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\"The value must be positive !!!\\n\")\n                        correct = False\n                elif attribute == \"unit\":\n                    if value not in [\"eV\", \"Hartree\", \"kcal\"]:\n                        print(\n                            f\"Wrong unit (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\"Only eV, Hartree, kcal are allowed options !!!\\n\")\n                        correct = False\n                    else:\n                        args.unit = value\n                elif attribute == \"calculator\":\n                    args.calculator = value\n                elif attribute == \"command\":\n                    args.command = value\n                elif attribute == \"use_hessian\":\n                    try:\n                        value = int(value)\n                        if value not in [0, 1]:\n                            print(\n                                f\"Wrong use_hessian (={value}) is given! Check the option file !!!\"\n                            )\n                            print(\n                                \"Only 0 or 1 are possible. If the value is zero, hessian is not used. Otherwise, hessian is used ... Default value is 0 \\n\"\n                            )\n                            correct = False\n                        else:\n                            args.use_hessian = value\n                    except:\n                        print(\n                            f\"Wrong use_hessian (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\n                            \"Only 0 or 1 are possible. If the value is zero, hessian is not used. Otherwise, hessian is used ... Default value is 0 \\n\"\n                        )\n                        correct = False\n\n                elif attribute == \"hessian_update\":\n                    if str.lower(value) not in [\"exact\", \"bofill\"]:\n                        print(\n                            f\"Wrong hessian_update (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\n                            \"Only bofill and exact are possible options !!! Default method is bofill\\n\"\n                        )\n                        correct = False\n                    else:\n                        args.hessian_update = value\n\n                elif attribute == \"reoptimize\":\n                    try:\n                        value = int(value)\n                        if value not in [0, 1]:\n                            print(\n                                f\"Wrong reoptimize (={value}) is given! Check the option file !!!\"\n                            )\n                            print(\n                                \"Only 0 or 1 are possible. If the value is zero, given geometry is directly undergone MCD, otherwise, the molecule is reoptimized !!! Default value is 1\\n\"\n                            )\n                            correct = False\n                        else:\n                            args.reoptimize = value\n                    except:\n                        print(\n                            f\"Wrong reoptimize (={value}) is given! Check the option file !!!\"\n                        )\n                        print(\n                            \"Only 0 or 1 are possible. If the value is zero, given geometry is directly undergone MCD, otherwise, the molecule is reoptimized !!! Default value is 1\\n\"\n                        )\n                        correct = False\n                else:\n                    wrong_attributes.append(attribute)\n                    correct = False\n\n            if len(wrong_attributes) &gt; 0:\n                content = \",\".join(wrong_attributes)\n                print(\n                    f\"Wrong attribute(s) (={content}) is given! Check the option file !!!\"\n                )\n                print(\n                    \"Possible attributes are 'working_directory', 'num_relaxation','step_size','unit','calculator','command','use_hessian','hessian_update','reoptimize'\"\n                )\n\n    else:\n        print(\"option directory is not found! Default parameters are used!!!\")\n\n    return correct\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.generate_path","title":"generate_path","text":"<pre><code>generate_path()\n</code></pre> Source code in <code>himatcal/utils/mcd/run.py</code> <pre><code>def generate_path():\n    parser = argparse.ArgumentParser()\n    parser.add_argument(\n        \"--input_directory\", \"-id\", type=str, help=\"directory of inputs\"\n    )\n    parser.add_argument(\n        \"--output_directory\",\n        \"-od\",\n        type=str,\n        help=\"directory for saving outputs\",\n        default=None,\n    )\n    parser.add_argument(\n        \"--working_directory\",\n        \"-wd\",\n        type=str,\n        help=\"scratch directory of QC programs\",\n        default=\"\",\n    )\n    parser.add_argument(\n        \"--num_relaxation\", type=int, help=\"Num relaxation for input\", default=5\n    )\n    parser.add_argument(\n        \"--step_size\", type=float, help=\"Maxmial displacement\", default=0.0\n    )\n    parser.add_argument(\n        \"--calculator\",\n        \"-c\",\n        type=str,\n        help=\"Name of Quantum Calculation software\",\n        default=\"gaussian\",\n    )\n    parser.add_argument(\"--unit\", \"-u\", type=str, help=\"unit\", default=\"Hartree\")\n    parser.add_argument(\n        \"--command\", type=str, help=\"command for running qc package\", default=\"g09\"\n    )\n    parser.add_argument(\"--use_hessian\", type=int, default=0)\n    parser.add_argument(\"--restart\", type=int, default=0)\n    parser.add_argument(\"--hessian_update\", type=str, default=\"bofill\")\n    parser.add_argument(\"--reoptimize\", type=int, default=1)\n\n    args = parser.parse_args()\n\n    input_directory = args.input_directory\n    output_directory = args.output_directory\n    if output_directory is None:\n        output_directory = input_directory\n    # If problem with input, output directory, automatically exit\n    if not os.path.exists(input_directory):\n        print(\"Cannot find the input directory !!!\")\n        exit()\n    elif not os.path.exists(output_directory):\n        print(\"Given output directory is not found !!!\")\n        exit()\n\n    print(f\"\\ninput directory: {input_directory}\")\n    print(f\"output directory: {output_directory}\\n\")\n\n    reactant = read_reactant(input_directory)  # Read geometry of reactant\n    constraints, num_steps = read_bond_info(input_directory)  # bond info\n    correct = change_option(args)  # Read option file and change values in args\n\n    use_hessian = args.use_hessian\n    reoptimize = args.reoptimize\n\n    restart = args.restart\n\n    if use_hessian == 0:\n        use_hessian = False\n    else:\n        use_hessian = True\n\n    if reoptimize == 0:\n        reoptimize = False\n    else:\n        reoptimize = True\n\n    if restart == 0:\n        restart = False\n    else:\n        restart = True\n\n    if not correct:\n        exit()\n    calculator = get_calculator(\n        args\n    )  # Make calculator, you can use your own calculator!\n    if calculator is None:\n        exit()\n    scanner = mcd.MCD(num_relaxation=args.num_relaxation, calculator=calculator)\n    scanner.use_hessian = use_hessian\n    scanner.hessian_update = args.hessian_update\n    scanner.step_size = args.step_size\n    scanner.log_directory = output_directory\n    working_directory = args.working_directory\n    if working_directory != \"\":\n        if os.path.exists(working_directory):\n            scanner.change_working_directory(working_directory)\n        else:\n            print(\n                \"working directory does not exist!!! Using output directory as default ...\"\n            )\n            working_directory = output_directory\n    else:\n        # print ('adfasdfa',output_directory)\n        working_directory = output_directory\n    scanner.change_working_directory(working_directory)\n    print(f\"working directory: {working_directory}\\n\")\n\n    scanner.change_energy_unit(args.unit)\n    # exit()\n    # Also, write constraints information (TODO)\n\n    num_scan = sum(num_steps.values())\n\n    print(\"\\n=======================================================\")\n    print(\"================= MCD RUNNING !!! ===================\")\n    print(\"=======================================================\\n\")\n\n    pathway = scanner.scan(\n        reactant,\n        constraints,\n        num_steps,\n        chg=reactant.chg,\n        multiplicity=reactant.multiplicity,\n    )\n    return pathway\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.get_calculator","title":"get_calculator","text":"<pre><code>get_calculator(args)\n</code></pre> Source code in <code>himatcal/utils/mcd/run.py</code> <pre><code>def get_calculator(args):\n    calculator_name = args.calculator.lower()\n    if calculator_name == \"gaussian\":\n        from himatcal.calculator.gaussian_mcd import Gaussian\n\n        calculator = Gaussian(args.command)\n    elif calculator_name == \"orca\":\n        from himatcal.calculator.orca_mcd import Orca\n\n        calculator = Orca(args.command)\n    else:\n        print(\n            f\"Wrong calculator (={calculator_name}) is given! Check the option file !!!\"\n        )\n        calculator = None\n        return calculator\n    calculator.load_content(os.path.join(args.input_directory, \"qc_input\"))\n    basis_file = os.path.join(\n        args.input_directory, \"basis\"\n    )  # For Effective Core Potential\n    if os.path.exists(basis_file):\n        calculator.load_basis(basis_file)\n    return calculator\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.read_bond_info","title":"read_bond_info","text":"<pre><code>read_bond_info(directory)\n</code></pre> Source code in <code>himatcal/utils/mcd/run.py</code> <pre><code>def read_bond_info(directory):\n    constraints = dict()\n    num_steps = dict()\n    formed_bonds = []\n    broken_bonds = []\n    try:\n        f = open(os.path.join(directory, \"coordinates\"))\n    except:\n        print(\"Cannot find 'coordinates' file! Recheck your input !!!\")\n        exit()\n    for line in f:\n        info = line.strip().split()  # 0: start, 1: end, 2: target length, 3: Num steps\n        if len(info) &gt; 0:\n            try:\n                constraint = tuple([int(idx) - 1 for idx in info[:-2]])\n                target_value = float(info[-2])\n            except:\n                print(\"Wrong coordinate found! Check coordinate file again !!!\")\n                print(f\"Current line: {line.strip()}\")\n                print(\n                    \"Input should be given as: [Coordinate] [target value] [num_step]\"\n                )\n                exit()\n            if len(constraint) &lt; 2:\n                print(\"Wrong coordinate found! Check coordinate file again !!!\")\n                print(f\"Current line: {line.strip()}\")\n                print(\n                    \"Input should be given as: [Coordinate] [target value] [num_step]\"\n                )\n                exit()\n            if len(constraint) &gt; 2:\n                target_value *= np.pi / 180\n            constraints[constraint] = target_value\n            try:\n                num_steps[constraint] = int(info[-1])\n            except:\n                print(\"Num steps are not given! Check coordinate file again !!!\")\n                print(\n                    \"Input should be given as: [Coordinate] [target value] [num_step]\"\n                )\n                exit()\n    return constraints, num_steps\n</code></pre>"},{"location":"reference/himatcal/utils/mcd/run.html#himatcal.utils.mcd.run.read_reactant","title":"read_reactant","text":"<pre><code>read_reactant(directory)\n</code></pre> Source code in <code>himatcal/utils/mcd/run.py</code> <pre><code>def read_reactant(directory):\n    try:\n        f = open(os.path.join(directory, \"R.com\"))\n    except:\n        print(\"Cannot find 'R.com' file! Recheck your input !!!\")\n        exit()\n    state_info = f.readline().strip().split(\" \")\n    chg, multiplicity = int(state_info[0]), int(state_info[1])\n    atom_list = []\n    atom_info = f.readline()\n    while atom_info.strip() != \"\":\n        atom_info = atom_info.strip().split()\n        # print (atom_info)\n        atom_type = atom_info[0]\n        x = float(atom_info[1])\n        y = float(atom_info[2])\n        z = float(atom_info[3])\n        atom = chem.Atom(atom_type)\n        atom.x = x\n        atom.y = y\n        atom.z = z\n        atom_list.append(atom)\n        try:\n            atom_info = f.readline()\n            if atom_info.strip() == \"\":\n                break\n        except:\n            break\n    f.close()\n    reactant = chem.Molecule()\n    reactant.atom_list = atom_list\n    reactant.chg = chg\n    reactant.multiplicity = multiplicity\n    return reactant\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html","title":"core","text":"<p>https://github.com/zincware/rdkit2ase/tree/main</p>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.OBJ_OR_STR","title":"OBJ_OR_STR  <code>module-attribute</code>","text":"<pre><code>OBJ_OR_STR = Union[str, Mol, Atoms]\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.OBJ_OR_STR_OR_LIST","title":"OBJ_OR_STR_OR_LIST  <code>module-attribute</code>","text":"<pre><code>OBJ_OR_STR_OR_LIST = Union[OBJ_OR_STR, list[tuple[OBJ_OR_STR, float]]]\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.ase2rdkit","title":"ase2rdkit","text":"<pre><code>ase2rdkit(atoms: Atoms, charge: int = 0) -&gt; Mol\n</code></pre> <p>Convert an ASE Atoms object to an RDKit molecule.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def ase2rdkit(atoms: Atoms, charge:int=0) -&gt; Chem.Mol:\n    \"\"\"Convert an ASE Atoms object to an RDKit molecule.\"\"\"\n    with io.StringIO() as f:\n        write(f, atoms, format=\"xyz\")\n        f.seek(0)\n        xyz = f.read()\n        raw_mol = Chem.MolFromXYZBlock(xyz)\n\n    mol = Chem.Mol(raw_mol)\n    rdDetermineBonds.DetermineBonds(mol, charge=charge)\n    return mol\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.pack","title":"pack","text":"<pre><code>pack(data: list[list[Atoms]], counts: list[int], density: float, seed: int = 42, tolerance: float = 2, logging: bool = False) -&gt; Atoms\n</code></pre> <p>Pack the given molecules into a box with the specified density.</p> <p>Parameters:</p> <ul> <li> <code>data</code>               (<code>list[list[Atoms]]</code>)           \u2013            <p>A list of lists of ASE Atoms objects representing the molecules to be packed.</p> </li> <li> <code>counts</code>               (<code>list[int]</code>)           \u2013            <p>A list of integers representing the number of each type of molecule.</p> </li> <li> <code>density</code>               (<code>float</code>)           \u2013            <p>The target density of the packed system in kg/m^3.</p> </li> <li> <code>seed</code>               (<code>int</code>, default:                   <code>42</code> )           \u2013            <p>The random seed for reproducibility, by default 42.</p> </li> <li> <code>tolerance</code>               (<code>float</code>, default:                   <code>2</code> )           \u2013            <p>The tolerance for the packing algorithm, by default 2.</p> </li> <li> <code>logging</code>               (<code>bool</code>, default:                   <code>False</code> )           \u2013            <p>If True, enables logging of the packing process, by default False.</p> </li> </ul> <p>Returns:</p> <ul> <li> <code>Atoms</code>           \u2013            <p>An ASE Atoms object representing the packed system.</p> </li> </ul> Example <p>from rdkit2ase import pack, smiles2conformers water = smiles2conformers(\"O\", 1) ethanol = smiles2conformers(\"CCO\", 1) density = 1000  # kg/m^3 packed_system = pack([water, ethanol], [7, 5], density) print(packed_system) Atoms(symbols='C10H44O12', pbc=True, cell=[8.4, 8.4, 8.4])</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def pack(\n    data: list[list[Atoms]],\n    counts: list[int],\n    density: float,\n    seed: int = 42,\n    tolerance: float = 2,\n    logging: bool = False,\n) -&gt; Atoms:\n    \"\"\"\n    Pack the given molecules into a box with the specified density.\n\n    Parameters\n    ----------\n    data : list[list[Atoms]]\n        A list of lists of ASE Atoms objects representing the molecules to be packed.\n    counts : list[int]\n        A list of integers representing the number of each type of molecule.\n    density : float\n        The target density of the packed system in kg/m^3.\n    seed : int, optional\n        The random seed for reproducibility, by default 42.\n    tolerance : float, optional\n        The tolerance for the packing algorithm, by default 2.\n    logging : bool, optional\n        If True, enables logging of the packing process, by default False.\n\n    Returns\n    -------\n    Atoms\n        An ASE Atoms object representing the packed system.\n\n    Example\n    -------\n    &gt;&gt;&gt; from rdkit2ase import pack, smiles2conformers\n    &gt;&gt;&gt; water = smiles2conformers(\"O\", 1)\n    &gt;&gt;&gt; ethanol = smiles2conformers(\"CCO\", 1)\n    &gt;&gt;&gt; density = 1000  # kg/m^3\n    &gt;&gt;&gt; packed_system = pack([water, ethanol], [7, 5], density)\n    &gt;&gt;&gt; print(packed_system)\n    Atoms(symbols='C10H44O12', pbc=True, cell=[8.4, 8.4, 8.4])\n    \"\"\"\n    rng = np.random.default_rng(seed)\n    selected_idx: list[np.ndarray] = []\n\n    for images, count in zip(data, counts):\n        selected_idx.append(\n            rng.choice(range(len(images)), count, replace=len(images) &lt; count)\n        )\n\n    images = [\n        [data[category][idx] for idx in indices]\n        for category, indices in enumerate(selected_idx)\n    ]\n    images = functools.reduce(operator.iadd, images, [])\n\n    cell = _get_cell_vectors(images=images, density=density)\n\n    file = f\"\"\"\ntolerance {tolerance}\nfiletype xyz\noutput mixture.xyz\npbc 0 0 0 {\" \".join([f\"{x:.6f}\" for x in cell])}\n    \"\"\"\n    for category, indices in enumerate(selected_idx):\n        for idx in indices:\n            file += f\"\"\"\nstructure struct_{category}_{idx}.xyz\n    filetype xyz\n\nend structure\n                     \"\"\"\n\n    with tempfile.TemporaryDirectory() as tmpdir:\n        tmpdir_path = pathlib.Path(tmpdir)\n        for category, indices in enumerate(selected_idx):\n            for idx in set(indices):\n                atoms = data[category][idx]\n                write(tmpdir_path / f\"struct_{category}_{idx}.xyz\", atoms, format=\"xyz\")\n        (tmpdir_path / \"pack.inp\").write_text(file)\n        subprocess.run(\n            \"packmol &lt; pack.inp\",\n            cwd=tmpdir_path,\n            shell=True,\n            check=True,\n            capture_output=not logging,\n        )\n        atoms: Atoms = read(tmpdir_path / \"mixture.xyz\")\n\n    atoms.cell = cell\n    atoms.pbc = True\n    return atoms\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.plot_gasteiger_charges","title":"plot_gasteiger_charges","text":"<pre><code>plot_gasteiger_charges(mol)\n</code></pre> <p>Plot Gasteiger charges on a molecule.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def plot_gasteiger_charges(mol):\n    \"\"\"\n    Plot Gasteiger charges on a molecule.\n    \"\"\"\n    from rdkit.Chem.Draw import SimilarityMaps\n\n    AllChem.ComputeGasteigerCharges(mol)\n    contribs = [\n        float(mol.GetAtomWithIdx(i).GetProp(\"_GasteigerCharge\"))\n        for i in range(mol.GetNumAtoms())\n    ]\n    SimilarityMaps.GetSimilarityMapFromWeights(\n        mol, contribs, colorMap=\"jet\", contourLines=10\n    )\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.rdkit2ase","title":"rdkit2ase","text":"<pre><code>rdkit2ase(mol) -&gt; Atoms\n</code></pre> <p>Convert an RDKit molecule to an ASE atoms object.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def rdkit2ase(mol) -&gt; Atoms:\n    \"\"\"Convert an RDKit molecule to an ASE atoms object.\"\"\"\n    mol = Chem.AddHs(mol)\n    AllChem.EmbedMolecule(mol)\n    AllChem.UFFOptimizeMolecule(mol)\n\n    return Atoms(\n        positions=mol.GetConformer().GetPositions(),\n        numbers=[atom.GetAtomicNum() for atom in mol.GetAtoms()],\n    )\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.smiles2atoms","title":"smiles2atoms","text":"<pre><code>smiles2atoms(smiles: str) -&gt; Atoms\n</code></pre> <p>Convert a SMILES string to an ASE Atoms object.</p> <p>Args:     smiles (str): The SMILES string.</p> <p>Returns:     atoms (Atoms): The Atoms object.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def smiles2atoms(smiles: str) -&gt; Atoms:\n    \"\"\"\n    Convert a SMILES string to an ASE Atoms object.\n\n    Args:\n        smiles (str): The SMILES string.\n\n    Returns:\n        atoms (Atoms): The Atoms object.\n    \"\"\"\n    mol = Chem.MolFromSmiles(smiles)\n    return rdkit2ase(mol)\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.smiles2conformers","title":"smiles2conformers","text":"<pre><code>smiles2conformers(smiles: str, numConfs: int, randomSeed: int = 42, maxAttempts: int = 1000) -&gt; list[Atoms]\n</code></pre> <p>Create multiple conformers for a SMILES string.</p> <p>Args:     smiles (str): The SMILES string.     numConfs (int): The number of conformers to generate.     randomSeed (int): The random seed.     maxAttempts (int): The maximum number of attempts.</p> <p>Returns:     images (list[Atoms]): The list of conformers.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def smiles2conformers(\n    smiles: str,\n    numConfs: int,\n    randomSeed: int = 42,\n    maxAttempts: int = 1000,\n) -&gt; list[Atoms]:\n    \"\"\"Create multiple conformers for a SMILES string.\n\n    Args:\n        smiles (str): The SMILES string.\n        numConfs (int): The number of conformers to generate.\n        randomSeed (int): The random seed.\n        maxAttempts (int): The maximum number of attempts.\n\n    Returns:\n        images (list[Atoms]): The list of conformers.\n    \"\"\"\n    mol = Chem.MolFromSmiles(smiles)\n    mol = Chem.AddHs(mol)\n    rdDistGeom.EmbedMultipleConfs(\n        mol,\n        numConfs=numConfs,\n        randomSeed=randomSeed,\n        maxAttempts=maxAttempts,\n    )\n\n    images: list[Atoms] = []\n\n    for conf in mol.GetConformers():\n        atoms = Atoms(\n            positions=conf.GetPositions(),\n            numbers=[atom.GetAtomicNum() for atom in mol.GetAtoms()],\n        )\n        images.append(atoms)\n\n    return images\n</code></pre>"},{"location":"reference/himatcal/utils/rdkit/core.html#himatcal.utils.rdkit.core.smiles_to_rdkit","title":"smiles_to_rdkit","text":"<pre><code>smiles_to_rdkit(smi, gen_3d=True, nconf=100)\n</code></pre> <p>Convert smiles to RDKit molecule. Tries to generate the lowest-energy conformer.</p> Source code in <code>himatcal/utils/rdkit/core.py</code> <pre><code>def smiles_to_rdkit(smi, gen_3d=True, nconf=100):\n    \"\"\"\n    Convert smiles to RDKit molecule.\n    Tries to generate the lowest-energy conformer.\n    \"\"\"\n    mol = Chem.MolFromSmiles(smi)\n    mol = Chem.AddHs(mol)\n\n    if gen_3d:\n        cids = AllChem.EmbedMultipleConfs(mol, nconf, AllChem.ETKDG())\n\n        AllChem.MMFFSanitizeMolecule(mol)\n        mmff_props = AllChem.MMFFGetMoleculeProperties(mol)\n\n        energies = []\n        for cid in cids:\n            ff = AllChem.MMFFGetMoleculeForceField(mol, mmff_props, confId=cid)\n            ff.Minimize()\n            energy = ff.CalcEnergy()\n            energies.append(energy)\n\n        energies = np.asarray(energies)\n        min_energy_idx = np.argsort(energies)[0]\n\n        new_mol = Chem.Mol(mol)\n        new_mol.RemoveAllConformers()\n        min_conf = mol.GetConformer(cids[min_energy_idx])\n        new_mol.AddConformer(min_conf, assignId=True)\n        mol = new_mol\n\n    return mol\n</code></pre>"}]}